async function renderServerDashboardHtml(env, url) {
  const title = escapeHtml(appName(env));
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const households = await fetchAdminHouseholds(env);
  const defaultHouseholdId = households[0]?.id || "";
  const householdId = url.searchParams.get("household_id") || "";
  const type = url.searchParams.get("type") || "all";
  const date = url.searchParams.get("date") || "";
  const q = url.searchParams.get("q") || "";
  const quality = url.searchParams.get("quality") || "all";
  const categoryFilter = url.searchParams.get("category") || "";
  const paymentFilter = url.searchParams.get("payment_method") || "";
  const groupBy = url.searchParams.get("group_by") || "category";
  const allowedTabs = new Set(["overview", "guide", "import", "calendar", "analysis", "transactions", "cleanup", "partners", "premium"]);
  const tab = allowedTabs.has(url.searchParams.get("tab")) ? url.searchParams.get("tab") : "overview";
  const txPage = Math.max(1, Math.round(Number(url.searchParams.get("page") || "1")) || 1);
  const txPerPage = Math.min(100, Math.max(20, Math.round(Number(url.searchParams.get("per_page") || "50")) || 50));
  const selectedHousehold = households.find((h) => h.id === householdId) || null;
  const activeHouseholdId = selectedHousehold?.id || "";
  const householdMembers = selectedHousehold ? await fetchHouseholdMembers(env, selectedHousehold.id) : [];
  const needsDeepAnalytics = ["overview", "analysis", "partners", "premium"].includes(tab);
  const needsCalendarData = ["overview", "calendar", "premium"].includes(tab);

  const allRows = attachSpenderNames(await fetchAdminRows(env, { month, householdId: activeHouseholdId, type: "all" }), householdMembers);
  const rowsBase = attachSpenderNames(await fetchAdminRows(env, { month, householdId: activeHouseholdId, type, q, quality, category: categoryFilter, payment_method: paymentFilter }), householdMembers);
  const rows = date ? rowsBase.filter((r) => r.transaction_date === date) : rowsBase;
  const prevMonth = addMonthsYm(month, -1);
  const prevRows = attachSpenderNames(needsDeepAnalytics ? await fetchAdminRows(env, { month: prevMonth, householdId: activeHouseholdId, type: "all" }) : [], householdMembers);
  const historyStart = `${addMonthsYm(month, -11)}-01`;
  const historyEnd = nextMonthStart(month);
  const historyRows = attachSpenderNames(needsDeepAnalytics ? await fetchAdminRowsRange(env, { householdId: activeHouseholdId, start: historyStart, end: historyEnd }) : [], householdMembers);
  const yearStart = `${month.slice(0, 4)}-01-01`;
  const yearEnd = `${Number(month.slice(0, 4)) + 1}-01-01`;
  const yearRows = attachSpenderNames(needsDeepAnalytics ? await fetchAdminRowsRange(env, { householdId: activeHouseholdId, start: yearStart, end: yearEnd }) : [], householdMembers);

  const stats = calculateStats(rows);
  const allStats = calculateStats(allRows);
  const calendar = needsCalendarData ? await getCalendar(env, activeHouseholdId, month) : [];
  const msg = url.searchParams.get("msg") || "";
  const err = url.searchParams.get("err") || "";
  const customCategoryRows = await fetchCustomCategories(env, activeHouseholdId);
  const paymentAssetRows = await fetchPaymentAssets(env, activeHouseholdId);
  const categoryOptions = mergedOptions(DEFAULT_CATEGORIES, [...customCategoryRows.map((c) => c.name).filter(Boolean), ...allRows.map((r) => r.category).filter(Boolean)]);
  const paymentOptions = mergedOptions(DEFAULT_PAYMENTS, [...paymentAssetRows.map((p) => p.name).filter(Boolean), ...allRows.map((r) => r.payment_method).filter(Boolean)]);
  const spenderOptionsHtml = renderSpenderOptions(householdMembers, "", "지출자 선택");
  const analysis = calculateDashboardAnalysis(allRows, rows, calendar, month);
  const extended = calculateExtendedAnalytics({ month, allRows, prevRows, historyRows, yearRows, rowsBase });
  const customStats = buildCustomStats(rows, groupBy);
  const affiliateState = buildAffiliateState({ env, month, allRows, analysis, extended, origin: publicBaseUrl(env, url) });
  const premiumState = buildPremiumState({ env, month, allRows, analysis, extended });
  const skillUrl = `${publicBaseUrl(env, url)}/skill`;
  const currentPath = url.pathname + url.search;
  const baseHidden = `<input type="hidden" name="month" value="${escapeHtml(month)}"/><input type="hidden" name="household_id" value="${escapeHtml(activeHouseholdId || defaultHouseholdId)}"/><input type="hidden" name="return_to" value="${escapeHtml(currentPath)}"/><input type="hidden" name="tab" value="${escapeHtml(tab)}"/>`;
  const filterHidden = `${baseHidden}<input type="hidden" name="type" value="${escapeHtml(type)}"/><input type="hidden" name="date" value="${escapeHtml(date)}"/><input type="hidden" name="q" value="${escapeHtml(q)}"/><input type="hidden" name="quality" value="${escapeHtml(quality)}"/><input type="hidden" name="category" value="${escapeHtml(categoryFilter)}"/><input type="hidden" name="payment_method" value="${escapeHtml(paymentFilter)}"/><input type="hidden" name="group_by" value="${escapeHtml(groupBy)}"/>`;
  const csvHref = `/admin/csv?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(selectedHousehold?.id || "")}&type=${encodeURIComponent(type)}&date=${encodeURIComponent(date)}&q=${encodeURIComponent(q)}&quality=${encodeURIComponent(quality)}&category=${encodeURIComponent(categoryFilter)}&payment_method=${encodeURIComponent(paymentFilter)}`;
  const householdValue = selectedHousehold?.id || "";

  const transactionManager = (titleText, descText, dataRows, managerId) => {
    const filteredRows = date ? dataRows.filter((r) => r.transaction_date === date) : dataRows;
    const totalCount = filteredRows.length;
    const pageCount = Math.max(1, Math.ceil(totalCount / txPerPage));
    const currentPage = Math.min(Math.max(1, txPage), pageCount);
    const startIdx = (currentPage - 1) * txPerPage;
    const pageRows = filteredRows.slice(startIdx, startIdx + txPerPage);
    const bulkId = `bulkBox_${managerId || "transactionsSection"}`;
    return `<section id="${managerId || "transactionsSection"}" class="card tx-card txManager"><div class="txToolbar"><div><h3>${escapeHtml(titleText)}</h3><p class="muted">${escapeHtml(descText)}</p></div><div class="txActions"><span class="txCount">${date ? `${escapeHtml(date)} · ${totalCount}건` : `현재 조건 ${totalCount}건`} · ${currentPage}/${pageCount}페이지</span>${date ? `<button id="clearDateFilter" class="ghost small" type="button">날짜 필터 해제</button>` : ""}</div></div><div class="speedNotice">빠른 표시 모드: 한 번에 ${txPerPage}건만 화면에 그립니다. 전체 ${totalCount}건 중 ${totalCount ? `${startIdx + 1}-${Math.min(startIdx + txPerPage, totalCount)}건` : "0건"} 표시 중입니다.</div><div class="txLiveTools"><input id="txLiveSearch" type="search" placeholder="현재 페이지에서 바로 검색: 메모, 분류, 지출자, 결제수단"/><span id="txLiveCount" class="muted">현재 페이지 빠른 검색</span></div><div class="bulkQuickPanel"><div class="bulkQuickTitle"><b>기록 유형 일괄 변경 <span id="txSelectedCount" class="selectedCount">0건 선택</span></b><span>현재 페이지의 거래를 체크한 뒤 바로 지출 또는 수입으로 바꿀 수 있습니다.</span></div><label class="chip"><input type="checkbox" onchange="setTxChecks(this.checked)"/> 현재 페이지 전체 선택</label><button form="bulkForm" name="bulk_quick_type" value="expense" type="submit" onclick="return confirmBulkType('expense')">선택 → 지출</button><button form="bulkForm" name="bulk_quick_type" value="income" type="submit" onclick="return confirmBulkType('income')">선택 → 수입</button><button class="ghost" type="button" onclick="document.getElementById('${bulkId}').open=true;document.getElementById('${bulkId}').scrollIntoView({behavior:'smooth',block:'center'});">분류/날짜도 수정</button></div><details id="${bulkId}" class="txBulkBox"><summary>분류·결제수단·날짜까지 일괄 수정/삭제</summary><form id="bulkForm" method="post" action="/admin/bulk" class="bulkFormGrid">${filterHidden}<div class="formField"><label>분류 변경</label><input name="bulk_category" list="categoryList" placeholder="예: 식비"/></div><div class="formField"><label>결제수단 변경</label><input name="bulk_payment_method" list="paymentList" placeholder="예: 카드"/></div><div class="formField"><label>기록 유형</label><select name="bulk_type"><option value="">유지</option><option value="expense">지출로 변경</option><option value="income">수입으로 변경</option></select></div><div class="formField"><label>날짜 변경</label><input name="bulk_transaction_date" type="date"/></div><div class="formField"><label>지출자 변경</label><select name="bulk_user_id">${spenderOptionsHtml}</select></div><button type="submit">선택 수정</button><button class="danger" name="bulk_delete" value="1" type="submit" onclick="return confirmBulkDelete()">선택 삭제</button></form></details>${renderTransactionPager({ month, householdId: householdValue, tab, total: totalCount, page: currentPage, perPage: txPerPage, type, q, quality, category: categoryFilter, payment_method: paymentFilter, date, groupBy })}<div class="desktopTxTableWrap">${renderDesktopTransactionTable(pageRows, filterHidden)}</div>${renderTransactionPager({ month, householdId: householdValue, tab, total: totalCount, page: currentPage, perPage: txPerPage, type, q, quality, category: categoryFilter, payment_method: paymentFilter, date, groupBy })}${renderTransactionEditModal(householdMembers, filterHidden)}${renderTransactionTurboScript()}</section>`;
  };

  const affiliateHtml = renderAffiliateTab(affiliateState);
  const premiumHtml = renderPremiumTab(premiumState);
  const guideHtml = renderGuideTab({ month, household: selectedHousehold, origin: publicBaseUrl(env, url), skillUrl });
  const importHtml = renderImportTab({ month, households, household: selectedHousehold, defaultHouseholdId, members: householdMembers });

  const overviewHtml = `${renderQuickStartPanel({ month, household: selectedHousehold, origin: publicBaseUrl(env, url), compact: true })}<section class="grid8"><div class="card kpi"><span>수입</span><b class="income">${numberWithCommas(allStats.totals.income)}원</b><small>이번 달 전체</small></div><div class="card kpi"><span>지출</span><b class="expense">${numberWithCommas(allStats.totals.expense)}원</b><small>전월 대비 ${formatSignedPercent(extended.expenseMoMRate)}</small></div><div class="card kpi"><span>잔액</span><b class="balance">${numberWithCommas(allStats.totals.balance)}원</b><small>수입-지출</small></div><div class="card kpi"><span>기록 수</span><b>${allRows.length}건</b><small>정리 대상 포함</small></div><div class="card kpi"><span>일평균 지출</span><b>${numberWithCommas(analysis.avgExpense)}원</b><small>월말 예상 ${numberWithCommas(analysis.burnForecast)}원</small></div><div class="card kpi"><span>무지출일</span><b class="income">${analysis.noSpendDays}일</b><small>소비 방어일</small></div><div class="card kpi"><span>정리 필요</span><b class="amber">${analysis.missingAny}건</b><small>미분류/수단 미입력</small></div><div class="card kpi"><span>위험 점수</span><b class="purple">${analysis.riskScore}점</b><div class="progress"><span style="width:${Math.min(100, analysis.riskScore)}%"></span></div></div></section><section class="layout"><div class="card"><h3>고급 분석 · 경각심 카드</h3><div class="analysisGrid">${renderInsightCards(analysis)}</div></div><div class="card"><h3>무료 스마트 도구 요약</h3><p class="muted">현재 기록을 기준으로 월말 예상과 절약 후보를 계산합니다.</p><div class="analysisGrid"><div class="insight"><b>${numberWithCommas(analysis.burnForecast || 0)}원</b><span>월말 예상 지출</span></div><div class="insight"><b>${numberWithCommas(premiumState.savingPotential || 0)}원</b><span>절약 후보</span></div><div class="insight"><b>${premiumState.premiumScore || 0}점</b><span>관리 점수</span></div></div></div></section><section class="layout2"><div class="card"><h3>최근 3개월 지출 추이</h3>${renderMonthlyTrendMini(extended.threeMonthTrend)}</div><div class="card"><h3>전월 대비 급증 카테고리</h3>${renderCategoryCompareTable(extended.categoryCompare.slice(0, 8), true)}</div></section>${renderInlinePremiumTeaser(premiumState)}${renderInlineAffiliateZone(affiliateState)}`;

  const calendarHtml = `<section id="calendarSection" class="layout2"><div class="card"><div class="sectionHead"><div><h3>소비 캘린더</h3><p class="muted">날짜를 클릭해도 페이지가 새로고침되지 않도록 개선했습니다. 스크립트가 막히면 해당 위치로만 이동합니다.</p></div><div class="calendarLegend"><span class="legend heat1"></span>적음 <span class="legend heat5"></span>많음</div></div>${renderServerCalendar(calendar, month, householdValue, date, type, q, quality, categoryFilter, paymentFilter, groupBy)}</div><div class="card"><h3>선택 조건 통계 · ${escapeHtml(groupLabel(groupBy))}</h3>${renderCustomStats(customStats)}</div></section>${transactionManager("날짜별 거래내역", "캘린더에서 선택한 날짜를 이 영역에서 바로 확인합니다.", rowsBase, "transactionsSection")}`;

  const analysisHtml = `<section class="analysisTabs"><div class="card"><h3>분석 확장판</h3><p class="muted">전월 대비, 최근 3개월, 최근 12개월, 올해 누계, 요일별 패턴을 같이 봅니다. 우리집 소비 흐름을 한눈에 볼 수 있게 정리했습니다.</p><div class="analysisGrid">${renderStrategyCards(extended, analysis)}</div></div><div class="card"><h3>최근 12개월 월별 추이</h3>${renderMonthlyTrendTable(extended.monthlyTrend)}</div><div class="card"><h3>전월 대비 카테고리 사용량 비교</h3>${renderCategoryCompareTable(extended.categoryCompare, false)}</div><div class="card"><h3>상위 카테고리 3개월 흐름</h3>${renderCategoryTrendTable(extended.categoryTrend3)}</div><section class="layout2"><div class="card"><h3>올해 월별 요약</h3>${renderYearlyMonthSummary(extended.yearMonthSummary)}</div><div class="card"><h3>요일별 소비 패턴</h3>${renderWeekdayStats(extended.weekdayStats)}</div></section></section>`;

  const manualFormHtml = `<section id="quickAddSection" class="card appInputCard"><div class="appInputHead"><div><span class="eyebrow">빠른 기록</span><h3>빠른 기록 입력</h3><p class="muted">금액부터 입력하고 저장하세요. 저장 후 목록 상단에서 바로 확인할 수 있습니다.</p></div><a class="ghost small" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "import" }))}">파일 업로드</a></div><form method="post" action="/admin/transactions" class="appInputGrid">${baseHidden}<div class="typeSegment"><label><input type="radio" name="type" value="expense" checked/><span>지출</span></label><label><input type="radio" name="type" value="income"/><span>수입</span></label></div><div class="moneyField"><label>금액</label><input class="moneyInput ledgerAmountInput" type="text" name="amount" placeholder="예: 12,000" inputmode="numeric" autocomplete="off" required/><span>원</span></div><div class="formField"><label>날짜</label><input type="date" name="transaction_date" value="${formatDate(nowKstDate())}"/></div><div class="formField"><label>분류</label><input name="category" list="categoryList" placeholder="식비, 급여"/></div><div class="formField"><label>내용</label><input name="memo" placeholder="점심, 월급, 쿠팡"/></div><div class="formField"><label>결제수단</label><input name="payment_method" list="paymentList" placeholder="카드"/></div><div class="formField"><label>지출자</label><select name="user_id">${spenderOptionsHtml}</select></div><button class="appSaveBtn" type="submit">저장</button></form></section>`;
  const transactionsHtml = `<section class="txPageGrid">${manualFormHtml}${transactionManager("기록 관리", "깔끔한 표 형태로 기록을 확인하고 빠르게 수정합니다.", rowsBase, "transactionsSection")}</section>`;
  const cleanupHtml = `<section class="layout2"><div class="card"><h3>정리 센터</h3><div class="cleanupGrid"><a class="cleanupBox" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "cleanup", quality: "missing_any", group_by: groupBy }))}"><b>${analysis.missingAny}건</b><span>전체 정리 필요</span></a><a class="cleanupBox" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "cleanup", quality: "missing_category", group_by: groupBy }))}"><b>${analysis.missingCategory}건</b><span>카테고리 미분류</span></a><a class="cleanupBox" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "cleanup", quality: "missing_payment", group_by: groupBy }))}"><b>${analysis.missingPayment}건</b><span>결제수단 미입력</span></a></div><p class="muted">정리 센터에서 미입력 데이터를 먼저 잡으면 통계 정확도가 크게 올라갑니다.</p></div><div class="card"><h3>추천 정리 순서</h3><ol class="guideList"><li>미분류부터 카테고리 지정</li><li>지출 건의 결제수단 채우기</li><li>큰 금액 순으로 메모 보정</li><li>월말에 CSV로 백업</li></ol></div></section>${transactionManager("정리 대상 거래", "미분류 또는 결제수단 미입력 거래를 필터링해서 일괄 수정하세요.", rowsBase, "transactionsSection")}`;
  const tabHtml = tab === "guide" ? guideHtml : tab === "import" ? importHtml : tab === "calendar" ? calendarHtml : tab === "analysis" ? analysisHtml : tab === "transactions" ? transactionsHtml : tab === "cleanup" ? cleanupHtml : tab === "partners" ? affiliateHtml : tab === "premium" ? premiumHtml : overviewHtml;

  return `<!doctype html>
<html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title}</title>
<style>${SERVER_DASHBOARD_CSS}</style>
</head><body class="desktopLedger tab-${escapeHtml(tab)}">${renderUnifiedNav(tab === "transactions" ? "records" : tab === "overview" ? "home" : tab, { month, householdId: householdValue })}${renderPcSidebar(tab, month, householdValue, selectedHousehold?.name || title)}<main class="wrap">
<section class="hero"><div class="brand"><div class="logo">💸</div><div><h1>${tab === "transactions" ? "기록 관리" : title}</h1><div class="subtitle">통합 가계부 · ${escapeHtml(selectedHousehold?.name || "전체 가계부")} · 페이지 버전: V19.3-REPORT</div></div></div><div class="topMiniActions"><a class="btn ghost" href="/menu?month=${escapeHtml(month)}${householdValue ? `&household_id=${encodeURIComponent(householdValue)}` : ""}">통합메뉴</a><a class="btn ghost" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "transactions", group_by: groupBy }))}">기록 관리</a><a class="btn ghost" href="/households${householdValue ? `?household_id=${encodeURIComponent(householdValue)}` : ""}">가계부·참여자</a><a class="btn ghost" href="/categories${householdValue ? `?household_id=${encodeURIComponent(householdValue)}` : ""}">분류 설정</a><a class="btn ghost" href="/settings">설정</a><a class="btn ghost" href="/app?month=${escapeHtml(month)}&household_id=${escapeHtml(householdValue)}">모바일 입력</a><form method="post" action="/logout"><button class="secondary" type="submit">로그아웃</button></form></div></section>
${msg ? `<div class="ok">${formatMessage(msg)}</div>` : ""}${err ? `<div class="error">${escapeHtml(err)}</div>` : ""}
<section class="card filterCard"><form method="get" action="/" class="calmFilters"><input type="hidden" name="tab" value="${escapeHtml(tab)}"/><div class="filterTop"><div class="field"><label>가계부</label><select name="household_id"><option value="" ${!selectedHousehold ? "selected" : ""}>전체 가계부</option>${households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === selectedHousehold?.id ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("")}</select></div><div class="field"><label>월 선택</label><input type="month" name="month" value="${escapeHtml(month)}"/></div><div class="field"><label>구분</label><select name="type"><option value="all" ${type === "all" ? "selected" : ""}>전체</option><option value="expense" ${type === "expense" ? "selected" : ""}>지출</option><option value="income" ${type === "income" ? "selected" : ""}>수입</option></select></div><div class="field"><label>검색</label><input name="q" value="${escapeHtml(q)}" placeholder="예: 커피, 병원, 카드"/></div><div class="filterActions"><button type="submit">조회</button><a class="btn ghost" href="/?legacy=1">초기화</a></div></div><div class="quickFilters"><a class="chip blue" href="${escapeHtml(dashboardQuery(month, householdValue, { tab, type: "all", group_by: groupBy }))}">전체 보기</a><a class="chip hot" href="${escapeHtml(dashboardQuery(month, householdValue, { tab, type: "expense", group_by: groupBy }))}">지출만</a><a class="chip blue" href="${escapeHtml(dashboardQuery(month, householdValue, { tab, type: "income", group_by: groupBy }))}">수입만</a><a class="chip" href="${escapeHtml(dashboardQuery(month, householdValue, { tab, quality: "missing_any", group_by: groupBy }))}">정리 필요</a><a class="chip" href="${escapeHtml(csvHref)}">CSV 다운로드</a></div><details class="filterDetails"><summary>상세 조건 열기</summary><div class="filterMore"><div class="field"><label>날짜</label><input type="date" name="date" value="${escapeHtml(date)}"/></div><div class="field"><label>분류</label><select name="category"><option value="">분류 전체</option><option value="__missing" ${categoryFilter === "__missing" ? "selected" : ""}>미분류만</option>${categoryOptions.map((c) => `<option value="${escapeHtml(c)}" ${categoryFilter === c ? "selected" : ""}>${escapeHtml(c)}</option>`).join("")}</select></div><div class="field"><label>결제수단</label><select name="payment_method"><option value="">수단 전체</option><option value="__missing" ${paymentFilter === "__missing" ? "selected" : ""}>수단 미입력만</option>${paymentOptions.map((p) => `<option value="${escapeHtml(p)}" ${paymentFilter === p ? "selected" : ""}>${escapeHtml(p)}</option>`).join("")}</select></div><div class="field"><label>정리 상태</label><select name="quality">${renderQualityOptions(quality)}</select></div><div class="field"><label>묶어 보기</label><select name="group_by">${renderGroupOptions(groupBy)}</select></div><div class="filterActions"><button type="submit">적용</button></div></div></details></form>${selectedHousehold ? `<div class="quick"><a class="chip blue" href="/households?household_id=${escapeHtml(selectedHousehold.id)}">가계부·참여자 관리</a><a class="chip hot" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "cleanup", quality: "missing_any", group_by: groupBy }))}">정리 필요 ${analysis.missingAny}건</a><a class="chip" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "analysis", type: "expense", group_by: "category" }))}">분석 확장</a><a class="chip" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "calendar", group_by: groupBy }))}">캘린더</a><a class="chip" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "transactions", group_by: groupBy }))}">기록 관리</a><a class="chip" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "partners", group_by: groupBy }))}">생활비 팁</a><a class="chip" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "premium", group_by: groupBy }))}">고급 분석</a><a class="chip" href="/my">카카오 사용자 웹</a></div><p class="muted">초대코드는 보안상 이 화면에 표시하지 않습니다. <b>가계부·참여자 관리</b>에서 필요한 때만 확인하세요.</p>` : `<div class="quick"><span class="chip blue">전체 가계부 보기</span><a class="chip hot" href="${escapeHtml(dashboardQuery(month, "", { tab: "cleanup", quality: "missing_any", group_by: groupBy }))}">정리 필요 ${analysis.missingAny}건</a><a class="chip" href="${escapeHtml(dashboardQuery(month, "", { tab: "transactions", group_by: groupBy }))}">기록 관리</a><a class="chip" href="/ledger?all=1">기록 전체</a><a class="chip" href="/households">가계부·참여자</a><a class="chip" href="/my">카카오 사용자 웹</a></div><p class="muted">현재 모든 가계부의 기록을 합쳐 보고 있습니다. 새 입력은 기본 가계부에 저장됩니다.</p>`}</section>
<section class="portalQuick">
  <a class="portalAction primary" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "transactions", group_by: groupBy }))}"><b>기록 관리</b><span>입력, 수정, 삭제, 일괄정리</span></a>
  <a class="portalAction" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "calendar", group_by: groupBy }))}"><b>달력 보기</b><span>날짜별 소비 확인</span></a>
  <a class="portalAction" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "analysis", group_by: groupBy }))}"><b>분석</b><span>분류/결제수단 통계</span></a>
  <a class="portalAction" href="/households${householdValue ? `?household_id=${encodeURIComponent(householdValue)}` : ""}"><b>가계부·참여자</b><span>승인, 방출, 초대코드</span></a>
  <a class="portalAction" href="/categories${householdValue ? `?household_id=${encodeURIComponent(householdValue)}` : ""}"><b>분류 설정</b><span>추천 분류와 내 분류</span></a>
  <a class="portalAction" href="/settings"><b>설정</b><span>비밀번호와 보안 설정</span></a>
  <a class="portalAction" href="${escapeHtml(dashboardQuery(month, householdValue, { tab: "import", group_by: groupBy }))}"><b>파일 업로드</b><span>엑셀/CSV 가져오기</span></a><a class="portalAction" href="/diagnostics"><b>시스템진단</b><span>DB/화면 연결 점검</span></a>
</section>
${renderTabs(tab, month, householdValue, { type, q, quality, category: categoryFilter, payment_method: paymentFilter, group_by: groupBy })}
<datalist id="categoryList">${categoryOptions.map((c) => `<option value="${escapeHtml(c)}"></option>`).join("")}</datalist><datalist id="paymentList">${paymentOptions.map((p) => `<option value="${escapeHtml(p)}"></option>`).join("")}</datalist>
${tabHtml}
${renderSpenderDatalist(householdMembers)}
${renderMobileBottomNav(tab, month, householdValue)}
<div class="footerNote">관리자 웹과 모바일 입력 화면을 분리해 더 빠르게 사용할 수 있습니다.</div>
</main>${renderCalendarFilterScript(date)}${renderAutoRefreshScript()}</body></html>`;
}












async function checkTableAvailable(env, table) {
  try {
    await supabase(env, `/rest/v1/${table}?select=*&limit=1`, { method: "GET" });
    return { ok: true, detail: "연결됨" };
  } catch (err) {
    return { ok: false, detail: safeError(err).slice(0, 160) };
  }
}

async function tableCheckPair(env, table) {
  const r = await checkTableAvailable(env, table);
  return [r.ok, r.detail];
}


async function getSettingValue(env, key) {
  const rows = await optionalSupabase(env, `/rest/v1/accountbook_settings?key=eq.${encodeURIComponent(key)}&select=value&limit=1`, { method: "GET" }, []);
  return rows?.[0]?.value || "";
}

async function handleSettingsPasswordUpdate(request, env) {
  if (!(await verifyAdminSession(request, env))) {
    return htmlResponse(renderServerLoginHtml(env, "보안 설정을 계속하려면 관리자 인증이 필요합니다.", "/settings"), 401);
  }
  const form = await request.formData();
  const current = String(form.get("current_password") || "").trim();
  const next = String(form.get("new_password") || "").trim();
  const confirm = String(form.get("confirm_password") || "").trim();
  if (!(await checkAdminPassword(env, current))) return redirectResponse("/settings?err=current_password_wrong");
  if (next.length < 10) return redirectResponse("/settings?err=password_too_short");
  if (next !== confirm) return redirectResponse("/settings?err=password_mismatch");
  const salt = newPasswordSalt();
  const hash = await pbkdf2PasswordHash(next, salt, PASSWORD_KDF_ITERATIONS);
  try {
    const state = await getAdminSecurityState(env);
    if (state.migration_required) throw new Error("schema_v22_7_0_auth_atomicity.sql required");
    await supabase(env, "/rest/v1/accountbook_admin_security?on_conflict=singleton", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify({
        singleton: true,
        password_hash: hash,
        password_salt: salt,
        password_iterations: PASSWORD_KDF_ITERATIONS,
        password_version: Math.max(1, Number(state.password_version || 1)) + 1,
        session_version: Math.max(1, Number(state.session_version || 1)) + 1,
        updated_at: new Date().toISOString(),
      }),
    });
    await optionalSupabase(env, `/rest/v1/accountbook_settings?key=eq.${encodeURIComponent("admin_password_hash")}`, { method: "DELETE", headers: { Prefer: "return=minimal" } }, null);
    const session = await makeAdminSession(env);
    return redirectResponse("/settings?msg=password_updated", {
      "set-cookie": `ab_admin=${encodeURIComponent(session)}; Path=/; Max-Age=43200; HttpOnly; Secure; SameSite=Lax`,
    });
  } catch (err) {
    return redirectResponse("/settings?err=settings_table_required");
  }
}

async function handleSettingsPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) {
    return htmlResponse(renderServerLoginHtml(env, "", `${url.pathname}${url.search}`), 401);
  }
  const state = await getAdminSecurityState(env);
  const settingValue = state.password_hash ? "v2" : await getSettingValue(env, "admin_password_hash");
  const msg = url.searchParams.get("msg") || "";
  const err = url.searchParams.get("err") || "";
  return htmlResponse(renderSettingsHtml({ env, hasDbPassword: !!settingValue, msg, err }));
}

function renderSettingsHtml({ env, hasDbPassword, msg = "", err = "" }) {
  const title = escapeHtml(appName(env));
  const errMap = {
    current_password_wrong: "현재 비밀번호가 맞지 않습니다.",
    password_too_short: "새 비밀번호는 10자 이상으로 입력하세요.",
    password_mismatch: "새 비밀번호 확인이 일치하지 않습니다.",
    settings_table_required: "설정 저장 테이블이 없습니다. 설정 저장 구조을 관리자 설정에서 실행하세요.",
  };
  const msgMap = {
    password_updated: "관리자 비밀번호를 변경했습니다. 보안 설정 화면을 그대로 유지했습니다.",
  };
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 설정</title><style>
*{box-sizing:border-box}body{margin:0;background:#f5f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.top{height:58px;background:#fff;border-bottom:1px solid #e5e7eb;display:flex;align-items:center;justify-content:space-between;padding:0 18px;position:sticky;top:0}.top a,.btn,button{display:inline-flex;align-items:center;justify-content:center;min-height:40px;border-radius:12px;border:1px solid #d1d5db;background:#fff;color:#111827;text-decoration:none;font-weight:900;padding:0 13px;cursor:pointer}.primary,button{background:#1d4ed8;color:#fff;border-color:#1d4ed8}.wrap{max-width:840px;margin:0 auto;padding:18px}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:14px 0;box-shadow:0 8px 24px rgba(15,23,42,.055)}label{display:block;font-weight:900;margin:12px 0 6px}input{width:100%;height:44px;border:1px solid #cbd5e1;border-radius:14px;padding:0 12px;font:inherit}.muted{color:#64748b;font-size:13px;line-height:1.6}.ok{background:#dcfce7;color:#166534;border-radius:14px;padding:11px;margin:10px 0}.err{background:#fee2e2;color:#991b1b;border-radius:14px;padding:11px;margin:10px 0}.pill{display:inline-flex;border-radius:999px;padding:6px 10px;font-weight:900;font-size:12px;background:#eff6ff;color:#1d4ed8}.warn{background:#fff7ed;color:#9a3412;border:1px solid #fed7aa;border-radius:14px;padding:12px;line-height:1.6}</style></head><body>${renderUnifiedNav("settings")}<header class="top"><b>설정</b><nav><a href="/?legacy=1">관리자 홈</a> <a href="/app">모바일 입력</a> <a href="/diagnostics">시스템진단</a></nav></header><main class="wrap"><h1>보안 설정</h1>${msg ? `<div class="ok">${escapeHtml(msgMap[msg] || msg)}</div>` : ""}${err ? `<div class="err">${escapeHtml(errMap[err] || err)}</div>` : ""}<section class="card"><h2>관리자 비밀번호</h2><p class="muted">가계부 접속 비밀번호는 정상입니다. 가족/관리자 외 접근을 막기 위한 관리자 보호장치입니다. 비밀번호는 PBKDF2 방식으로 저장되며 원문은 보관하지 않습니다.</p><p><span class="pill">${hasDbPassword ? "앱 비밀번호 설정됨" : "Cloudflare 초기 비밀번호 사용 중"}</span></p><form method="post" action="/admin/settings/password"><label>현재 비밀번호</label><input name="current_password" type="password" autocomplete="current-password" required/><label>새 비밀번호</label><input name="new_password" type="password" autocomplete="new-password" minlength="10" required/><label>새 비밀번호 확인</label><input name="confirm_password" type="password" autocomplete="new-password" minlength="10" required/><p><button type="submit">비밀번호 변경</button></p></form><div class="warn"><b>중요</b><br/>변경하면 다른 관리자 로그인 세션은 즉시 만료되고 현재 화면은 유지됩니다. 이후에는 Cloudflare 초기 비밀번호가 로그인 수단으로 사용되지 않습니다.</div></section><section class="card"><h2>공유 설정</h2><p class="muted">공유 기능은 기본 공유와 문구 복사를 우선 제공합니다.</p></section><section class="card"><h2>저장 상태</h2><p class="muted">설정 저장이 정상 처리되는지 화면에서 확인하세요.</p></section></main></body></html>`;
}




function canonicalRouteRows(month = currentMonthKst(), householdId = "") {
  const hid = safeNavHouseholdId(householdId);
  const hh = hid ? `&household_id=${encodeURIComponent(hid)}` : "";
  return [
    ["관리자 홈", dashboardQuery(month, hid, { tab: "overview" }), "전체 현황"],
    ["기록 관리", dashboardQuery(month, hid, { tab: "transactions" }), "입력·수정·삭제"],
    ["모바일 입력", `/app?month=${encodeURIComponent(month)}${hh}`, "빠른 기록"],
    ["가계부·참여자", "/households", "가족/모임 공동 사용"],
    ["분류 설정", hid ? `/categories?household_id=${encodeURIComponent(hid)}` : "/categories", "카테고리"],
    ["예산 관리", `/budgets?month=${encodeURIComponent(month)}${hh}`, "월 수입 대비 예산"],
    ["무료 스마트 도구", `/smart-tools?month=${encodeURIComponent(month)}${hh}`, "예측·반복지출·영수증·리포트"],
    ["영수증 기록", `/receipts?month=${encodeURIComponent(month)}${hh}`, "사진·문자 확인 후 저장"],
    ["자동 리포트", `/reports?month=${encodeURIComponent(month)}${hh}`, "주간·월간 생성·공유"],
    ["결제수단", `/payment-methods?month=${encodeURIComponent(month)}${hh}`, "카드/계좌/간편결제"],
    ["정기지출 준비", `/reserve-plans?month=${encodeURIComponent(month)}${hh}`, "세금/보험 미리 준비"],
    ["백업·복구", `/backup?month=${encodeURIComponent(month)}${hh}`, "백업/복구/되돌리기 통합"],
    ["최종 사용자 준비 확인", "/user-ready-check", "사용자 화면 최종 확인"],
    ["사용자 배포 확인", "/release-check", "최종 사용자 흐름 확인"],
    ["운영센터", "/operation-center", "점검/배포/기능맵 통합"],
    ["설정", "/settings", "보안/공유 설정"],
  ];
}

async function handleRouteAuditPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  const selectedHousehold = households.find((h) => h.id === householdId) || households[0] || null;
  const rows = canonicalRouteRows(month, selectedHousehold?.id || "");
  const body = rows.map(([label, href, purpose]) => `<tr><td><b>${escapeHtml(label)}</b></td><td><a href="${escapeHtml(href)}">${escapeHtml(href)}</a></td><td>${escapeHtml(purpose)}</td><td><span class="ok">표준</span></td></tr>`).join("");
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>경로 점검</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1100px;margin:0 auto;padding:18px}.hero{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;box-shadow:0 10px 28px rgba(15,23,42,.055);margin:14px 0}.filters{display:flex;gap:8px;flex-wrap:wrap}.filters select,.filters input,.filters button{height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.filters button{background:#111827;color:#fff;font-weight:1000}table{width:100%;border-collapse:collapse;background:#fff;border:1px solid #e5e7eb;border-radius:18px;overflow:hidden}td,th{border-bottom:1px solid #e5e7eb;padding:11px;text-align:left;font-size:14px}a{color:#2563eb;font-weight:900}.ok{display:inline-flex;border-radius:999px;background:#dcfce7;color:#166534;padding:5px 9px;font-size:12px;font-weight:1000}.note{color:#64748b;line-height:1.6}</style></head><body>${renderUnifiedNav("route-audit", { month, householdId: selectedHousehold?.id || "" })}<main class="wrap"><section class="hero"><h1>경로 점검</h1><p class="note">화면마다 메뉴명이 달라지지 않도록 표준 메뉴명과 진입 경로를 한 곳에서 확인합니다.</p><form class="filters" method="get" action="/route-audit"><select name="household_id">${households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === selectedHousehold?.id ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("")}</select><input type="month" name="month" value="${escapeHtml(month)}"/><button type="submit">기준 변경</button></form></section><table><thead><tr><th>표준 메뉴명</th><th>표준 경로</th><th>용도</th><th>상태</th></tr></thead><tbody>${body}</tbody></table></main></body></html>`);
}



async function handleTopTabAuditPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const rows = [
    ["관리자 기록", "/?legacy=1&tab=transactions", "통합메뉴 1개 + 보조 상단 메뉴 숨김"],
    ["모바일 입력", "/app", "통합메뉴 1개 + 월/가계부 선택만 유지"],
    ["가계부·참여자", "/households", "옛 관리자/설정/기록 버튼 숨김"],
    ["분류 설정", "/categories", "옛 관리자/설정/기록 버튼 숨김"],
    ["설정", "/settings", "옛 관리자/앱/진단 탭 숨김"],
    ["점검/백업 화면", "/menu", "상단 보조 nav 숨김"],
  ];
  const body = rows.map(([name, route, rule]) => `<tr><td><b>${escapeHtml(name)}</b></td><td><code>${escapeHtml(route)}</code></td><td>${escapeHtml(rule)}</td><td><span class="ok">정리됨</span></td></tr>`).join("");
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>상단 탭 중복 점검</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1100px;margin:0 auto;padding:18px}.hero{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;box-shadow:0 10px 28px rgba(15,23,42,.055);margin:14px 0}.note{color:#64748b;line-height:1.6}table{width:100%;border-collapse:collapse;background:#fff;border:1px solid #e5e7eb;border-radius:18px;overflow:hidden}td,th{border-bottom:1px solid #e5e7eb;padding:11px;text-align:left;font-size:14px}code{background:#f1f5f9;border-radius:8px;padding:3px 7px}.ok{display:inline-flex;border-radius:999px;background:#dcfce7;color:#166534;padding:5px 9px;font-size:12px;font-weight:1000}.btn{display:inline-flex;align-items:center;justify-content:center;height:40px;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:900;padding:0 12px}</style></head><body>${renderUnifiedNav("nav-audit")}<main class="wrap"><section class="hero"><h1>상단 탭 중복 점검</h1><p class="note">모든 주요 화면의 상단 진입은 통합메뉴 1개로 통일하고, 각 화면에 남아 있던 보조 상단 탭은 숨깁니다.</p><p><a class="btn" href="/menu">통합메뉴로 이동</a></p></section><table><thead><tr><th>화면</th><th>대표 경로</th><th>정리 기준</th><th>상태</th></tr></thead><tbody>${body}</tbody></table></main></body></html>`);
}

