function safeArray(value) {
  return Array.isArray(value) ? value : [];
}

function safeObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function countObjectArrays(obj) {
  const o = safeObject(obj);
  return Object.values(o).reduce((a, v) => a + (Array.isArray(v) ? v.length : 0), 0);
}

function validateBackupPayloadShape(payload) {
  const errors = [];
  const warnings = [];
  const p = safeObject(payload);
  if (!p || !Object.keys(p).length) errors.push("JSON 객체가 아닙니다.");
  if (p.app !== "kakao-accountbook") warnings.push("app 값이 kakao-accountbook이 아닙니다.");
  if (!String(p.version || "").startsWith("V")) warnings.push("백업 버전 정보가 없습니다.");
  if (!p.exported_at) warnings.push("exported_at 값이 없습니다.");
  if (!safeObject(p.scope).month) warnings.push("백업 기준 월(scope.month)이 없습니다.");
  if (!Array.isArray(p.households)) errors.push("households 배열이 없습니다.");
  if (!Array.isArray(p.transactions)) errors.push("transactions 배열이 없습니다.");
  if (!safeObject(p.household_members) || !Object.keys(safeObject(p.household_members)).length) warnings.push("household_members 정보가 없거나 비어 있습니다.");
  if (!safeObject(p.budgets)) warnings.push("budgets 객체가 없습니다.");
  if (!safeObject(p.recurring)) warnings.push("recurring 객체가 없습니다.");
  if (!safeObject(p.categories)) warnings.push("categories 객체가 없습니다.");

  const transactions = safeArray(p.transactions);
  const missingId = transactions.filter((t) => !safeObject(t).id).length;
  const missingDate = transactions.filter((t) => !safeObject(t).transaction_date).length;
  const badAmount = transactions.filter((t) => !Number.isFinite(Number(safeObject(t).amount))).length;
  if (missingId) warnings.push(`거래 ID가 없는 항목 ${missingId}건`);
  if (missingDate) warnings.push(`거래 날짜가 없는 항목 ${missingDate}건`);
  if (badAmount) warnings.push(`금액이 숫자가 아닌 항목 ${badAmount}건`);

  const counts = {
    households: safeArray(p.households).length,
    transactions: transactions.length,
    members: countObjectArrays(p.household_members),
    budgets: countObjectArrays(p.budgets),
    recurring: countObjectArrays(p.recurring),
    categories: countObjectArrays(p.categories),
  };
  return { ok: errors.length === 0, errors, warnings, counts };
}

function summarizeBackupPayload(payload) {
  const p = safeObject(payload);
  const transactions = safeArray(p.transactions);
  const expense = transactions.filter((t) => safeObject(t).type !== "income").reduce((a, t) => a + Number(safeObject(t).amount || 0), 0);
  const income = transactions.filter((t) => safeObject(t).type === "income").reduce((a, t) => a + Number(safeObject(t).amount || 0), 0);
  const categoryMap = {};
  for (const t of transactions) {
    const row = safeObject(t);
    const c = row.category || "미분류";
    categoryMap[c] = (categoryMap[c] || 0) + Number(row.amount || 0);
  }
  const topCategories = Object.entries(categoryMap).sort((a, b) => b[1] - a[1]).slice(0, 8);
  const byDate = {};
  for (const t of transactions) {
    const row = safeObject(t);
    const d = row.transaction_date || "날짜없음";
    byDate[d] = (byDate[d] || 0) + 1;
  }
  const dateRange = Object.keys(byDate).filter((d) => /^\d{4}-\d{2}-\d{2}$/.test(d)).sort();
  return {
    version: p.version || "",
    exported_at: p.exported_at || "",
    scope: safeObject(p.scope),
    income,
    expense,
    balance: income - expense,
    topCategories,
    firstDate: dateRange[0] || "",
    lastDate: dateRange[dateRange.length - 1] || "",
  };
}

function renderBackupPreviewHtml({ payload = null, validation = null, summary = null, error = "" } = {}) {
  const hasPayload = !!payload;
  const counts = validation?.counts || { households: 0, transactions: 0, members: 0, budgets: 0, recurring: 0, categories: 0 };
  const metricCards = [
    ["가계부", counts.households],
    ["거래", counts.transactions],
    ["참여자", counts.members],
    ["예산", counts.budgets],
    ["고정항목", counts.recurring],
    ["사용자 분류", counts.categories],
  ].map(([k, v]) => `<div class="metric"><span>${escapeHtml(k)}</span><b>${numberWithCommas(v || 0)}</b></div>`).join("");
  const errors = (validation?.errors || []).map((x) => `<li>${escapeHtml(x)}</li>`).join("");
  const warnings = (validation?.warnings || []).map((x) => `<li>${escapeHtml(x)}</li>`).join("");
  const topRows = (summary?.topCategories || []).map(([name, amount]) => `<tr><td>${escapeHtml(name)}</td><td>${numberWithCommas(amount)}원</td></tr>`).join("");
  const statusBox = error ? `<section class="card bad"><h2>파일을 읽지 못했습니다</h2><p>${escapeHtml(error)}</p></section>` : hasPayload ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>${validation.ok ? "검증 통과" : "검증 실패"}</h2><p>${validation.ok ? "백업 파일 구조가 정상입니다. 아직 복구 적용은 하지 않고 미리보기만 제공합니다." : "필수 구조가 부족합니다. 이 파일은 복구용으로 사용하지 않는 것이 안전합니다."}</p>${errors ? `<h3>오류</h3><ul>${errors}</ul>` : ""}${warnings ? `<h3>주의</h3><ul>${warnings}</ul>` : ""}</section>` : "";
  const summaryHtml = hasPayload ? `<section class="grid">${metricCards}</section><section class="card"><h2>백업 요약</h2><div class="summaryGrid"><div><span>백업 버전</span><b>${escapeHtml(summary.version || "미상")}</b></div><div><span>생성 시각</span><b>${escapeHtml(summary.exported_at || "미상")}</b></div><div><span>기간</span><b>${escapeHtml(summary.firstDate || "-")} ~ ${escapeHtml(summary.lastDate || "-")}</b></div><div><span>수입</span><b>${numberWithCommas(summary.income || 0)}원</b></div><div><span>지출</span><b>${numberWithCommas(summary.expense || 0)}원</b></div><div><span>잔액</span><b>${numberWithCommas(summary.balance || 0)}원</b></div></div></section><section class="card"><h2>상위 분류</h2><table><thead><tr><th>분류</th><th>금액</th></tr></thead><tbody>${topRows || `<tr><td colspan="2">표시할 분류가 없습니다.</td></tr>`}</tbody></table></section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>백업 미리보기</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1120px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#0f766e);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:25px;margin-top:6px}.upload{display:grid;gap:10px}.upload input[type=file]{padding:16px;border:2px dashed #cbd5e1;border-radius:18px;background:#f8fafc}.btn,.upload button{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.summaryGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:10px}.summaryGrid div{background:#f8fafc;border:1px solid #e5e7eb;border-radius:16px;padding:12px}.summaryGrid span{display:block;color:#64748b;font-size:13px}.summaryGrid b{display:block;margin-top:4px}table{width:100%;border-collapse:collapse}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left}.warn{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}@media(max-width:640px){.wrap{padding:12px}.hero h1{font-size:24px}}</style></head><body>${renderUnifiedNav("backup")}<main class="wrap"><section class="hero"><h1>백업 미리보기</h1><p>내려받은 JSON 백업 파일을 복구하기 전에 구조와 건수를 확인합니다. 이 화면은 DB에 아무것도 저장하지 않습니다.</p><p><a class="btn light" href="/backup">백업센터로 돌아가기</a></p></section><section class="card"><h2>JSON 백업 파일 선택</h2><p class="warn">민감한 데이터가 포함될 수 있으므로 본인 백업 파일만 확인하세요. 현재 단계에서는 복구 자동 적용을 하지 않습니다.</p><form class="upload" method="post" action="/backup/preview" enctype="multipart/form-data"><input type="file" name="backup_file" accept="application/json,.json" required/><button type="submit">백업 파일 검증/미리보기</button></form></section>${statusBox}${summaryHtml}</main></body></html>`;
}

async function handleBackupPreviewPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  return htmlResponse(renderBackupPreviewHtml());
}

async function handleBackupPreviewPost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  try {
    const form = await request.formData();
    const file = form.get("backup_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderBackupPreviewHtml({ error: "업로드된 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 8 * 1024 * 1024) {
      return htmlResponse(renderBackupPreviewHtml({ error: "파일이 너무 큽니다. 8MB 이하 JSON만 먼저 확인하세요." }), 400);
    }
    const payload = JSON.parse(raw);
    const validation = validateBackupPayloadShape(payload);
    const summary = summarizeBackupPayload(payload);
    return htmlResponse(renderBackupPreviewHtml({ payload, validation, summary }), validation.ok ? 200 : 400);
  } catch (err) {
    rememberOpsEvent({ kind: "backup_preview_failed", severity: "warn", path: "/backup/preview", method: "POST", detail: safeError(err) });
    return htmlResponse(renderBackupPreviewHtml({ error: "JSON 파일 형식이나 백업 구조를 확인해 주세요. 원본 데이터는 변경되지 않았습니다." }), 400);
  }
}




function normalizeComparableText(value) {
  return String(value || "").trim();
}

function transactionComparable(row) {
  const r = safeObject(row);
  return {
    type: normalizeTransactionType(r.type),
    transaction_date: String(r.transaction_date || "").slice(0, 10),
    amount: Number(r.amount || 0),
    category: normalizeComparableText(r.category),
    memo: normalizeComparableText(r.memo || r.raw_text),
    payment_method: normalizeComparableText(r.payment_method),
    user_id: normalizeComparableText(r.user_id),
  };
}

function transactionSignature(row) {
  const r = transactionComparable(row);
  return [r.type, r.transaction_date, r.amount, r.category, r.memo, r.payment_method].join("|");
}

function transactionDiffFields(a, b) {
  const aa = transactionComparable(a);
  const bb = transactionComparable(b);
  const fields = ["type", "transaction_date", "amount", "category", "memo", "payment_method", "user_id"];
  return fields.filter((f) => String(aa[f]) !== String(bb[f]));
}

function compareBackupTransactions(backupRows, currentRows) {
  const backup = safeArray(backupRows);
  const current = safeArray(currentRows);
  const currentById = new Map();
  const currentBySignature = new Map();
  for (const row of current) {
    const r = safeObject(row);
    if (r.id) currentById.set(String(r.id), r);
    const sig = transactionSignature(r);
    if (!currentBySignature.has(sig)) currentBySignature.set(sig, []);
    currentBySignature.get(sig).push(r);
  }

  const backupIds = new Set();
  const backupSigs = new Set();
  const sameId = [];
  const contentDuplicates = [];
  const conflicts = [];
  const newCandidates = [];

  for (const row of backup) {
    const r = safeObject(row);
    const id = String(r.id || "");
    const sig = transactionSignature(r);
    if (id) backupIds.add(id);
    backupSigs.add(sig);
    if (id && currentById.has(id)) {
      const cur = currentById.get(id);
      const diff = transactionDiffFields(r, cur);
      if (diff.length) conflicts.push({ backup: r, current: cur, diff });
      else sameId.push(r);
    } else if (currentBySignature.has(sig)) {
      contentDuplicates.push({ backup: r, current: currentBySignature.get(sig)[0] });
    } else {
      newCandidates.push(r);
    }
  }

  const currentOnly = current.filter((row) => {
    const r = safeObject(row);
    const id = String(r.id || "");
    const sig = transactionSignature(r);
    return (!id || !backupIds.has(id)) && !backupSigs.has(sig);
  });

  const risk = conflicts.length ? "danger" : (sameId.length || contentDuplicates.length) ? "warn" : "good";
  return {
    risk,
    counts: {
      backup: backup.length,
      current: current.length,
      same_id: sameId.length,
      same_content: contentDuplicates.length,
      conflicts: conflicts.length,
      new_candidates: newCandidates.length,
      current_only: currentOnly.length,
    },
    sameId,
    contentDuplicates,
    conflicts,
    newCandidates,
    currentOnly,
  };
}

function renderBackupCompareRows(rows, type = "new") {
  const arr = safeArray(rows).slice(0, 30);
  if (!arr.length) return `<tr><td colspan="6">표시할 항목이 없습니다.</td></tr>`;
  return arr.map((item) => {
    const row = safeObject(item.backup || item);
    const diff = Array.isArray(item.diff) && item.diff.length ? ` · 차이: ${item.diff.join(", ")}` : "";
    return `<tr><td>${escapeHtml(String(row.transaction_date || ""))}</td><td>${row.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(row.amount || 0)}원</td><td>${escapeHtml(row.category || "")}</td><td>${escapeHtml(row.memo || row.raw_text || "")}</td><td>${escapeHtml(row.id || "")}${escapeHtml(diff)}</td></tr>`;
  }).join("");
}

function renderBackupCompareHtml({ payload = null, validation = null, summary = null, compare = null, month = "", householdId = "", households = [], error = "" } = {}) {
  const hasResult = !!compare;
  const riskLabel = compare?.risk === "danger" ? "충돌 위험" : compare?.risk === "warn" ? "중복 가능성" : "안전";
  const riskText = compare?.risk === "danger" ? "같은 ID인데 내용이 다른 거래가 있습니다. 자동 복구/가져오기는 위험합니다." : compare?.risk === "warn" ? "이미 존재하는 거래가 있어 중복 저장 위험이 있습니다. 가져오기 전에 확인이 필요합니다." : "현재 데이터와 충돌·중복 위험이 낮습니다.";
  const cards = compare ? [
    ["백업 거래", compare.counts.backup],
    ["현재 거래", compare.counts.current],
    ["동일 ID", compare.counts.same_id],
    ["동일 내용", compare.counts.same_content],
    ["충돌", compare.counts.conflicts],
    ["신규 후보", compare.counts.new_candidates],
    ["현재만 있음", compare.counts.current_only],
  ].map(([label, value]) => `<div class="metric"><span>${escapeHtml(label)}</span><b>${numberWithCommas(value || 0)}</b></div>`).join("") : "";
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const errorBox = error ? `<section class="card bad"><h2>비교 실패</h2><p>${escapeHtml(error)}</p></section>` : "";
  const validationBox = validation ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>백업 파일 구조: ${validation.ok ? "정상" : "확인 필요"}</h2>${validation.errors?.length ? `<h3>오류</h3><ul>${validation.errors.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}${validation.warnings?.length ? `<h3>주의</h3><ul>${validation.warnings.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}</section>` : "";
  const resultHtml = hasResult ? `<section class="card ${compare.risk}"><h2>비교 결과: ${escapeHtml(riskLabel)}</h2><p>${escapeHtml(riskText)}</p></section><section class="grid">${cards}</section><section class="card"><h2>충돌 항목</h2><p class="note">같은 ID인데 백업과 현재 데이터 내용이 다른 항목입니다.</p><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>ID/차이</th></tr></thead><tbody>${renderBackupCompareRows(compare.conflicts, "conflict")}</tbody></table></section><section class="card"><h2>신규 후보</h2><p class="note">현재 데이터에 없어 보이는 백업 거래입니다. 아직 DB에 저장하지 않습니다.</p><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>ID</th></tr></thead><tbody>${renderBackupCompareRows(compare.newCandidates, "new")}</tbody></table></section><section class="card"><h2>중복 가능 항목</h2><p class="note">ID 또는 내용 기준으로 이미 존재하는 거래입니다.</p><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>ID</th></tr></thead><tbody>${renderBackupCompareRows([...compare.sameId.slice(0, 15), ...compare.contentDuplicates.slice(0, 15)], "dup")}</tbody></table></section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>백업 비교</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1140px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#7c2d12);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.warn{border-color:#fde68a;background:#fffbeb}.card.danger,.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:25px;margin-top:6px}.upload{display:grid;grid-template-columns:1fr 160px 170px;gap:10px}.upload input,.upload select,.upload button{min-height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.upload input[type=file]{padding:10px}.upload button{background:#111827;color:#fff;font-weight:1000;cursor:pointer}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px}.btn.light{background:#eff6ff;color:#1e3a8a}.note{color:#64748b;line-height:1.55}table{width:100%;border-collapse:collapse;background:#fff}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}.upload{grid-template-columns:1fr}.card{overflow-x:auto}table{min-width:760px}}</style></head><body>${renderUnifiedNav("backup", { month, householdId })}<main class="wrap"><section class="hero"><h1>백업 비교/중복 위험 분석</h1><p>백업 JSON을 현재 Supabase 데이터와 비교해, 복구 전에 중복·충돌 위험을 확인합니다. 이 화면은 DB에 아무것도 저장하지 않습니다.</p><p><a class="btn light" href="/backup">백업센터</a> <a class="btn light" href="/backup/preview">백업 미리보기</a></p></section><section class="card"><h2>백업 파일 비교</h2><p class="warnBox">복구 자동 적용 전 단계입니다. 같은 ID, 같은 내용, 충돌 항목, 신규 후보만 분석합니다.</p><form class="upload" method="post" action="/backup/compare" enctype="multipart/form-data"><input type="file" name="backup_file" accept="application/json,.json" required/><select name="household_id"><option value="">백업 기준 사용/전체</option>${householdOptions}</select><button type="submit">비교 분석</button></form></section>${errorBox}${validationBox}${resultHtml}</main></body></html>`;
}

async function handleBackupComparePage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  return htmlResponse(renderBackupCompareHtml({ households, householdId, month: currentMonthKst() }));
}

async function handleBackupComparePost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  let households = [];
  try { households = await fetchAdminHouseholds(env); } catch (_) {}
  try {
    const form = await request.formData();
    const file = form.get("backup_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderBackupCompareHtml({ households, error: "업로드된 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 8 * 1024 * 1024) {
      return htmlResponse(renderBackupCompareHtml({ households, error: "파일이 너무 큽니다. 8MB 이하 JSON만 먼저 비교하세요." }), 400);
    }
    const payload = JSON.parse(raw);
    const validation = validateBackupPayloadShape(payload);
    const summary = summarizeBackupPayload(payload);
    const scope = safeObject(payload.scope);
    const month = validMonth(scope.month) || currentMonthKst();
    const formHouseholdId = String(form.get("household_id") || "").trim();
    const householdId = formHouseholdId || String(scope.household_id || "").trim();
    if (!validation.ok) {
      return htmlResponse(renderBackupCompareHtml({ payload, validation, summary, households, month, householdId }), 400);
    }
    const currentRows = await fetchAdminRows(env, { month, householdId, type: "all" });
    const compare = compareBackupTransactions(safeArray(payload.transactions), currentRows);
    return htmlResponse(renderBackupCompareHtml({ payload, validation, summary, compare, households, month, householdId }));
  } catch (err) {
    rememberOpsEvent({ kind: "backup_compare_failed", severity: "warn", path: "/backup/compare", method: "POST", detail: safeError(err) });
    return htmlResponse(renderBackupCompareHtml({ households, error: "백업 비교를 완료하지 못했습니다. 파일 구조와 선택한 가계부를 확인해 주세요." }), 400);
  }
}


function renderImportCandidateRows(rows = []) {
  const arr = safeArray(rows).slice(0, 200);
  if (!arr.length) return `<tr><td colspan="8">가져오기 후보가 없습니다.</td></tr>`;
  return arr.map((row, idx) => {
    const r = safeObject(row);
    const key = stableShortHash(JSON.stringify(transactionComparable(r)));
    return `<tr data-candidate-row="1"><td><input class="candidateCheck" type="checkbox" name="candidate_key" value="${escapeHtml(key)}" data-amount="${escapeHtml(r.amount || 0)}" data-type="${escapeHtml(r.type || "expense")}"/></td><td>${idx + 1}</td><td>${escapeHtml(String(r.transaction_date || ""))}</td><td>${r.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(r.amount || 0)}원</td><td>${escapeHtml(r.category || "")}</td><td>${escapeHtml(r.memo || r.raw_text || "")}</td><td>${escapeHtml(r.payment_method || "")}</td></tr>`;
  }).join("");
}

function renderImportCandidateHiddenJson(rows = []) {
  const safeRows = safeArray(rows).slice(0, 200).map((r) => transactionComparable(r));
  return escapeHtml(JSON.stringify(safeRows));
}

function renderBackupCandidateSelectHtml({ payload = null, validation = null, compare = null, month = "", householdId = "", households = [], error = "" } = {}) {
  const candidates = safeArray(compare?.newCandidates);
  const conflictCount = Number(compare?.counts?.conflicts || 0);
  const duplicateCount = Number(compare?.counts?.same_id || 0) + Number(compare?.counts?.same_content || 0);
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const errorBox = error ? `<section class="card bad"><h2>후보 분석 실패</h2><p>${escapeHtml(error)}</p></section>` : "";
  const validationBox = validation ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>백업 구조: ${validation.ok ? "정상" : "확인 필요"}</h2>${validation.errors?.length ? `<h3>오류</h3><ul>${validation.errors.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}${validation.warnings?.length ? `<h3>주의</h3><ul>${validation.warnings.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}</section>` : "";
  const summary = compare ? `<section class="grid"><div class="metric"><span>신규 후보</span><b>${numberWithCommas(candidates.length)}</b></div><div class="metric"><span>충돌</span><b>${numberWithCommas(conflictCount)}</b></div><div class="metric"><span>중복 가능</span><b>${numberWithCommas(duplicateCount)}</b></div><div class="metric"><span>현재만 있음</span><b>${numberWithCommas(compare.counts.current_only || 0)}</b></div></section>` : "";
  const riskBox = compare ? `<section class="card ${conflictCount ? "bad" : duplicateCount ? "warn" : "good"}"><h2>${conflictCount ? "충돌 항목 확인 필요" : duplicateCount ? "중복 가능성 있음" : "신규 후보 선택 가능"}</h2><p>${conflictCount ? "같은 ID인데 내용이 다른 항목이 있어 자동 가져오기를 진행하면 안 됩니다." : "아래 신규 후보 중 실제로 가져올 항목을 체크해 가져오기 계획만 만들 수 있습니다. 아직 DB에는 저장하지 않습니다."}</p></section>` : "";
  const candidateBox = compare ? `<section class="card"><div class="cardTitle"><div><h2>가져오기 후보 선택</h2><p class="note">현재 데이터에 없어 보이는 거래만 표시합니다. 체크박스는 가져오기 계획 생성용이며, DB 저장은 하지 않습니다.</p></div><div class="actions"><button type="button" class="btn light" onclick="setCandidateChecks(true)">전체 선택</button><button type="button" class="btn light" onclick="setCandidateChecks(false)">선택 해제</button><button type="button" class="btn green" onclick="downloadImportPlan()">선택 계획 JSON 저장</button></div></div><div class="selectedBar"><b id="candidateSelectedCount">0건 선택</b><span id="candidateSelectedAmount">0원</span></div><input type="hidden" id="candidateJson" value="${renderImportCandidateHiddenJson(candidates)}"/><div class="tableWrap"><table><thead><tr><th>선택</th><th>#</th><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th></tr></thead><tbody>${renderImportCandidateRows(candidates)}</tbody></table></div>${candidates.length > 200 ? `<p class="note">후보가 많아 상위 200건만 표시합니다.</p>` : ""}</section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>가져오기 후보 선택</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1160px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#0f172a,#14532d);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.warn{border-color:#fde68a;background:#fffbeb}.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:25px;margin-top:6px}.upload{display:grid;grid-template-columns:1fr 160px 170px;gap:10px}.upload input,.upload select,.upload button{min-height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.upload input[type=file]{padding:10px}.upload button,.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.btn.green{background:#059669;color:#fff}.note{color:#64748b;line-height:1.55}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}.cardTitle{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;flex-wrap:wrap}.actions{display:flex;gap:8px;flex-wrap:wrap}.selectedBar{display:flex;gap:10px;align-items:center;flex-wrap:wrap;margin:10px 0;padding:12px;border-radius:16px;background:#eff6ff;color:#1e3a8a;font-weight:1000}.tableWrap{overflow-x:auto}table{width:100%;border-collapse:collapse;background:#fff;min-width:860px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}.candidateCheck{width:20px;height:20px}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}.upload{grid-template-columns:1fr}.card{overflow-x:auto}}</style></head><body>${renderUnifiedNav("backup", { month, householdId })}<main class="wrap"><section class="hero"><h1>가져오기 후보 선택</h1><p>백업 파일에서 현재 데이터에 없는 거래 후보만 골라 가져오기 계획을 만듭니다. 이 단계도 DB에 아무것도 저장하지 않습니다.</p><p><a class="btn light" href="/backup">백업센터</a> <a class="btn light" href="/backup/compare">백업 비교</a></p></section><section class="card"><h2>백업 파일 분석</h2><p class="warnBox">복구 자동 적용 전 단계입니다. 선택 결과는 JSON 계획 파일로만 저장되며, Supabase 데이터는 변경하지 않습니다.</p><form class="upload" method="post" action="/backup/select" enctype="multipart/form-data"><input type="file" name="backup_file" accept="application/json,.json" required/><select name="household_id"><option value="">백업 기준 사용/전체</option>${householdOptions}</select><button type="submit">후보 분석</button></form></section>${errorBox}${validationBox}${summary}${riskBox}${candidateBox}</main><script>(function(){function money(n){n=Number(n||0);return n.toLocaleString('ko-KR')+'원'}window.setCandidateChecks=function(v){document.querySelectorAll('.candidateCheck').forEach(function(x){x.checked=!!v});updateCandidateSelection()};function updateCandidateSelection(){var count=0, amount=0;document.querySelectorAll('.candidateCheck').forEach(function(x){if(x.checked){count++;if((x.getAttribute('data-type')||'expense')==='income')amount-=Number(x.getAttribute('data-amount')||0);else amount+=Number(x.getAttribute('data-amount')||0)}});var c=document.getElementById('candidateSelectedCount');var a=document.getElementById('candidateSelectedAmount');if(c)c.textContent=count+'건 선택';if(a)a.textContent='순지출 기준 '+money(amount)}document.querySelectorAll('.candidateCheck').forEach(function(x){x.addEventListener('change',updateCandidateSelection)});window.downloadImportPlan=function(){var raw=document.getElementById('candidateJson');var rows=[];try{rows=JSON.parse(raw?raw.value:'[]')}catch(e){rows=[]}var selected=[];document.querySelectorAll('.candidateCheck').forEach(function(x,idx){if(x.checked&&rows[idx])selected.push(rows[idx])});var payload={app:'kakao-accountbook',version:'V19.8-BUDGET-ALERT',created_at:new Date().toISOString(),mode:'candidate_plan_only_no_db_write',selected_count:selected.length,selected:selected};var blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='accountbook_import_candidate_plan.json';document.body.appendChild(a);a.click();setTimeout(function(){URL.revokeObjectURL(a.href);a.remove()},1000)};updateCandidateSelection();})();</script></body></html>`;
}

async function handleBackupCandidateSelectPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  return htmlResponse(renderBackupCandidateSelectHtml({ households, householdId, month: currentMonthKst() }));
}

async function handleBackupCandidateSelectPost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  let households = [];
  try { households = await fetchAdminHouseholds(env); } catch (_) {}
  try {
    const form = await request.formData();
    const file = form.get("backup_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderBackupCandidateSelectHtml({ households, error: "업로드된 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 8 * 1024 * 1024) {
      return htmlResponse(renderBackupCandidateSelectHtml({ households, error: "파일이 너무 큽니다. 8MB 이하 JSON만 먼저 분석하세요." }), 400);
    }
    const payload = JSON.parse(raw);
    const validation = validateBackupPayloadShape(payload);
    const scope = safeObject(payload.scope);
    const month = validMonth(scope.month) || currentMonthKst();
    const formHouseholdId = String(form.get("household_id") || "").trim();
    const householdId = formHouseholdId || String(scope.household_id || "").trim();
    if (!validation.ok) {
      return htmlResponse(renderBackupCandidateSelectHtml({ payload, validation, households, month, householdId }), 400);
    }
    const currentRows = await fetchAdminRows(env, { month, householdId, type: "all" });
    const compare = compareBackupTransactions(safeArray(payload.transactions), currentRows);
    return htmlResponse(renderBackupCandidateSelectHtml({ payload, validation, compare, households, month, householdId }));
  } catch (err) {
    rememberOpsEvent({ kind: "backup_candidate_failed", severity: "warn", path: "/backup/import-candidates", method: "POST", detail: safeError(err) });
    return htmlResponse(renderBackupCandidateSelectHtml({ households, error: "가져오기 후보를 분석하지 못했습니다. 파일 구조와 선택한 가계부를 확인해 주세요." }), 400);
  }
}


function safeCandidatePlanRows(plan) {
  const p = safeObject(plan);
  const rows = Array.isArray(p.selected) ? p.selected : Array.isArray(p.rows) ? p.rows : [];
  return rows.map((r) => transactionComparable(r)).filter((r) => r.transaction_date || r.memo || r.amount);
}

function validateImportCandidatePlan(plan) {
  const errors = [];
  const warnings = [];
  const p = safeObject(plan);
  if (!p || !Object.keys(p).length) errors.push("JSON 객체가 아닙니다.");
  if (p.app && p.app !== "kakao-accountbook") warnings.push("app 값이 kakao-accountbook이 아닙니다.");
  if (p.mode && p.mode !== "candidate_plan_only_no_db_write") warnings.push("v10.4 후보 선택 계획 파일이 아닐 수 있습니다.");
  if (!Array.isArray(p.selected) && !Array.isArray(p.rows)) errors.push("selected 배열이 없습니다.");
  const rows = safeCandidatePlanRows(p);
  if (!rows.length) errors.push("가져오기 후보가 0건입니다.");
  const badDate = rows.filter((r) => !isValidTransactionDateString(r.transaction_date)).length;
  const badAmount = rows.filter((r) => !Number.isFinite(Number(r.amount))).length;
  if (badDate) errors.push(`날짜 형식이 잘못된 후보 ${badDate}건`);
  if (badAmount) errors.push(`금액이 숫자가 아닌 후보 ${badAmount}건`);
  const expected = Number(p.selected_count || rows.length);
  if (Number.isFinite(expected) && expected !== rows.length) warnings.push(`selected_count(${expected})와 실제 후보 수(${rows.length})가 다릅니다.`);
  const income = rows.filter((r) => r.type === "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  const expense = rows.filter((r) => r.type !== "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  return { ok: errors.length === 0, errors, warnings, rows, counts: { selected: rows.length, income, expense, balance: income - expense } };
}

function finalCheckAgainstCurrent(candidateRows, currentRows) {
  const current = safeArray(currentRows);
  const currentBySignature = new Map();
  for (const row of current) {
    const sig = transactionSignature(row);
    if (!currentBySignature.has(sig)) currentBySignature.set(sig, []);
    currentBySignature.get(sig).push(row);
  }
  const stillNew = [];
  const nowDuplicate = [];
  for (const row of safeArray(candidateRows)) {
    const sig = transactionSignature(row);
    if (currentBySignature.has(sig)) nowDuplicate.push({ backup: row, current: currentBySignature.get(sig)[0] });
    else stillNew.push(row);
  }
  const risk = nowDuplicate.length ? "warn" : "good";
  return { risk, stillNew, nowDuplicate, counts: { plan: candidateRows.length, current: current.length, still_new: stillNew.length, now_duplicate: nowDuplicate.length } };
}

function renderFinalCheckRows(rows = []) {
  const arr = safeArray(rows).slice(0, 80);
  if (!arr.length) return `<tr><td colspan="6">표시할 항목이 없습니다.</td></tr>`;
  return arr.map((row) => {
    const r = safeObject(row.backup || row);
    return `<tr><td>${escapeHtml(String(r.transaction_date || ""))}</td><td>${r.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(r.amount || 0)}원</td><td>${escapeHtml(r.category || "")}</td><td>${escapeHtml(r.memo || r.raw_text || "")}</td><td>${escapeHtml(r.payment_method || "")}</td></tr>`;
  }).join("");
}

function renderImportFinalCheckHtml({ households = [], householdId = "", month = "", validation = null, finalCheck = null, passwordOk = false, error = "" } = {}) {
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const errorBox = error ? `<section class="card bad"><h2>최종 확인 실패</h2><p>${escapeHtml(error)}</p></section>` : "";
  const validationBox = validation ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>계획 파일 검증: ${validation.ok ? "정상" : "확인 필요"}</h2><div class="grid mini"><div class="metric"><span>선택 후보</span><b>${numberWithCommas(validation.counts.selected)}</b></div><div class="metric"><span>수입 합계</span><b>${numberWithCommas(validation.counts.income)}원</b></div><div class="metric"><span>지출 합계</span><b>${numberWithCommas(validation.counts.expense)}원</b></div><div class="metric"><span>잔액 영향</span><b>${numberWithCommas(validation.counts.balance)}원</b></div></div>${validation.errors?.length ? `<h3>오류</h3><ul>${validation.errors.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}${validation.warnings?.length ? `<h3>주의</h3><ul>${validation.warnings.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}</section>` : "";
  const finalHtml = finalCheck ? `<section class="card ${finalCheck.risk === "good" ? "good" : "warn"}"><h2>${finalCheck.risk === "good" ? "최종 확인 통과" : "중복 재확인 필요"}</h2><p>${finalCheck.risk === "good" ? "계획 파일의 모든 후보가 현재 DB에 아직 없어 보입니다. 그래도 이 화면은 DB에 저장하지 않습니다." : "계획 생성 이후 현재 DB에 이미 들어간 항목이 있어 보입니다. 실제 가져오기 전 후보 계획을 다시 만드는 것이 안전합니다."}</p><div class="grid mini"><div class="metric"><span>계획 후보</span><b>${numberWithCommas(finalCheck.counts.plan)}</b></div><div class="metric"><span>현재 거래</span><b>${numberWithCommas(finalCheck.counts.current)}</b></div><div class="metric"><span>아직 신규</span><b>${numberWithCommas(finalCheck.counts.still_new)}</b></div><div class="metric"><span>현재 중복</span><b>${numberWithCommas(finalCheck.counts.now_duplicate)}</b></div></div></section><section class="card"><h2>아직 신규 후보</h2><p class="note">다음 실제 가져오기 단계에서 대상이 될 수 있는 항목입니다. 이 화면에서는 저장하지 않습니다.</p><div class="tableWrap"><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th></tr></thead><tbody>${renderFinalCheckRows(finalCheck.stillNew)}</tbody></table></div></section><section class="card"><h2>현재 중복 후보</h2><p class="note">계획 생성 이후 이미 현재 데이터에 있는 것으로 보이는 항목입니다.</p><div class="tableWrap"><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th></tr></thead><tbody>${renderFinalCheckRows(finalCheck.nowDuplicate)}</tbody></table></div></section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>가져오기 최종 확인</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1160px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#7f1d1d);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.warn{border-color:#fde68a;background:#fffbeb}.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:24px;margin-top:6px}.upload{display:grid;grid-template-columns:1fr 160px 170px 170px;gap:10px}.upload input,.upload select,.upload button{min-height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.upload input[type=file]{padding:10px}.upload button,.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.note{color:#64748b;line-height:1.55}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}.tableWrap{overflow-x:auto}table{width:100%;border-collapse:collapse;background:#fff;min-width:760px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}@media(max-width:840px){.wrap{padding:12px}.hero h1{font-size:24px}.upload{grid-template-columns:1fr}.card{overflow-x:auto}}</style></head><body>${renderUnifiedNav("backup", { month, householdId })}<main class="wrap"><section class="hero"><h1>가져오기 최종 확인</h1><p>v10.4에서 저장한 후보 계획 JSON을 실제 가져오기 전 다시 검증하고, 관리자 비밀번호를 재확인합니다. 이 단계도 DB에 아무것도 저장하지 않습니다.</p><p><a class="btn light" href="/backup/select">후보 선택</a> <a class="btn light" href="/backup/compare">백업 비교</a></p></section><section class="card"><h2>후보 계획 파일 최종 확인</h2><p class="warnBox">선택 계획 JSON과 관리자 비밀번호를 함께 확인합니다. 비밀번호가 맞아도 아직 Supabase에는 저장하지 않습니다.</p><form class="upload" method="post" action="/backup/final-check" enctype="multipart/form-data"><input type="file" name="plan_file" accept="application/json,.json" required/><select name="household_id"><option value="">가계부 선택</option>${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month || currentMonthKst())}"/><input type="password" name="admin_password" placeholder="관리자 비밀번호" autocomplete="current-password" required/><button type="submit">최종 확인</button></form></section>${errorBox}${validationBox}${finalHtml}</main></body></html>`;
}

async function handleImportFinalCheckPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  return htmlResponse(renderImportFinalCheckHtml({ households, householdId, month }));
}

async function handleImportFinalCheckPost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  let households = [];
  try { households = await fetchAdminHouseholds(env); } catch (_) {}
  try {
    const form = await request.formData();
    const password = String(form.get("admin_password") || "").trim();
    const month = validMonth(form.get("month")) || currentMonthKst();
    const householdId = String(form.get("household_id") || "").trim();
    if (!(await checkAdminPassword(env, password))) {
      return htmlResponse(renderImportFinalCheckHtml({ households, month, householdId, error: "관리자 비밀번호 재확인에 실패했습니다." }), 401);
    }
    const file = form.get("plan_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderImportFinalCheckHtml({ households, month, householdId, error: "업로드된 후보 계획 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 4 * 1024 * 1024) {
      return htmlResponse(renderImportFinalCheckHtml({ households, month, householdId, error: "파일이 너무 큽니다. 4MB 이하 후보 계획 파일만 확인하세요." }), 400);
    }
    const plan = JSON.parse(raw);
    const validation = validateImportCandidatePlan(plan);
    if (!validation.ok) {
      return htmlResponse(renderImportFinalCheckHtml({ households, month, householdId, validation, error: "후보 계획 파일 구조를 먼저 확인해야 합니다." }), 400);
    }
    const currentRows = await fetchAdminRows(env, { month, householdId, type: "all" });
    const finalCheck = finalCheckAgainstCurrent(validation.rows, currentRows);
    return htmlResponse(renderImportFinalCheckHtml({ households, month, householdId, validation, finalCheck, passwordOk: true }));
  } catch (err) {
    rememberOpsEvent({ kind: "backup_final_check_failed", severity: "warn", path: "/backup/import-final-check", method: "POST", detail: safeError(err) });
    return htmlResponse(renderImportFinalCheckHtml({ households, error: "최종 확인을 완료하지 못했습니다. 후보 파일을 다시 생성해 주세요." }), 400);
  }
}


const IMPORT_APPLY_LIMIT = 20;
const IMPORT_CONFIRM_TEXT = "가져오기 적용";

function renderImportApplyRows(rows = [], status = "") {
  const arr = safeArray(rows).slice(0, 80);
  if (!arr.length) return `<tr><td colspan="7">표시할 항목이 없습니다.</td></tr>`;
  return arr.map((item) => {
    const row = safeObject(item.row || item.backup || item);
    const message = item.error ? `실패: ${item.error}` : item.id ? `저장됨: ${item.id}` : status;
    return `<tr><td>${escapeHtml(String(row.transaction_date || ""))}</td><td>${row.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(row.amount || 0)}원</td><td>${escapeHtml(row.category || "")}</td><td>${escapeHtml(row.memo || row.raw_text || "")}</td><td>${escapeHtml(row.payment_method || "")}</td><td>${escapeHtml(message || "")}</td></tr>`;
  }).join("");
}

function renderImportApplyHtml({ households = [], householdId = "", month = "", validation = null, finalCheck = null, result = null, error = "" } = {}) {
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const errorBox = error ? `<section class="card bad"><h2>가져오기 적용 실패</h2><p>${escapeHtml(error)}</p></section>` : "";
  const validationBox = validation ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>계획 파일 검증: ${validation.ok ? "정상" : "확인 필요"}</h2><div class="grid mini"><div class="metric"><span>계획 후보</span><b>${numberWithCommas(validation.counts.selected)}</b></div><div class="metric"><span>수입</span><b>${numberWithCommas(validation.counts.income)}원</b></div><div class="metric"><span>지출</span><b>${numberWithCommas(validation.counts.expense)}원</b></div><div class="metric"><span>잔액 영향</span><b>${numberWithCommas(validation.counts.balance)}원</b></div></div>${validation.errors?.length ? `<h3>오류</h3><ul>${validation.errors.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}${validation.warnings?.length ? `<h3>주의</h3><ul>${validation.warnings.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}</section>` : "";
  const finalBox = finalCheck ? `<section class="card ${finalCheck.counts.now_duplicate ? "warn" : "good"}"><h2>적용 직전 중복 재검사</h2><div class="grid mini"><div class="metric"><span>계획 후보</span><b>${numberWithCommas(finalCheck.counts.plan)}</b></div><div class="metric"><span>아직 신규</span><b>${numberWithCommas(finalCheck.counts.still_new)}</b></div><div class="metric"><span>현재 중복</span><b>${numberWithCommas(finalCheck.counts.now_duplicate)}</b></div><div class="metric"><span>1회 적용 제한</span><b>${numberWithCommas(IMPORT_APPLY_LIMIT)}건</b></div></div><p class="note">${finalCheck.counts.now_duplicate ? "현재 DB에 이미 들어간 항목은 자동으로 제외합니다." : "중복 항목 없이 신규 후보만 적용 대상입니다."}</p></section>` : "";
  const resultBox = result ? `<section class="card ${result.failed ? "warn" : "good"}"><h2>적용 결과</h2><div class="grid mini"><div class="metric"><span>요청 후보</span><b>${numberWithCommas(result.requested)}</b></div><div class="metric"><span>적용 대상</span><b>${numberWithCommas(result.to_apply)}</b></div><div class="metric"><span>성공</span><b>${numberWithCommas(result.applied)}</b></div><div class="metric"><span>실패</span><b>${numberWithCommas(result.failed)}</b></div><div class="metric"><span>중복 제외</span><b>${numberWithCommas(result.skipped_duplicate)}</b></div><div class="metric"><span>제한 초과 제외</span><b>${numberWithCommas(result.skipped_limit)}</b></div></div><p class="note">적용 성공 건은 Supabase transactions 테이블에 저장되었습니다. 실패/제외 항목은 아래 표에서 확인하세요.</p></section><section class="card"><h2>성공 항목</h2><div class="tableWrap"><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th><th>상태</th></tr></thead><tbody>${renderImportApplyRows(result.success, "저장됨")}</tbody></table></div></section><section class="card"><h2>실패/제외 항목</h2><div class="tableWrap"><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th><th>상태</th></tr></thead><tbody>${renderImportApplyRows([...result.failed_rows, ...result.duplicate_rows, ...result.limit_rows])}</tbody></table></div></section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>가져오기 실제 적용</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1160px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#4c0519);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.warn{border-color:#fde68a;background:#fffbeb}.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:24px;margin-top:6px}.upload{display:grid;grid-template-columns:1fr 155px 155px 165px 170px;gap:10px}.upload input,.upload select,.upload button{min-height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.upload input[type=file]{padding:10px}.upload button,.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.btn.danger{background:#dc2626}.note{color:#64748b;line-height:1.55}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}.dangerBox{background:#fef2f2;border:1px solid #fecaca;border-radius:16px;padding:12px;color:#991b1b;line-height:1.55;font-weight:800}.tableWrap{overflow-x:auto}table{width:100%;border-collapse:collapse;background:#fff;min-width:820px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}@media(max-width:980px){.wrap{padding:12px}.hero h1{font-size:24px}.upload{grid-template-columns:1fr}.card{overflow-x:auto}}</style></head><body>${renderUnifiedNav("backup", { month, householdId })}<main class="wrap"><section class="hero"><h1>가져오기 실제 적용</h1><p>후보 계획 JSON을 최종 재검사한 뒤 신규 후보만 Supabase에 저장합니다. 안전을 위해 1회 최대 ${IMPORT_APPLY_LIMIT}건만 적용합니다.</p><p><a class="btn light" href="/backup/final-check">최종 확인</a> <a class="btn light" href="/backup/select">후보 선택</a></p></section><section class="card"><h2>실제 적용 전 확인</h2><p class="dangerBox">이 화면은 실제 DB에 거래를 추가합니다. 적용 전 반드시 백업을 내려받고, 확인 문구에 <b>${IMPORT_CONFIRM_TEXT}</b>을 정확히 입력하세요.</p><form class="upload" method="post" action="/backup/apply" enctype="multipart/form-data"><input type="file" name="plan_file" accept="application/json,.json" required/><select name="household_id" required><option value="">가계부 선택</option>${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month || currentMonthKst())}" required/><input type="password" name="admin_password" placeholder="관리자 비밀번호" autocomplete="current-password" required/><input name="confirm_text" placeholder="${escapeHtml(IMPORT_CONFIRM_TEXT)}" required/><button class="btn danger" type="submit">최대 ${IMPORT_APPLY_LIMIT}건 적용</button></form></section>${errorBox}${validationBox}${finalBox}${resultBox}</main></body></html>`;
}

async function handleImportApplyPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  return htmlResponse(renderImportApplyHtml({ households, householdId, month }));
}

async function handleImportApplyPost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  let households = [];
  try { households = await fetchAdminHouseholds(env); } catch (_) {}
  let month = currentMonthKst();
  let householdId = "";
  try {
    const form = await request.formData();
    const password = String(form.get("admin_password") || "").trim();
    month = validMonth(form.get("month")) || currentMonthKst();
    householdId = String(form.get("household_id") || "").trim();
    const confirmText = String(form.get("confirm_text") || "").trim();
    if (!householdId) {
      return htmlResponse(renderImportApplyHtml({ households, month, householdId, error: "가져올 가계부를 선택해야 합니다." }), 400);
    }
    if (confirmText !== IMPORT_CONFIRM_TEXT) {
      return htmlResponse(renderImportApplyHtml({ households, month, householdId, error: `확인 문구를 정확히 입력해야 합니다: ${IMPORT_CONFIRM_TEXT}` }), 400);
    }
    if (!(await checkAdminPassword(env, password))) {
      return htmlResponse(renderImportApplyHtml({ households, month, householdId, error: "관리자 비밀번호 재확인에 실패했습니다." }), 401);
    }
    const file = form.get("plan_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderImportApplyHtml({ households, month, householdId, error: "업로드된 후보 계획 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 4 * 1024 * 1024) {
      return htmlResponse(renderImportApplyHtml({ households, month, householdId, error: "파일이 너무 큽니다. 4MB 이하 후보 계획 파일만 적용하세요." }), 400);
    }
    const plan = JSON.parse(raw);
    const validation = validateImportCandidatePlan(plan);
    if (!validation.ok) {
      return htmlResponse(renderImportApplyHtml({ households, month, householdId, validation, error: "후보 계획 파일 구조를 먼저 확인해야 합니다." }), 400);
    }
    const currentRows = await fetchAdminRows(env, { month, householdId, type: "all" });
    const finalCheck = finalCheckAgainstCurrent(validation.rows, currentRows);
    const applyRows = finalCheck.stillNew.slice(0, IMPORT_APPLY_LIMIT);
    const limitRows = finalCheck.stillNew.slice(IMPORT_APPLY_LIMIT).map((row) => ({ row, error: `1회 ${IMPORT_APPLY_LIMIT}건 제한으로 제외` }));
    const duplicateRows = finalCheck.nowDuplicate.map((x) => ({ row: x.backup || x, error: "현재 DB 중복으로 제외" }));
    const success = [];
    const failedRows = [];
    const insertedSigs = new Set(currentRows.map((r) => transactionSignature(r)));
    for (const row of applyRows) {
      const sig = transactionSignature(row);
      if (insertedSigs.has(sig)) {
        duplicateRows.push({ row, error: "적용 중 중복 재감지로 제외" });
        continue;
      }
      try {
        const created = await createManualTransaction(env, {
          household_id: householdId,
          user_id: row.user_id || "",
          type: row.type === "income" ? "income" : "expense",
          transaction_date: row.transaction_date,
          amount: row.amount,
          category: row.category || "",
          memo: row.memo || "",
          payment_method: row.payment_method || "",
          raw_text: row.memo || "",
          source: "backup_import_v19_3",
        });
        insertedSigs.add(sig);
        success.push({ row, id: created?.id || "" });
      } catch (err) {
        rememberOpsEvent({ kind: "backup_import_row_failed", severity: "warn", path: "/backup/import-apply", method: "POST", detail: safeError(err) });
        failedRows.push({ row, error: "저장하지 못함(기존 데이터 유지)" });
      }
    }
    const result = {
      requested: validation.rows.length,
      to_apply: applyRows.length,
      applied: success.length,
      failed: failedRows.length,
      skipped_duplicate: duplicateRows.length,
      skipped_limit: limitRows.length,
      success,
      failed_rows: failedRows,
      duplicate_rows: duplicateRows,
      limit_rows: limitRows,
    };
    return htmlResponse(renderImportApplyHtml({ households, month, householdId, validation, finalCheck, result }));
  } catch (err) {
    rememberOpsEvent({ kind: "backup_import_apply_failed", severity: "error", path: "/backup/import-apply", method: "POST", detail: safeError(err) });
    return htmlResponse(renderImportApplyHtml({ households, month, householdId, error: "가져오기를 완료하지 못했습니다. 적용 결과를 확인한 뒤 같은 파일을 반복 제출하지 마세요." }), 400);
  }
}


function isBackupImportSource(value) {
  return String(value || "").includes("backup_import_");
}

function importHistoryBatchKey(row) {
  const r = safeObject(row);
  const created = String(r.created_at || "");
  const day = created.slice(0, 10) || String(r.transaction_date || "").slice(0, 10) || "날짜없음";
  const hour = created.slice(11, 13) || "00";
  return `${day} ${hour}시`;
}

async function fetchImportHistoryRows(env, { month, householdId }) {
  const rows = await fetchAdminRows(env, { month, householdId, type: "all" });
  return rows.filter((r) => isBackupImportSource(r.source));
}

function summarizeImportHistory(rows = []) {
  const imported = safeArray(rows);
  const total = imported.length;
  const income = imported.filter((r) => r.type === "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  const expense = imported.filter((r) => r.type !== "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  const byBatch = {};
  for (const r of imported) {
    const key = importHistoryBatchKey(r);
    if (!byBatch[key]) byBatch[key] = { key, count: 0, income: 0, expense: 0, first_created: r.created_at || "", last_created: r.created_at || "" };
    byBatch[key].count += 1;
    if (r.type === "income") byBatch[key].income += Number(r.amount || 0);
    else byBatch[key].expense += Number(r.amount || 0);
    if (r.created_at && (!byBatch[key].first_created || r.created_at < byBatch[key].first_created)) byBatch[key].first_created = r.created_at;
    if (r.created_at && (!byBatch[key].last_created || r.created_at > byBatch[key].last_created)) byBatch[key].last_created = r.created_at;
  }
  const batches = Object.values(byBatch).sort((a, b) => String(b.last_created || b.key).localeCompare(String(a.last_created || a.key)));
  return { total, income, expense, balance: income - expense, batches };
}

function renderImportHistoryRows(rows = []) {
  const arr = safeArray(rows).slice(0, 300);
  if (!arr.length) return `<tr><td colspan="9">가져오기 이력이 없습니다.</td></tr>`;
  return arr.map((r) => `<tr><td>${escapeHtml(String(r.created_at || "").replace("T", " ").slice(0, 19))}</td><td>${escapeHtml(String(r.transaction_date || ""))}</td><td>${r.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(r.amount || 0)}원</td><td>${escapeHtml(r.category || "")}</td><td>${escapeHtml(r.memo || r.raw_text || "")}</td><td>${escapeHtml(r.payment_method || "")}</td><td>${escapeHtml(r.source || "")}</td><td>${escapeHtml(r.id || "")}</td></tr>`).join("");
}

function renderImportHistoryBatchRows(batches = []) {
  const arr = safeArray(batches);
  if (!arr.length) return `<tr><td colspan="6">가져오기 배치가 없습니다.</td></tr>`;
  return arr.map((b) => `<tr><td><b>${escapeHtml(b.key)}</b></td><td>${numberWithCommas(b.count)}건</td><td>${numberWithCommas(b.income)}원</td><td>${numberWithCommas(b.expense)}원</td><td>${escapeHtml(String(b.first_created || "").replace("T", " ").slice(0, 19))}</td><td>${escapeHtml(String(b.last_created || "").replace("T", " ").slice(0, 19))}</td></tr>`).join("");
}

async function handleImportHistoryPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  const selectedHousehold = households.find((h) => h.id === householdId) || households[0] || null;
  const hid = selectedHousehold?.id || "";
  const rows = await fetchImportHistoryRows(env, { month, householdId: hid });
  const summary = summarizeImportHistory(rows);
  const qs = new URLSearchParams();
  qs.set("month", month);
  if (hid) qs.set("household_id", hid);
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === hid ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>가져오기 이력</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1180px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#1e3a8a);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.filters{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}.filters select,.filters input,.filters button{height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.filters button{background:#111827;color:#fff;font-weight:1000}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:24px;margin-top:6px}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px}.btn.light{background:#eff6ff;color:#1e3a8a}.note{color:#64748b;line-height:1.55}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}.tableWrap{overflow-x:auto}table{width:100%;border-collapse:collapse;background:#fff;min-width:980px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}}</style></head><body>${renderUnifiedNav("backup", { month, householdId: hid })}<main class="wrap"><section class="hero"><h1>가져오기 이력/감사 로그</h1><p>백업 가져오기로 실제 저장된 거래를 확인합니다. 현재는 source 값이 backup_import_* 인 거래를 기준으로 집계합니다.</p><form class="filters" method="get" action="/backup/import-history"><select name="household_id">${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month)}"/><button type="submit">조회</button></form></section><section class="grid"><div class="metric"><span>가져오기 건수</span><b>${numberWithCommas(summary.total)}건</b></div><div class="metric"><span>수입 합계</span><b>${numberWithCommas(summary.income)}원</b></div><div class="metric"><span>지출 합계</span><b>${numberWithCommas(summary.expense)}원</b></div><div class="metric"><span>잔액 영향</span><b>${numberWithCommas(summary.balance)}원</b></div></section><section class="card"><h2>내보내기</h2><p class="warnBox">가져오기 이력은 실제 저장된 거래 기준입니다. 필요하면 CSV로 내려받아 보관하세요.</p><p><a class="btn light" href="/backup/import-history.csv?${escapeHtml(qs.toString())}">이력 CSV 다운로드</a> <a class="btn" href="/backup/apply?${escapeHtml(qs.toString())}">가져오기 실제 적용</a></p></section><section class="card"><h2>시간대별 요약</h2><div class="tableWrap"><table><thead><tr><th>배치 추정</th><th>건수</th><th>수입</th><th>지출</th><th>시작</th><th>마지막</th></tr></thead><tbody>${renderImportHistoryBatchRows(summary.batches)}</tbody></table></div></section><section class="card"><h2>상세 이력</h2><p class="note">최근 300건까지만 화면에 표시합니다. 전체는 CSV로 확인하세요.</p><div class="tableWrap"><table><thead><tr><th>저장시각</th><th>거래일</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th><th>source</th><th>ID</th></tr></thead><tbody>${renderImportHistoryRows(rows)}</tbody></table></div></section></main></body></html>`);
}

function csvCell(value) {
  return `"${String(value ?? "").replace(/"/g, '""')}"`;
}

async function handleImportHistoryCsv(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const householdId = String(url.searchParams.get("household_id") || "").trim();
  const rows = await fetchImportHistoryRows(env, { month, householdId });
  const header = ["created_at", "transaction_date", "type", "amount", "category", "memo", "payment_method", "source", "id"];
  const lines = [header.join(",")];
  for (const r of rows) {
    lines.push([r.created_at, r.transaction_date, r.type, r.amount, r.category, r.memo || r.raw_text || "", r.payment_method, r.source, r.id].map(csvCell).join(","));
  }
  return new Response("\ufeff" + lines.join("\n"), {
    headers: {
      "content-type": "text/csv; charset=utf-8",
      "content-disposition": `attachment; filename="accountbook_import_history_${month}.csv"`,
      "cache-control": "no-store",
    },
  });
}


function renderRollbackCandidateRows(rows = []) {
  const arr = safeArray(rows).slice(0, 500);
  if (!arr.length) return `<tr><td colspan="10">되돌리기 후보가 없습니다.</td></tr>`;
  return arr.map((r, idx) => {
    const row = safeObject(r);
    const json = escapeHtml(JSON.stringify({
      id: row.id || "",
      household_id: row.household_id || "",
      transaction_date: row.transaction_date || "",
      type: row.type === "income" ? "income" : "expense",
      amount: Number(row.amount || 0),
      category: row.category || "",
      memo: row.memo || row.raw_text || "",
      payment_method: row.payment_method || "",
      source: row.source || "",
      created_at: row.created_at || ""
    }));
    return `<tr data-rollback-row="1"><td><input class="rollbackCheck" type="checkbox" data-idx="${idx}" data-amount="${escapeHtml(row.amount || 0)}" data-type="${escapeHtml(row.type || "expense")}"/></td><td>${escapeHtml(String(row.created_at || "").replace("T", " ").slice(0, 19))}</td><td>${escapeHtml(String(row.transaction_date || ""))}</td><td>${row.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(row.amount || 0)}원</td><td>${escapeHtml(row.category || "")}</td><td>${escapeHtml(row.memo || row.raw_text || "")}</td><td>${escapeHtml(row.payment_method || "")}</td><td>${escapeHtml(row.source || "")}</td><td><code>${escapeHtml(row.id || "")}</code><input type="hidden" class="rollbackPayload" value="${json}"/></td></tr>`;
  }).join("");
}

function summarizeRollbackCandidates(rows = []) {
  const arr = safeArray(rows);
  const income = arr.filter((r) => r.type === "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  const expense = arr.filter((r) => r.type !== "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  const bySource = {};
  for (const r of arr) {
    const key = r.source || "unknown";
    bySource[key] = (bySource[key] || 0) + 1;
  }
  return { count: arr.length, income, expense, balance: income - expense, bySource };
}

function renderRollbackSourceRows(bySource = {}) {
  const entries = Object.entries(bySource).sort((a, b) => b[1] - a[1]);
  if (!entries.length) return `<tr><td colspan="2">source별 후보가 없습니다.</td></tr>`;
  return entries.map(([source, count]) => `<tr><td>${escapeHtml(source)}</td><td>${numberWithCommas(count)}건</td></tr>`).join("");
}

async function handleRollbackCandidatePage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  const selectedHousehold = households.find((h) => h.id === householdId) || households[0] || null;
  const hid = selectedHousehold?.id || "";
  const sourceFilter = String(url.searchParams.get("source") || "").trim();
  let rows = await fetchImportHistoryRows(env, { month, householdId: hid });
  if (sourceFilter) rows = rows.filter((r) => String(r.source || "") === sourceFilter);
  const summary = summarizeRollbackCandidates(rows);
  const qs = new URLSearchParams();
  qs.set("month", month);
  if (hid) qs.set("household_id", hid);
  const allSources = summarizeRollbackCandidates(await fetchImportHistoryRows(env, { month, householdId: hid })).bySource;
  const sourceOptions = Object.keys(allSources).sort().map((src) => `<option value="${escapeHtml(src)}" ${src === sourceFilter ? "selected" : ""}>${escapeHtml(src)}</option>`).join("");
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === hid ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>되돌리기 후보</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1200px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#7c2d12);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.filters{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}.filters select,.filters input,.filters button{height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.filters button{background:#111827;color:#fff;font-weight:1000}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:24px;margin-top:6px}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.btn.green{background:#059669}.note{color:#64748b;line-height:1.55}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}.selectedBar{display:flex;gap:10px;align-items:center;flex-wrap:wrap;margin:10px 0;padding:12px;border-radius:16px;background:#fff7ed;color:#9a3412;font-weight:1000}.actions{display:flex;gap:8px;flex-wrap:wrap}.tableWrap{overflow-x:auto}table{width:100%;border-collapse:collapse;background:#fff;min-width:1080px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}.rollbackCheck{width:20px;height:20px}code{background:#f1f5f9;border-radius:8px;padding:3px 6px}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}}</style></head><body>${renderUnifiedNav("backup", { month, householdId: hid })}<main class="wrap"><section class="hero"><h1>되돌리기 후보 화면</h1><p>가져오기 이력 중 되돌릴 후보만 선택해 계획 JSON을 만듭니다. 이 화면은 DB에서 삭제하지 않습니다.</p><form class="filters" method="get" action="/backup/rollback-candidates"><select name="household_id">${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month)}"/><select name="source"><option value="">source 전체</option>${sourceOptions}</select><button type="submit">후보 조회</button></form></section><section class="grid"><div class="metric"><span>되돌리기 후보</span><b>${numberWithCommas(summary.count)}건</b></div><div class="metric"><span>수입 후보</span><b>${numberWithCommas(summary.income)}원</b></div><div class="metric"><span>지출 후보</span><b>${numberWithCommas(summary.expense)}원</b></div><div class="metric"><span>잔액 영향</span><b>${numberWithCommas(summary.balance)}원</b></div></section><section class="card"><h2>주의</h2><p class="warnBox">되돌리기 후보 화면은 계획 파일만 만듭니다. 실제 삭제는 다음 단계에서 관리자 비밀번호 재확인, 확인 문구, 중복/존재 재검사 후 제한적으로 처리하는 방식이 안전합니다.</p><div class="actions"><a class="btn light" href="/backup/import-history?${escapeHtml(qs.toString())}">가져오기 이력으로 돌아가기</a><button type="button" class="btn light" onclick="setRollbackChecks(true)">전체 선택</button><button type="button" class="btn light" onclick="setRollbackChecks(false)">선택 해제</button><button type="button" class="btn green" onclick="downloadRollbackPlan()">선택 계획 JSON 저장</button></div><div class="selectedBar"><b id="rollbackSelectedCount">0건 선택</b><span id="rollbackSelectedAmount">0원</span></div></section><section class="card"><h2>source별 후보</h2><div class="tableWrap"><table><thead><tr><th>source</th><th>건수</th></tr></thead><tbody>${renderRollbackSourceRows(summary.bySource)}</tbody></table></div></section><section class="card"><h2>되돌리기 후보 상세</h2><p class="note">최근 500건까지만 화면에 표시합니다. 선택 계획은 거래 ID와 거래 요약을 포함합니다.</p><div class="tableWrap"><table><thead><tr><th>선택</th><th>저장시각</th><th>거래일</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th><th>source</th><th>ID</th></tr></thead><tbody>${renderRollbackCandidateRows(rows)}</tbody></table></div></section></main><script>(function(){function money(n){n=Number(n||0);return n.toLocaleString('ko-KR')+'원'}window.setRollbackChecks=function(v){document.querySelectorAll('.rollbackCheck').forEach(function(x){x.checked=!!v});updateRollbackSelection()};function selectedRows(){var out=[];document.querySelectorAll('.rollbackCheck').forEach(function(x){if(!x.checked)return;var tr=x.closest('tr');var payload=tr?tr.querySelector('.rollbackPayload'):null;try{if(payload)out.push(JSON.parse(payload.value||'{}'))}catch(e){}});return out}function updateRollbackSelection(){var rows=selectedRows();var amount=0;rows.forEach(function(r){if((r.type||'expense')==='income')amount-=Number(r.amount||0);else amount+=Number(r.amount||0)});var c=document.getElementById('rollbackSelectedCount');var a=document.getElementById('rollbackSelectedAmount');if(c)c.textContent=rows.length+'건 선택';if(a)a.textContent='되돌리기 순지출 영향 '+money(amount)}document.querySelectorAll('.rollbackCheck').forEach(function(x){x.addEventListener('change',updateRollbackSelection)});window.downloadRollbackPlan=function(){var selected=selectedRows();var payload={app:'kakao-accountbook',version:'V19.8-BUDGET-ALERT',created_at:new Date().toISOString(),mode:'rollback_candidate_plan_only_no_db_write',month:${JSON.stringify(month)},household_id:${JSON.stringify(hid)},selected_count:selected.length,selected:selected};var blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='accountbook_import_rollback_candidate_plan.json';document.body.appendChild(a);a.click();setTimeout(function(){URL.revokeObjectURL(a.href);a.remove()},1000)};updateRollbackSelection();})();</script></body></html>`);
}


function safeRollbackPlanRows(plan) {
  const p = safeObject(plan);
  const rows = Array.isArray(p.selected) ? p.selected : Array.isArray(p.rows) ? p.rows : [];
  return rows.map((r) => {
    const row = safeObject(r);
    return {
      id: String(row.id || "").trim(),
      household_id: String(row.household_id || "").trim(),
      transaction_date: String(row.transaction_date || "").slice(0, 10),
      type: row.type === "income" ? "income" : "expense",
      amount: Number(row.amount || 0),
      category: String(row.category || "").slice(0, 80),
      memo: String(row.memo || row.raw_text || "").slice(0, 160),
      payment_method: String(row.payment_method || "").slice(0, 40),
      source: String(row.source || "").slice(0, 80),
      created_at: String(row.created_at || ""),
    };
  }).filter((r) => r.id || r.transaction_date || r.memo || r.amount);
}

function validateRollbackCandidatePlan(plan) {
  const errors = [];
  const warnings = [];
  const p = safeObject(plan);
  if (!p || !Object.keys(p).length) errors.push("JSON 객체가 아닙니다.");
  if (p.app && p.app !== "kakao-accountbook") warnings.push("app 값이 kakao-accountbook이 아닙니다.");
  if (p.mode && p.mode !== "rollback_candidate_plan_only_no_db_write") warnings.push("v10.9 되돌리기 후보 계획 파일이 아닐 수 있습니다.");
  if (!Array.isArray(p.selected) && !Array.isArray(p.rows)) errors.push("selected 배열이 없습니다.");
  const rows = safeRollbackPlanRows(p);
  if (!rows.length) errors.push("되돌리기 후보가 0건입니다.");
  const missingId = rows.filter((r) => !r.id).length;
  const badAmount = rows.filter((r) => !Number.isFinite(Number(r.amount))).length;
  const nonImport = rows.filter((r) => !isBackupImportSource(r.source)).length;
  if (missingId) errors.push(`거래 ID가 없는 후보 ${missingId}건`);
  if (badAmount) errors.push(`금액이 숫자가 아닌 후보 ${badAmount}건`);
  if (nonImport) errors.push(`가져오기 source가 아닌 후보 ${nonImport}건`);
  const expected = Number(p.selected_count || rows.length);
  if (Number.isFinite(expected) && expected !== rows.length) warnings.push(`selected_count(${expected})와 실제 후보 수(${rows.length})가 다릅니다.`);
  const income = rows.filter((r) => r.type === "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  const expense = rows.filter((r) => r.type !== "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  return { ok: errors.length === 0, errors, warnings, rows, counts: { selected: rows.length, income, expense, balance: income - expense } };
}

async function fetchTransactionsByIds(env, ids = []) {
  const out = [];
  for (const id of safeArray(ids).map((x) => String(x || "").trim()).filter(Boolean).slice(0, 200)) {
    try {
      const rows = await supabase(env, `/rest/v1/transactions?id=eq.${encodeURIComponent(id)}&select=*`, { method: "GET" }) || [];
      if (Array.isArray(rows) && rows[0]) out.push(rows[0]);
    } catch (_) {}
  }
  return out;
}

function compareRollbackPlanToCurrent(planRows = [], currentRows = []) {
  const currentById = new Map();
  for (const row of safeArray(currentRows)) currentById.set(String(safeObject(row).id || ""), safeObject(row));
  const deletable = [];
  const missing = [];
  const mismatch = [];
  const blocked = [];
  for (const planRow of safeArray(planRows)) {
    const current = currentById.get(String(planRow.id || ""));
    if (!current) {
      missing.push({ plan: planRow, error: "현재 DB에 거래가 없음" });
      continue;
    }
    if (!isBackupImportSource(current.source)) {
      blocked.push({ plan: planRow, current, error: "현재 거래 source가 가져오기 항목이 아님" });
      continue;
    }
    const diff = [];
    for (const field of ["transaction_date", "type", "amount", "category", "memo", "payment_method", "source"]) {
      const a = field === "amount" ? Number(planRow[field] || 0) : String(planRow[field] || "");
      const b = field === "amount" ? Number(current[field] || 0) : String((field === "memo" ? (current.memo || current.raw_text || "") : current[field]) || "");
      if (String(a) !== String(b)) diff.push(field);
    }
    if (diff.length) mismatch.push({ plan: planRow, current, diff, error: `현재 데이터와 차이: ${diff.join(", ")}` });
    else deletable.push({ plan: planRow, current });
  }
  const income = deletable.filter((x) => x.plan.type === "income").reduce((a, x) => a + Number(x.plan.amount || 0), 0);
  const expense = deletable.filter((x) => x.plan.type !== "income").reduce((a, x) => a + Number(x.plan.amount || 0), 0);
  return {
    ok: mismatch.length === 0 && blocked.length === 0,
    counts: {
      plan: planRows.length,
      deletable: deletable.length,
      missing: missing.length,
      mismatch: mismatch.length,
      blocked: blocked.length,
      income,
      expense,
      balance: income - expense,
    },
    deletable,
    missing,
    mismatch,
    blocked,
  };
}

function renderRollbackFinalRows(items = [], mode = "plan") {
  const arr = safeArray(items).slice(0, 120);
  if (!arr.length) return `<tr><td colspan="8">표시할 항목이 없습니다.</td></tr>`;
  return arr.map((item) => {
    const row = safeObject(item.plan || item.current || item);
    const reason = item.error || (Array.isArray(item.diff) ? `차이: ${item.diff.join(", ")}` : "");
    return `<tr><td>${escapeHtml(String(row.id || ""))}</td><td>${escapeHtml(String(row.transaction_date || ""))}</td><td>${row.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(row.amount || 0)}원</td><td>${escapeHtml(row.category || "")}</td><td>${escapeHtml(row.memo || row.raw_text || "")}</td><td>${escapeHtml(row.source || "")}</td><td>${escapeHtml(reason)}</td></tr>`;
  }).join("");
}

function renderRollbackFinalCheckHtml({ households = [], householdId = "", month = "", validation = null, finalCheck = null, error = "" } = {}) {
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const errorBox = error ? `<section class="card bad"><h2>최종 확인 실패</h2><p>${escapeHtml(error)}</p></section>` : "";
  const validationBox = validation ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>계획 파일 검증: ${validation.ok ? "정상" : "확인 필요"}</h2><div class="grid mini"><div class="metric"><span>선택 후보</span><b>${numberWithCommas(validation.counts.selected)}</b></div><div class="metric"><span>수입 후보</span><b>${numberWithCommas(validation.counts.income)}원</b></div><div class="metric"><span>지출 후보</span><b>${numberWithCommas(validation.counts.expense)}원</b></div><div class="metric"><span>잔액 영향</span><b>${numberWithCommas(validation.counts.balance)}원</b></div></div>${validation.errors?.length ? `<h3>오류</h3><ul>${validation.errors.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}${validation.warnings?.length ? `<h3>주의</h3><ul>${validation.warnings.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}</section>` : "";
  const finalHtml = finalCheck ? `<section class="card ${finalCheck.ok ? "good" : "warn"}"><h2>${finalCheck.ok ? "삭제 전 최종 확인 통과" : "삭제 전 확인 필요"}</h2><p>${finalCheck.ok ? "계획 파일의 후보가 현재 DB에도 동일하게 존재합니다. 그래도 이 화면은 DB에서 삭제하지 않습니다." : "일부 후보가 현재 DB와 다르거나 삭제 대상이 아닙니다. 실제 삭제 전 계획을 다시 만드는 것이 안전합니다."}</p><div class="grid mini"><div class="metric"><span>계획 후보</span><b>${numberWithCommas(finalCheck.counts.plan)}</b></div><div class="metric"><span>삭제 가능 후보</span><b>${numberWithCommas(finalCheck.counts.deletable)}</b></div><div class="metric"><span>현재 없음</span><b>${numberWithCommas(finalCheck.counts.missing)}</b></div><div class="metric"><span>내용 차이</span><b>${numberWithCommas(finalCheck.counts.mismatch)}</b></div><div class="metric"><span>차단</span><b>${numberWithCommas(finalCheck.counts.blocked)}</b></div><div class="metric"><span>지출 되돌림 영향</span><b>${numberWithCommas(finalCheck.counts.expense)}원</b></div></div></section><section class="card"><h2>삭제 가능 후보</h2><p class="note">다음 실제 되돌리기 단계에서 대상이 될 수 있는 항목입니다. 이 화면에서는 삭제하지 않습니다.</p><div class="tableWrap"><table><thead><tr><th>ID</th><th>거래일</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>source</th><th>상태</th></tr></thead><tbody>${renderRollbackFinalRows(finalCheck.deletable)}</tbody></table></div></section><section class="card"><h2>삭제 제외/확인 필요</h2><p class="note">현재 없거나, source가 다르거나, 내용이 달라진 항목입니다.</p><div class="tableWrap"><table><thead><tr><th>ID</th><th>거래일</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>source</th><th>사유</th></tr></thead><tbody>${renderRollbackFinalRows([...finalCheck.missing, ...finalCheck.mismatch, ...finalCheck.blocked])}</tbody></table></div></section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>되돌리기 최종 확인</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1160px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#7f1d1d);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.warn{border-color:#fde68a;background:#fffbeb}.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:24px;margin-top:6px}.upload{display:grid;grid-template-columns:1fr 160px 170px 170px;gap:10px}.upload input,.upload select,.upload button{min-height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.upload input[type=file]{padding:10px}.upload button,.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.note{color:#64748b;line-height:1.55}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}.tableWrap{overflow-x:auto}table{width:100%;border-collapse:collapse;background:#fff;min-width:900px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}@media(max-width:840px){.wrap{padding:12px}.hero h1{font-size:24px}.upload{grid-template-columns:1fr}.card{overflow-x:auto}}</style></head><body>${renderUnifiedNav("backup", { month, householdId })}<main class="wrap"><section class="hero"><h1>되돌리기 최종 확인</h1><p>v10.9에서 만든 되돌리기 계획 JSON을 실제 삭제 전 다시 검증하고, 관리자 비밀번호를 재확인합니다. 이 단계도 DB에서 아무것도 삭제하지 않습니다.</p><p><a class="btn light" href="/backup/rollback-candidates">되돌리기 후보</a> <a class="btn light" href="/backup/import-history">가져오기 이력</a></p></section><section class="card"><h2>되돌리기 계획 파일 최종 확인</h2><p class="warnBox">계획 JSON과 관리자 비밀번호를 함께 확인합니다. 비밀번호가 맞아도 아직 Supabase에서 삭제하지 않습니다.</p><form class="upload" method="post" action="/backup/rollback-final-check" enctype="multipart/form-data"><input type="file" name="rollback_plan_file" accept="application/json,.json" required/><select name="household_id"><option value="">가계부 선택</option>${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month || currentMonthKst())}"/><input type="password" name="admin_password" placeholder="관리자 비밀번호" autocomplete="current-password" required/><button type="submit">최종 확인</button></form></section>${errorBox}${validationBox}${finalHtml}</main></body></html>`;
}

async function handleRollbackFinalCheckPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  return htmlResponse(renderRollbackFinalCheckHtml({ households, householdId, month }));
}

async function handleRollbackFinalCheckPost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  let households = [];
  try { households = await fetchAdminHouseholds(env); } catch (_) {}
  try {
    const form = await request.formData();
    const password = String(form.get("admin_password") || "").trim();
    const month = validMonth(form.get("month")) || currentMonthKst();
    const householdId = String(form.get("household_id") || "").trim();
    if (!(await checkAdminPassword(env, password))) {
      return htmlResponse(renderRollbackFinalCheckHtml({ households, month, householdId, error: "관리자 비밀번호 재확인에 실패했습니다." }), 401);
    }
    const file = form.get("rollback_plan_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderRollbackFinalCheckHtml({ households, month, householdId, error: "업로드된 되돌리기 계획 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 4 * 1024 * 1024) {
      return htmlResponse(renderRollbackFinalCheckHtml({ households, month, householdId, error: "파일이 너무 큽니다. 4MB 이하 되돌리기 계획 파일만 확인하세요." }), 400);
    }
    const plan = JSON.parse(raw);
    const validation = validateRollbackCandidatePlan(plan);
    if (!validation.ok) {
      return htmlResponse(renderRollbackFinalCheckHtml({ households, month, householdId, validation, error: "되돌리기 계획 파일 구조를 먼저 확인해야 합니다." }), 400);
    }
    const currentRows = await fetchTransactionsByIds(env, validation.rows.map((r) => r.id));
    const finalCheck = compareRollbackPlanToCurrent(validation.rows, currentRows);
    return htmlResponse(renderRollbackFinalCheckHtml({ households, month, householdId, validation, finalCheck }));
  } catch (err) {
    rememberOpsEvent({ kind: "rollback_final_check_failed", severity: "warn", path: "/rollback/final-check", method: "POST", detail: safeError(err) });
    return htmlResponse(renderRollbackFinalCheckHtml({ households, error: "되돌리기 최종 확인을 완료하지 못했습니다. 계획 파일을 다시 생성해 주세요." }), 400);
  }
}

