async function handleHouseholdCreateJoinGuidePage(request, env, url) {
  const userId = await verifyUserSession(request, env);
  const households = userId ? await fetchUserHouseholds(env, userId) : [];
  const rows = households.map((h) => {
    const readable = canReadMyHousehold(h.role);
    const invite = canManageMyHousehold(h.role) && h.invite_code ? `가계부 참여 ${h.invite_code}` : h.role === "pending" ? "승인 대기" : h.role === "blocked" ? "이용 제한" : "관리자만 확인";
    const action = readable ? `<a href="/app?household_id=${encodeURIComponent(h.id)}">열기</a>` : `<a href="/my?household_id=${encodeURIComponent(h.id)}">상태</a>`;
    return `<tr><td>${escapeHtml(h.name || "가계부")}</td><td>${escapeHtml(userHouseholdRoleLabel(h.role || "member"))}</td><td>${escapeHtml(invite)}</td><td>${action}</td></tr>`;
  }).join("") || `<tr><td colspan="4">로그인 후 /my/households에서 새 가계부를 만들거나 초대코드로 참여할 수 있습니다.</td></tr>`;
  const login = userId ? `<a class="btn" href="/my/households">내 가계부 전환·추가</a>` : `<a class="btn" href="/my">로그인하고 시작</a>`;
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${escapeHtml(appName(env))} · 가계부 생성·참여 가이드</title><style>body{margin:0;background:#f8fafc;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1040px;margin:0 auto;padding:16px}.hero,.card{background:#fff;border:1px solid #e5e7eb;border-radius:24px;padding:20px;margin:14px 0;box-shadow:0 14px 34px rgba(15,23,42,.055)}.hero{background:linear-gradient(135deg,#111827,#0f766e);color:#fff}.hero p{color:#ccfbf1;line-height:1.65}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:10px}.step{background:#fff;border:1px solid #e5e7eb;border-radius:20px;padding:16px}.step p{color:#64748b;line-height:1.55}.btn,.step a,td a{display:inline-flex;align-items:center;justify-content:center;min-height:38px;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 12px;margin:3px}.soft{background:#eef2f7!important;color:#111827!important}.tableWrap{overflow:auto}table{width:100%;border-collapse:collapse;min-width:720px}td,th{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left}.note{background:#ecfdf5;border:1px solid #a7f3d0;color:#065f46;border-radius:16px;padding:12px;line-height:1.55}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}}</style></head><body><main class="wrap"><section class="hero"><h1>가계부 생성·참여 흐름</h1><p>한 사용자가 여러 가계부를 만들거나 참여할 수 있습니다. 우리집 장부, 여행 장부, 모임비 장부를 나눠도 모든 조회는 내가 참여한 가계부 범위 안에서만 열립니다.</p><p>${login}<a class="btn soft" href="/households">참여자 관리</a></p></section><section class="grid"><div class="step"><h2>1. 새 가계부 만들기</h2><p>/my/households에서 이름을 입력하면 owner 권한의 새 가계부가 만들어집니다.</p><a href="/my/households">만들기</a></div><div class="step"><h2>2. 초대코드 공유</h2><p>선택 가계부의 “가계부 참여 코드” 문구를 가족/모임원에게 보냅니다.</p><a href="/my/households">초대코드 확인</a></div><div class="step"><h2>3. 다른 가계부 참여</h2><p>받은 초대코드를 /my/households 또는 /my 첫 화면에 입력해 참여합니다.</p><a href="/my/households">참여하기</a></div><div class="step"><h2>4. 권한 정리</h2><p>owner/admin은 참여자 화면에서 member/viewer/pending/blocked를 조정합니다.</p><a href="/households">권한 관리</a></div></section><section class="card"><h2>내 참여 가계부</h2><div class="tableWrap"><table><thead><tr><th>가계부</th><th>권한</th><th>초대 문구</th><th>진입</th></tr></thead><tbody>${rows}</tbody></table></div></section><section class="card"><h2>운영 원칙</h2><div class="note">새 가계부 생성과 초대코드 참여는 /my/create, /my/join 기존 안전 흐름을 사용합니다. viewer는 입력/수정/삭제가 제한되고, member는 자기 기록 중심, owner/admin은 전체 관리 기준을 유지합니다.</div></section></main></body></html>`);
}

