async function fetchPersistentNluMetrics(env = {}, hours = 168) {
  const cfg = nluOpsConfig(env);
  if (!cfg.aggregate_metrics_enabled) return [];
  const since = new Date(Date.now() - Math.max(1, Math.min(2160, Number(hours || 168))) * 3600000).toISOString();
  return optionalSupabase(env, `/rest/v1/nlu_intent_metrics_hourly?bucket_start=gte.${encodeURIComponent(since)}&select=bucket_start,intent,result,request_count,latency_sum_ms,latency_max_ms,version&order=bucket_start.desc&limit=5000`, { method: "GET" }, []);
}

async function fetchPersistentNluFailures(env = {}, days = 14, limit = 300) {
  const cfg = nluOpsConfig(env);
  if (!cfg.failure_samples_enabled) return [];
  const since = new Date(Date.now() - Math.max(1, Math.min(90, Number(days || 14))) * 86400000).toISOString();
  return optionalSupabase(env, `/rest/v1/nlu_failure_samples?last_seen=gte.${encodeURIComponent(since)}&select=sample_hash,redacted_sample,intent,result,reason,version,hit_count,first_seen,last_seen&order=hit_count.desc,last_seen.desc&limit=${Math.max(1, Math.min(1000, Number(limit || 300)))}`, { method: "GET" }, []);
}

function summarizePersistentNluMetrics(rows = []) {
  const totals = { total: 0, latency_sum_ms: 0, latency_max_ms: 0, by_result: {}, by_intent: {} };
  for (const row of safeArray(rows)) {
    const count = Math.max(0, Number(row.request_count || 0));
    totals.total += count;
    totals.latency_sum_ms += Math.max(0, Number(row.latency_sum_ms || 0));
    totals.latency_max_ms = Math.max(totals.latency_max_ms, Math.max(0, Number(row.latency_max_ms || 0)));
    const result = String(row.result || "unknown");
    const intent = String(row.intent || "UNKNOWN");
    totals.by_result[result] = (totals.by_result[result] || 0) + count;
    totals.by_intent[intent] = (totals.by_intent[intent] || 0) + count;
  }
  totals.avg_latency_ms = totals.total ? Math.round(totals.latency_sum_ms / totals.total) : 0;
  totals.success_rate = totals.total ? Math.round((Number(totals.by_result.ok || 0) / totals.total) * 10000) / 100 : 0;
  totals.fallback_rate = totals.total ? Math.round((Number(totals.by_result.fallback || 0) / totals.total) * 10000) / 100 : 0;
  totals.clarify_rate = totals.total ? Math.round((Number(totals.by_result.clarify || 0) / totals.total) * 10000) / 100 : 0;
  totals.error_rate = totals.total ? Math.round((Number(totals.by_result.error || 0) / totals.total) * 10000) / 100 : 0;
  return totals;
}

async function nluAdminAuthorized(request, env, url) {
  const adminOk = await verifyAdminSession(request, env);
  const keyOk = env.CRON_SECRET && url.searchParams.get("key") === env.CRON_SECRET;
  return !!(adminOk || keyOk);
}

async function handleNluOpsJson(request, env, url) {
  if (!(await nluAdminAuthorized(request, env, url))) return jsonResponse({ ok: false, error: "admin_required" }, 401);
  const hours = Math.max(1, Math.min(2160, Number(url.searchParams.get("hours") || 168)));
  const days = Math.max(1, Math.min(90, Number(url.searchParams.get("days") || 14)));
  const [metrics, failures] = await Promise.all([fetchPersistentNluMetrics(env, hours), fetchPersistentNluFailures(env, days, 300)]);
  return jsonResponse({
    ok: true,
    version: APP_VERSION,
    runtime: getNluOpsSnapshot(env),
    persistent: { enabled: nluOpsConfig(env), hours, days, summary: summarizePersistentNluMetrics(metrics), metrics, failures },
  });
}

async function handleNluFailuresCsv(request, env, url) {
  if (!(await nluAdminAuthorized(request, env, url))) return jsonResponse({ ok: false, error: "admin_required" }, 401);
  const days = Math.max(1, Math.min(90, Number(url.searchParams.get("days") || 14)));
  const rows = await fetchPersistentNluFailures(env, days, 1000);
  const lines = [["sample_hash", "redacted_sample", "intent", "result", "reason", "version", "hit_count", "first_seen", "last_seen"].map(csvCell).join(",")];
  for (const r of rows) lines.push([r.sample_hash, r.redacted_sample || "", r.intent, r.result, r.reason, r.version, r.hit_count, r.first_seen, r.last_seen].map(csvCell).join(","));
  return new Response("\ufeff" + lines.join("\n"), { status: 200, headers: { "content-type": "text/csv; charset=utf-8", "content-disposition": `attachment; filename="nlu-failures-${new Date().toISOString().slice(0,10)}.csv"`, "cache-control": "no-store", "x-content-type-options": "nosniff" } });
}

async function handleNluOpsPage(request, env, url) {
  if (!(await nluAdminAuthorized(request, env, url))) return redirectResponse("/admin-view");
  const hours = Math.max(1, Math.min(2160, Number(url.searchParams.get("hours") || 168)));
  const days = Math.max(1, Math.min(90, Number(url.searchParams.get("days") || 14)));
  const runtime = getNluOpsSnapshot(env);
  const [metricRows, failureRows] = await Promise.all([fetchPersistentNluMetrics(env, hours), fetchPersistentNluFailures(env, days, 200)]);
  const persistent = summarizePersistentNluMetrics(metricRows);
  const topIntents = Object.entries(persistent.total ? persistent.by_intent : runtime.by_intent).sort((a, b) => b[1] - a[1]).slice(0, 15).map(([intent, count]) => `<tr><td><b>${escapeHtml(intent)}</b></td><td>${numberWithCommas(count)}</td></tr>`).join("") || `<tr><td colspan="2">아직 집계가 없습니다.</td></tr>`;
  const recentProblems = runtime.recent.filter((e) => e.result !== "ok").slice(0, 60).map((e) => `<tr><td>${escapeHtml(String(e.at || "").replace("T", " ").slice(0,19))}</td><td><span class="pill ${escapeHtml(e.result)}">${escapeHtml(e.result)}</span></td><td>${escapeHtml(e.intent)}</td><td>${escapeHtml(e.sample || "-")}</td><td>${escapeHtml(e.reason || "")}</td><td>${numberWithCommas(e.latency_ms)}ms</td></tr>`).join("") || `<tr><td colspan="6">현재 Worker 인스턴스에서 최근 실패·확인 질문이 없습니다.</td></tr>`;
  const persistentProblems = failureRows.slice(0, 80).map((e) => `<tr><td>${escapeHtml(String(e.last_seen || "").replace("T", " ").slice(0,19))}</td><td><span class="pill ${escapeHtml(e.result || "")}">${escapeHtml(e.result || "")}</span></td><td>${escapeHtml(e.intent || "")}</td><td>${escapeHtml(e.redacted_sample || "텍스트 저장 비활성")}</td><td>${numberWithCommas(e.hit_count || 0)}</td><td>${escapeHtml(e.version || "")}</td></tr>`).join("") || `<tr><td colspan="6">영구 실패 샘플이 없거나 기능이 비활성입니다.</td></tr>`;
  const cfg = nluOpsConfig(env);
  const metricSource = persistent.total ? persistent : { total: runtime.total, success_rate: runtime.success_rate, fallback_rate: runtime.fallback_rate, clarify_rate: runtime.clarify_rate, error_rate: runtime.error_rate, avg_latency_ms: runtime.latency.p50, latency_max_ms: runtime.latency.max };
  const configRows = Object.entries(cfg).map(([k,v]) => `<tr><td><code>${escapeHtml(k)}</code></td><td>${escapeHtml(String(v))}</td></tr>`).join("");
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>NLU 운영·학습</title><style>*{box-sizing:border-box}body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1220px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#4f46e5);color:#fff;border-radius:28px;padding:24px;margin:14px 0;box-shadow:0 18px 44px rgba(15,23,42,.2)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.94}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:10px}.metric,.card{background:#fff;border:1px solid #e5e7eb;border-radius:20px;padding:16px;box-shadow:0 10px 28px rgba(15,23,42,.05)}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:25px;margin-top:6px}.card{margin:12px 0}.tableWrap{overflow:auto}table{width:100%;border-collapse:collapse;min-width:720px}th,td{padding:10px;border-bottom:1px solid #e5e7eb;text-align:left;font-size:13px;vertical-align:top}.pill{display:inline-flex;border-radius:999px;padding:5px 9px;background:#f1f5f9;font-weight:900}.fallback{background:#ffedd5;color:#9a3412}.clarify{background:#e0e7ff;color:#3730a3}.error{background:#fee2e2;color:#991b1b}.ok{background:#dcfce7;color:#166534}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:40px;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 12px;margin:3px}.btn.light{background:#eef2ff;color:#3730a3}.notice{background:#fffbeb;border:1px solid #fde68a;color:#854d0e;border-radius:16px;padding:13px;line-height:1.55}code{background:#f1f5f9;border-radius:8px;padding:3px 6px}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}}</style></head><body>${renderUnifiedNav("operation-center", { showOps: true })}<main class="wrap"><section class="hero"><h1>자연어 운영·학습 센터</h1><p>실패 발화, 확인 질문, 의도별 성공률과 응답시간을 확인해 실제 사용자 표현을 안전하게 개선합니다.</p><p><a class="btn light" href="/nlu-ops.json?hours=${hours}&days=${days}">JSON 보기</a><a class="btn light" href="/nlu-failures.csv?days=${days}">실패 샘플 CSV</a><a class="btn light" href="/nlu-intents.json">Intent 목록</a><a class="btn light" href="/operation-center">운영센터</a></p></section><section class="grid"><div class="metric"><span>집계 요청</span><b>${numberWithCommas(metricSource.total || 0)}</b></div><div class="metric"><span>성공률</span><b>${numberWithCommas(metricSource.success_rate || 0)}%</b></div><div class="metric"><span>폴백률</span><b>${numberWithCommas(metricSource.fallback_rate || 0)}%</b></div><div class="metric"><span>확인질문률</span><b>${numberWithCommas(metricSource.clarify_rate || 0)}%</b></div><div class="metric"><span>오류율</span><b>${numberWithCommas(metricSource.error_rate || 0)}%</b></div><div class="metric"><span>지연</span><b>${numberWithCommas(persistent.total ? persistent.avg_latency_ms : runtime.latency.p95)}ms</b></div></section><section class="card"><h2>집계 설정</h2><div class="tableWrap"><table><tbody>${configRows}</tbody></table></div><p class="notice">기본값은 DB 영구 로그 비활성입니다. 선택 SQL 적용 후 NLU_METRICS_ENABLED=1로 집계만 켜고, 실패 문장 수집은 개인정보 검토 후 별도로 켜세요.</p></section><section class="card"><h2>상위 의도</h2><div class="tableWrap"><table><thead><tr><th>의도</th><th>건수</th></tr></thead><tbody>${topIntents}</tbody></table></div></section><section class="card"><h2>현재 인스턴스의 최근 확인·실패</h2><div class="tableWrap"><table><thead><tr><th>시간</th><th>결과</th><th>의도</th><th>비식별 샘플</th><th>사유</th><th>지연</th></tr></thead><tbody>${recentProblems}</tbody></table></div></section><section class="card"><h2>영구 실패 샘플 · 최근 ${days}일</h2><div class="tableWrap"><table><thead><tr><th>최근</th><th>결과</th><th>의도</th><th>비식별 문장</th><th>반복</th><th>버전</th></tr></thead><tbody>${persistentProblems}</tbody></table></div></section><section class="notice"><b>개선 순서</b><br/>반복 샘플 확인 → 기존 의도 누락인지 판단 → 사전·규칙·되묻기 보강 → 평가 데이터셋 추가 → 전체 회귀시험 → 점진 배포. 실패 문장을 OpenBuilder 블록에 무조건 학습시키지 않습니다.</section></main></body></html>`);
}

async function handleSkillOpsPage(request, env, url) {
  const adminOk = await verifyAdminSession(request, env);
  const keyOk = env.CRON_SECRET && url.searchParams.get("key") === env.CRON_SECRET;
  if (!adminOk && !keyOk) return redirectResponse("/admin-view");
  const title = escapeHtml(appName(env));
  const snap = getSkillOpsSnapshot();
  const rows = snap.recent.map((e) => `<tr><td>${escapeHtml(e.at)}</td><td><span class="kind ${escapeHtml(e.kind)}">${escapeHtml(e.kind)}</span></td><td>${escapeHtml(maskKey(e.user_key || ""))}</td><td>${escapeHtml(e.utterance || "")}</td><td>${escapeHtml(e.detail || "")}</td></tr>`).join("") || `<tr><td colspan="5">아직 이벤트가 없습니다.</td></tr>`;
  const kindRows = Object.entries(snap.byKind || {}).map(([k, v]) => `<span>${escapeHtml(k)} ${numberWithCommas(v)}건</span>`).join("");
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 스킬 운영상태</title><style>body{margin:0;background:#f8fafc;color:#101828;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1160px;margin:0 auto;padding:16px}.hero,.card{background:#fff;border:1px solid #e8edf4;border-radius:24px;padding:20px;margin:14px 0;box-shadow:0 14px 34px rgba(15,23,42,.055)}.hero{background:linear-gradient(135deg,#111827,#7c3aed);color:#fff}.hero p{color:#e9d5ff}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:10px}.box{background:#f8fafc;border:1px solid #e8edf4;border-radius:18px;padding:14px}.box b{display:block;font-size:24px}table{width:100%;border-collapse:collapse;background:#fff}td,th{border-bottom:1px solid #e8edf4;padding:10px;text-align:left;font-size:13px}.chips{display:flex;gap:8px;flex-wrap:wrap}.chips span{background:#eef2ff;color:#3730a3;border:1px solid #c7d2fe;border-radius:999px;padding:8px 11px;font-weight:900;font-size:12px}.kind{border-radius:999px;padding:5px 9px;background:#f1f5f9;font-weight:900}.rate_limited{background:#ffedd5;color:#9a3412}.error,.bad_json{background:#fee2e2;color:#991b1b}.ok{background:#dcfce7;color:#166534}.muted{color:#667085;line-height:1.6}.scroll{overflow:auto;border:1px solid #e8edf4;border-radius:18px}</style></head><body><main class="wrap"><section class="hero"><h1>카카오 스킬 운영상태</h1><p>이 화면은 현재 Worker 인스턴스의 최근 /skill 이벤트와 과도 요청 제한 상태를 보여줍니다.</p></section><section class="grid"><div class="box"><span>활성 요청 버킷</span><b>${numberWithCommas(snap.activeBuckets)}</b></div><div class="box"><span>최근 이벤트</span><b>${numberWithCommas(snap.recent.length)}</b></div><div class="box"><span>기본 제한</span><b>${numberWithCommas(boundedRuntimeNumber(env.SKILL_RATE_LIMIT, 60, 10, 10000))}/분</b></div></section><section class="card"><h2>이벤트 요약</h2><div class="chips">${kindRows || "<span>이벤트 없음</span>"}</div><p class="muted">Cloudflare Worker 메모리 기반 임시 로그라 인스턴스 재시작 시 초기화됩니다. 장기 로그가 필요하면 별도 DB 로그 테이블을 추가하세요.</p></section><section class="card"><h2>최근 이벤트</h2><div class="scroll"><table><thead><tr><th>시간</th><th>종류</th><th>사용자키</th><th>발화</th><th>상세</th></tr></thead><tbody>${rows}</tbody></table></div></section></main></body></html>`);
}

