async function handleRecurringCandidateConfirm(request, env) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const form = await request.formData();
  const householdId = String(form.get("household_id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const returnTo = `/smart-tools?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}`;
  const { selected } = await getMySelectedHousehold(env, userId, householdId);
  if (!selected || String(selected.id) !== householdId) return redirectResponse("/my?err=no_household");
  if (!canManageMyHousehold(selected.role)) return redirectResponse(`${returnTo}&err=manage_required`);
  if (String(form.get("confirmed") || "") !== "yes") return redirectResponse(`${returnTo}&err=confirmation_required`);
  const memo = String(form.get("memo") || "").trim().slice(0, 120);
  const amount = Math.max(0, Math.min(2_000_000_000, Math.round(parseAmountValue(form.get("amount") || "0"))));
  if (!memo || !amount) return redirectResponse(`${returnTo}&err=recurring_missing`);
  const row = {
    household_id: selected.id,
    type: "expense",
    amount,
    category: String(form.get("category") || "정기지출").trim().slice(0, 80) || "정기지출",
    memo,
    payment_method: String(form.get("payment_method") || "").trim().slice(0, 80),
    day_of_month: Math.min(28, Math.max(1, Number(form.get("day_of_month") || 1))),
    user_id: userId,
    is_active: true,
  };
  try {
    const existing = await fetchRecurring(env, selected.id);
    const key = normalizeRecurringKey(row);
    if (safeArray(existing).some((item) => normalizeRecurringKey(item) === key)) return redirectResponse(`${returnTo}&msg=recurring_exists`);
    await supabase(env, "/rest/v1/accountbook_recurring", {
      method: "POST",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify(row),
    });
    return redirectResponse(`${returnTo}&msg=recurring_registered`);
  } catch (err) {
    rememberOpsEvent({ kind: "recurring_candidate_confirm_failed", severity: "warn", path: "/my/recurring/from-candidate", method: "POST", detail: safeError(err) });
    return redirectResponse(`${returnTo}&err=recurring_save_failed`);
  }
}

function renderMySettingsHtml({ env, url, user, month, households, selected, rows = [], budgets, budget, keywordMap, customCategories, recurring, msg = "", err = "" }) {
  const title = escapeHtml(appName(env));
  const hh = `household_id=${encodeURIComponent(selected.id)}&month=${encodeURIComponent(month)}`;
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === selected.id ? "selected" : ""}>${escapeHtml(h.name)} · ${escapeHtml(h.role)}</option>`).join("");
  const incomeRows = incomeBudgetRows(budgets).filter((r) => Number(r.amount || 0) > 0);
  while (incomeRows.length < 2) incomeRows.push({ name: defaultIncomeBudgetNames()[incomeRows.length] || "기타수입", amount: 0 });
  const expenseAllRows = expenseBudgetRows(budgets, customCategories);
  const expenseSetRows = expenseAllRows.filter((r) => Number(r.amount || 0) > 0);
  const starterNames = ["식비", "교통", "생활용품", "보험", "카페/간식"];
  const budgetEditRows = expenseSetRows.length ? expenseSetRows : starterNames.map((name) => ({ name, amount: 0 }));
  const incomePlanTotal = sumBudgetAmounts(incomeRows);
  const expensePlanTotal = sumBudgetAmounts(expenseSetRows);
  const budgetCenter = budgetCenterSummary(rows, budgets);
  const actualIncomeList = budgetCenter.actualIncomeCategories.length
    ? budgetCenter.actualIncomeCategories.map((item) => `<li><span>${escapeHtml(item.category)}</span><b>${numberWithCommas(item.amount)}원</b><small>${numberWithCommas(item.count)}건</small></li>`).join("")
    : `<li class="emptyIncome">아직 이번 달 수입 기록이 없습니다.</li>`;
  const recurringInfo = recurringSummary(recurring);
  const spentMap = categorySpentMap(rows);
  const categoryRows = defaultExpenseBudgetNames(customCategories);
  const categoryOptions = [`<option value="">직접입력</option>`, ...categoryRows.map((c) => `<option value="${escapeHtml(c)}">${escapeHtml(c)}</option>`)].join("");
  const incomeOptions = [`<option value="">직접입력</option>`, ...defaultIncomeBudgetNames().map((c) => `<option value="${escapeHtml(c)}">${escapeHtml(c)}</option>`)].join("");
  const keywordEditor = renderKeywordBulkEditor({ selected, month, keywordMap, customCategories, compact: true });
  const recurringRows = safeArray(recurring).length ? safeArray(recurring).map((r) => `<tr><td>${escapeHtml(r.memo || "")}</td><td>${escapeHtml(r.type === "income" ? "수입" : "지출")}</td><td>${numberWithCommas(r.amount)}원</td><td>${escapeHtml(r.category || "")}</td><td>매월 ${escapeHtml(r.day_of_month || 1)}일</td><td>${escapeHtml(r.last_applied_month || "-")}</td><td><form method="post" action="/my/recurring/delete" onsubmit="return confirm('삭제할까요?')"><input type="hidden" name="household_id" value="${escapeHtml(selected.id)}"/><input type="hidden" name="month" value="${escapeHtml(month)}"/><input type="hidden" name="id" value="${escapeHtml(r.id || "")}"/><button class="danger" type="submit">삭제</button></form></td></tr>`).join("") : `<tr><td colspan="7">아직 정기지출이 없습니다.</td></tr>`;
  const incomeInputs = incomeRows.slice(0, 8).map((r) => `<div class="budgetLine incomeLine"><input name="income_name" value="${escapeHtml(r.name)}" placeholder="직접입력: 수입 종류"/><select class="pickValue">${incomeOptions}</select><input name="income_amount" value="${Number(r.amount || 0) || ""}" inputmode="numeric" placeholder="예상 수입"/></div>`).join("");
  const expenseInputs = budgetEditRows.slice(0, 12).map((r) => `<div class="budgetLine expenseLine"><input name="budget_category" value="${escapeHtml(r.name)}" placeholder="직접입력: 예산 분류"/><select class="pickValue">${categoryOptions}</select><input name="budget_amount" value="${Number(r.amount || 0) || ""}" inputmode="numeric" placeholder="예산 금액"/></div>`).join("");
  const budgetListRows = expenseSetRows.length ? expenseSetRows.map((r) => {
    const spent = Number(spentMap[r.name] || 0);
    const remain = Math.max(0, Number(r.amount || 0) - spent);
    const rate = Number(r.amount || 0) ? Math.round(spent / Number(r.amount || 0) * 100) : 0;
    return `<tr><td><b>${escapeHtml(r.name)}</b></td><td>${numberWithCommas(r.amount)}원</td><td>${numberWithCommas(spent)}원</td><td>${numberWithCommas(remain)}원</td><td>${rate}%</td></tr>`;
  }).join("") : `<tr><td colspan="5">아직 저장된 분류별 예산이 없습니다. 필요한 분류만 추가해서 저장하세요.</td></tr>`;
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 설정</title><style>${myNavCss()}*,*:before,*:after{box-sizing:border-box}html,body{max-width:100%;overflow-x:hidden}body{margin:0;background:linear-gradient(180deg,#fff9d9,#f8fafc 50%,#eef2f7);font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif;color:#101828;letter-spacing:-.025em}.wrap{max-width:1240px;margin:0 auto;padding:16px 16px 120px}.hero,.card{background:#fff;border:1px solid #e8edf4;border-radius:24px;padding:20px;margin:14px 0;box-shadow:0 12px 30px rgba(15,23,42,.06)}.hero p,.muted{color:#667085;line-height:1.55;font-size:13px}.summaryGrid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.summaryBox{background:#f8fafc;border:1px solid #e8edf4;border-radius:18px;padding:14px;min-width:0}.summaryBox b{display:block;font-size:22px;overflow-wrap:anywhere}.toolbar{display:flex;gap:8px;flex-wrap:wrap;align-items:center}.rowform{display:grid;grid-template-columns:100px 1fr 150px 150px 150px 100px auto;gap:8px;align-items:center}.rowform input,.rowform select{min-width:0;width:100%}.budgetForm{display:grid;grid-template-columns:1fr 1fr;gap:14px}.budgetLine{display:grid;grid-template-columns:1.2fr .9fr 150px;gap:8px;margin:8px 0}.budgetLine>*{min-width:0}.incomeSummary{list-style:none;padding:0;margin:10px 0;display:grid;gap:7px}.incomeSummary li{display:grid;grid-template-columns:minmax(0,1fr) auto auto;gap:8px;align-items:center;border:1px solid #e8edf4;border-radius:13px;padding:10px 12px}.incomeSummary li span{font-weight:900}.incomeSummary li small{color:#667085}.incomeSummary .emptyIncome{display:block;color:#667085;background:#f8fafc}input,select{border:1px solid #cbd5e1;border-radius:14px;padding:11px;font:inherit;background:#fff}button,.btn{display:inline-flex;align-items:center;justify-content:center;border:0;border-radius:14px;background:#111827;color:#fff!important;padding:11px 14px;text-decoration:none;font-weight:1000;cursor:pointer}.secondary{background:#eef2f7!important;color:#111827!important;border:1px solid #d8dee8}.danger{background:#ef4444!important}.ok{background:#ecfdf5;color:#166534;border:1px solid #bbf7d0;border-radius:14px;padding:11px}.error{background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;border-radius:14px;padding:11px}table{width:100%;border-collapse:collapse;background:#fff}td,th{border-bottom:1px solid #e8edf4;padding:10px;text-align:left;font-size:13px}.scroll{overflow:auto;border:1px solid #e8edf4;border-radius:18px}details.fold{border:1px solid #e8edf4;border-radius:22px;background:#fff;padding:6px 14px}details.fold summary{cursor:pointer;font-weight:1000;padding:12px 4px}.sectionNote{background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;border-radius:16px;padding:12px;font-size:13px;line-height:1.55}.keywordGrid{display:grid;grid-template-columns:1fr 1fr;gap:10px}.keywordCard{display:grid;grid-template-columns:110px 1fr auto;gap:8px;align-items:center;border:1px solid #e8edf4;border-radius:16px;padding:10px;background:#f8fafc}.keywordCard label{font-weight:1000}.addBtn{background:#eef2ff!important;color:#3730a3!important;border:1px solid #c7d2fe}@media(max-width:900px){.budgetForm,.keywordGrid{grid-template-columns:1fr}.budgetLine,.keywordCard,.rowform{grid-template-columns:1fr}.toolbar>*{width:100%}}@media(max-width:600px){.wrap{padding:10px 10px 126px}.hero,.card{padding:16px;border-radius:19px}.summaryGrid{grid-template-columns:1fr 1fr}.summaryBox b{font-size:19px}.incomeSummary li{grid-template-columns:1fr auto}.incomeSummary li small{grid-column:1/-1}.budgetLine input,.budgetLine select{width:100%;font-size:16px}}@media(max-width:360px){.summaryGrid{grid-template-columns:1fr}}</style></head><body><main class="wrap"><div class="appLayout">${renderMySideNav(selected, selected.role, month, "settings")}<div class="pageMain"><section class="hero"><h1>수입·예산 설정</h1><p>실제 수입은 기록에서 자동 합산하고, 예상 수입과 지출 한도는 종류·분류별 행의 합계로 계산합니다.</p></section>${msg ? `<div class="ok">${formatMessage(msg)}</div>` : ""}${err ? `<div class="error">${formatMessage(err)}</div>` : ""}<section class="card"><form method="get" action="/my/settings" class="toolbar"><select name="household_id">${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month)}"/><button type="submit">조회</button><a class="btn secondary" href="/app?${hh}">홈</a></form></section><section class="card"><h2>이번 달 요약</h2><div class="summaryGrid"><div class="summaryBox"><span class="muted">실제 수입 · 기록 자동합계</span><b>${numberWithCommas(budgetCenter.actualIncome)}원</b></div><div class="summaryBox"><span class="muted">예상 수입 · 종류별 합계</span><b>${numberWithCommas(incomePlanTotal)}원</b></div><div class="summaryBox"><span class="muted">지출 예산 · 분류별 합계</span><b>${numberWithCommas(expensePlanTotal)}원</b></div><div class="summaryBox"><span class="muted">이번 달 지출</span><b>${numberWithCommas(budget.expense || 0)}원</b><span class="muted">예산 사용 ${budget.rate || 0}%</span></div></div><h3>실제 수입 분류</h3><ul class="incomeSummary">${actualIncomeList}</ul></section><section class="card"><h2>예상 수입 + 지출 예산</h2><p class="muted">월 총액을 따로 입력하지 않습니다. 수입 종류와 지출 분류별 금액을 입력하면 위 합계가 자동으로 만들어집니다. 빈 행과 0원 행은 저장하지 않습니다.</p><form method="post" action="/my/budget-bulk/save" id="budgetBulkForm"><input type="hidden" name="household_id" value="${escapeHtml(selected.id)}"/><input type="hidden" name="month" value="${escapeHtml(month)}"/><div class="budgetForm"><div><h3>예상 수입 종류</h3><div id="incomeRows">${incomeInputs}</div><p><button type="button" class="addBtn" data-add="income">+ 수입 종류 추가</button></p><div class="sectionNote">급여·부수입을 고르거나 왼쪽 칸에 직접 이름을 입력하세요. 입력한 행의 합계가 예상 수입입니다.</div></div><div><h3>지출 분류별 한도</h3><div id="expenseRows">${expenseInputs}</div><p><button type="button" class="addBtn" data-add="expense">+ 지출 분류 추가</button></p><div class="sectionNote">식비·교통 등 필요한 분류만 입력하세요. 분류별 합계가 이번 달 전체 지출 예산입니다.</div></div></div><p><button type="submit">종류별 수입·분류별 예산 저장</button></p></form></section><section class="card"><h2>저장된 분류별 지출 예산</h2><p class="muted">분류별 합계: <b>${numberWithCommas(expensePlanTotal)}원</b></p><div class="scroll"><table><thead><tr><th>분류</th><th>예산</th><th>사용</th><th>남음</th><th>사용률</th></tr></thead><tbody>${budgetListRows}</tbody></table></div></section><section class="card"><h2>정기 수입·지출 자동 기록</h2><div class="summaryGrid"><div class="summaryBox"><span class="muted">정기지출 합계</span><b>${numberWithCommas(recurringInfo.expense)}원</b></div><div class="summaryBox"><span class="muted">정기수입 합계</span><b>${numberWithCommas(recurringInfo.income)}원</b></div><div class="summaryBox"><span class="muted">월 순정기액</span><b>${numberWithCommas(recurringInfo.net)}원</b></div><div class="summaryBox"><span class="muted">등록 건수</span><b>${numberWithCommas(recurringInfo.count)}건</b></div></div><form method="post" action="/my/recurring/save" class="rowform"><input type="hidden" name="household_id" value="${escapeHtml(selected.id)}"/><input type="hidden" name="month" value="${escapeHtml(month)}"/><select name="type"><option value="expense">지출</option><option value="income">수입</option></select><input name="memo" placeholder="예: 자동차보험" required/><input name="amount" placeholder="금액" required/><input name="category" placeholder="분류" value="정기지출"/><input name="payment_method" placeholder="결제수단"/><input name="day_of_month" type="number" min="1" max="31" value="1"/><button type="submit">정기항목 저장</button></form><div class="scroll" style="margin-top:14px"><table><thead><tr><th>내용</th><th>구분</th><th>금액</th><th>분류</th><th>일자</th><th>최근 적용월</th><th></th></tr></thead><tbody>${recurringRows}</tbody></table></div></section><section class="card"><h2>키워드 안내·설정</h2><p class="muted">가족이 실제로 쓰는 표현을 수입·지출 분류에 연결하세요.</p>${keywordEditor}</section></div></div></main><script>
(function(){
  const incomeOptions = ${JSON.stringify(incomeOptions)};
  const categoryOptions = ${JSON.stringify(categoryOptions)};
  function bindPickers(root){
    root.querySelectorAll('.pickValue').forEach(function(sel){
      sel.addEventListener('change', function(){
        const line = sel.closest('.budgetLine');
        const input = line && line.querySelector('input');
        if (input && sel.value) input.value = sel.value;
      });
    });
  }
  function makeLine(type){
    const div = document.createElement('div');
    div.className = 'budgetLine ' + (type === 'income' ? 'incomeLine' : 'expenseLine');
    if (type === 'income') {
      div.innerHTML = '<input name="income_name" placeholder="직접입력: 수입 종류"/><select class="pickValue">' + incomeOptions + '</select><input name="income_amount" inputmode="numeric" placeholder="예상 수입"/>';
    } else {
      div.innerHTML = '<input name="budget_category" placeholder="직접입력: 예산 분류"/><select class="pickValue">' + categoryOptions + '</select><input name="budget_amount" inputmode="numeric" placeholder="예산 금액"/>';
    }
    bindPickers(div);
    return div;
  }
  document.querySelectorAll('[data-add]').forEach(function(btn){
    btn.addEventListener('click', function(){
      const type = btn.getAttribute('data-add');
      document.getElementById(type === 'income' ? 'incomeRows' : 'expenseRows').appendChild(makeLine(type));
    });
  });
  bindPickers(document);
})();
</script></body></html>`;
}
function myReturnLocation(month = currentMonthKst(), householdId = "", extra = {}) {
  const qs = new URLSearchParams();
  qs.set("month", validMonth(month) || currentMonthKst());
  if (householdId) qs.set("household_id", householdId);
  for (const [k, v] of Object.entries(extra || {})) if (v !== undefined && v !== null && String(v) !== "") qs.set(k, String(v));
  return `/my?${qs.toString()}#records`;
}

function canWriteMyHousehold(role = "") {
  const r = String(role || "").toLowerCase();
  return ["owner", "admin", "member"].includes(r);
}

function canReadMyHousehold(role = "") {
  return ["owner", "admin", "member", "viewer"].includes(String(role || "").toLowerCase());
}

function canManageMyHousehold(role = "") {
  return ["owner", "admin"].includes(String(role || "").toLowerCase());
}

function householdAccessTitle(role = "") {
  if (role === "pending") return "참여 승인 대기 중";
  if (role === "blocked") return "이 가계부의 이용이 제한됨";
  return "이 화면은 관리자 전용";
}

function renderMyAccessStatusHtml({ env, user = null, household = null, role = "", month = currentMonthKst(), manageOnly = false }) {
  const normalizedRole = String(role || household?.role || "").toLowerCase();
  const title = manageOnly && canReadMyHousehold(normalizedRole) ? "관리자 권한이 필요한 화면" : householdAccessTitle(normalizedRole);
  let guide = "가계부 목록에서 이용 가능한 가계부를 선택하거나 새 가계부를 만들어 주세요.";
  let steps = ["가계부 전환·추가 화면으로 이동", "이용 가능한 가계부 선택", "문제가 계속되면 가계부 관리자에게 권한 확인 요청"];
  if (normalizedRole === "pending") {
    guide = "참여 요청은 정상 접수됐습니다. 같은 코드를 반복 입력해도 승인이 빨라지지 않으며, 관리자가 승인하면 기록과 조회가 열립니다.";
    steps = ["가계부 관리자에게 참여 승인 요청", "승인 전에는 다른 이용 가능한 가계부 사용", "승인 후 가계부 목록에서 다시 열기"];
  } else if (normalizedRole === "blocked") {
    guide = "초대코드를 다시 입력해도 제한은 해제되지 않습니다. 가계부 관리자만 권한을 변경할 수 있습니다.";
    steps = ["가계부 관리자에게 제한 사유와 권한 확인 요청", "다른 이용 가능한 가계부로 전환", "필요하면 별도의 새 가계부 생성"];
  } else if (manageOnly) {
    guide = "참여자·초대 및 단톡방 연결 정보는 소유자 또는 관리자만 볼 수 있습니다. 현재 권한으로는 기록 조회 화면을 계속 사용할 수 있습니다.";
    steps = ["내 가계부로 돌아가기", "관리 작업이 필요하면 소유자에게 관리자 권한 요청", "조회 전용 사용자는 기록을 변경하지 않고 조회만 이용"];
  }
  const householdName = household?.name || "선택한 가계부";
  const list = steps.map((step, index) => `<li><b>${index + 1}</b><span>${escapeHtml(step)}</span></li>`).join("");
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><meta name="robots" content="noindex,nofollow"/><title>${escapeHtml(appName(env))} · ${escapeHtml(title)}</title><style>*,*:before,*:after{box-sizing:border-box}body{margin:0;background:linear-gradient(180deg,#fff7ed,#f8fafc 50%);color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:760px;margin:0 auto;padding:18px}.card{background:#fff;border:1px solid #e5e7eb;border-radius:28px;padding:24px;margin:14px 0;box-shadow:0 18px 44px rgba(15,23,42,.08)}.badge{display:inline-flex;border-radius:999px;background:#fff7ed;color:#9a3412;border:1px solid #fed7aa;padding:6px 10px;font-size:12px;font-weight:1000}h1{font-size:28px;margin:14px 0 8px}.sub{color:#64748b;line-height:1.65}.guide{background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;border-radius:18px;padding:14px;line-height:1.65}ol{list-style:none;padding:0;margin:18px 0;display:grid;gap:10px}li{display:grid;grid-template-columns:34px 1fr;gap:10px;align-items:center;border:1px solid #e5e7eb;border-radius:16px;padding:11px}li b{display:grid;place-items:center;width:30px;height:30px;border-radius:50%;background:#111827;color:#fff}.actions{display:flex;gap:8px;flex-wrap:wrap}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:44px;border-radius:14px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 14px}.soft{background:#eef2f7;color:#111827}@media(max-width:620px){.wrap{padding:12px}.card{padding:19px;border-radius:22px}h1{font-size:24px}.actions,.btn{width:100%}}</style></head><body><main class="wrap"><section class="card"><span class="badge">${escapeHtml(userHouseholdRoleLabel(normalizedRole || "member"))}</span><h1>${escapeHtml(title)}</h1><p class="sub"><b>${escapeHtml(householdName)}</b><br/>${escapeHtml(user?.nickname || "사용자")}님의 현재 권한을 기준으로 안전하게 접근을 제한했습니다.</p><div class="guide">${escapeHtml(guide)}</div><ol>${list}</ol><div class="actions"><a class="btn" href="/my/households">가계부 전환·추가</a>${canReadMyHousehold(normalizedRole) ? `<a class="btn soft" href="/app?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(household?.id || "")}">내 가계부</a>` : `<a class="btn soft" href="/my">처음 화면</a>`}</div></section></main></body></html>`;
}

function myAccessStatusResponse(args = {}, status = 403) {
  return htmlResponse(renderMyAccessStatusHtml(args), status);
}

function canManageMyRecord(role = "", row = {}, userId = "") {
  const r = String(role || "").toLowerCase();
  if (["owner", "admin"].includes(r)) return true;
  return canWriteMyHousehold(r) && String(row.user_id || "") === String(userId || "");
}

async function getMySelectedHousehold(env, userId, householdId = "") {
  const memberships = await fetchUserHouseholds(env, userId);
  const households = memberships.filter((h) => canReadMyHousehold(h.role));
  if (!memberships.length) return { households, memberships, selected: null, restricted: null };
  const requested = householdId ? memberships.find((h) => String(h.id) === String(householdId)) || null : null;
  if (requested && !canReadMyHousehold(requested.role)) return { households, memberships, selected: null, restricted: requested };
  if (!households.length) return { households, memberships, selected: null, restricted: requested || memberships[0] || null };
  const selected = (requested && canReadMyHousehold(requested.role) ? requested : null) || households[0] || null;
  return { households, memberships, selected, restricted: null };
}


function transactionEditHistoryKey(householdId = "") {
  return `transaction_edit_history:${String(householdId || "default").trim() || "default"}`;
}

async function fetchTransactionEditHistoryMap(env, householdId = "") {
  try {
    const value = await getSettingValue(env, transactionEditHistoryKey(householdId));
    if (!value) return {};
    const parsed = typeof value === "string" ? JSON.parse(value || "{}") : value;
    const out = {};
    for (const [id, list] of Object.entries(safeObject(parsed))) {
      if (id && Array.isArray(list)) out[id] = list.slice(-20);
    }
    return out;
  } catch (err) {
    return {};
  }
}

function transactionAuditFields() {
  return [
    ["user_id", "지출자"],
    ["type", "구분"],
    ["transaction_date", "날짜"],
    ["amount", "금액"],
    ["memo", "내용"],
    ["category", "분류"],
    ["payment_method", "결제수단"],
  ];
}

function valueForAudit(row = {}, key = "", memberMap = {}) {
  if (key === "user_id") return memberMap[String(row.user_id || "")] || row.user_id || "미지정";
  if (key === "type") return row.type === "income" ? "수입" : "지출";
  if (key === "amount") return `${Number(row.amount || 0).toLocaleString("ko-KR")}원`;
  return String(row[key] ?? "");
}

function buildTransactionChanges(before = {}, after = {}, memberMap = {}) {
  const changes = [];
  for (const [key, label] of transactionAuditFields()) {
    const bRaw = key === "amount" ? Math.round(Number(before[key] || 0)) : String(before[key] ?? "");
    const aRaw = key === "amount" ? Math.round(Number(after[key] || 0)) : String(after[key] ?? "");
    if (String(bRaw) === String(aRaw)) continue;
    changes.push({ field: key, label, before: valueForAudit(before, key, memberMap), after: valueForAudit(after, key, memberMap) });
  }
  return changes;
}

async function appendTransactionEditHistory(env, householdId = "", transactionId = "", before = {}, after = {}, editedBy = "", members = []) {
  if (!householdId || !transactionId) return [];
  const memberMap = memberNameMap(members || []);
  const changes = buildTransactionChanges(before, after, memberMap);
  if (!changes.length) return [];
  const map = await fetchTransactionEditHistoryMap(env, householdId);
  const list = Array.isArray(map[transactionId]) ? map[transactionId] : [];
  list.push({ at: new Date().toISOString(), edited_by: editedBy || "", edited_by_name: memberMap[String(editedBy || "")] || "", changes });
  map[transactionId] = list.slice(-20);
  await supabase(env, "/rest/v1/accountbook_settings?on_conflict=key", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify({ key: transactionEditHistoryKey(householdId), value: JSON.stringify(map) }),
  });
  return map[transactionId];
}

function memberExists(members = [], userId = "") {
  return safeArray(members).some((m) => String(m.user_id || "") === String(userId || ""));
}

function canManageAllRecords(role = "") {
  return ["owner", "admin"].includes(String(role || ""));
}

async function getTransactionForUserEdit(env, id, householdId) {
  if (!id || !householdId) return null;
  const params = new URLSearchParams();
  params.set("select", "id,household_id,user_id,type,amount,category,memo,payment_method,transaction_date,source,raw_text,created_at");
  params.set("id", `eq.${id}`);
  params.set("household_id", `eq.${householdId}`);
  params.set("limit", "1");
  const rows = await supabase(env, `/rest/v1/transactions?${params.toString()}`, { method: "GET" }) || [];
  return rows[0] || null;
}

function parseMyAmount(form) {
  const amount = Math.round(Number(String(form.get("amount") || "0").replace(/,/g, "")));
  return Number.isFinite(amount) ? amount : 0;
}

async function handleMyAddTransaction(request, env) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const form = await request.formData();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const householdId = String(form.get("household_id") || "").trim();
  const { selected } = await getMySelectedHousehold(env, userId, householdId);
  if (!selected) return redirectResponse("/my?err=no_household");
  if (!canWriteMyHousehold(selected.role)) return redirectResponse(myReturnLocation(month, selected.id, { err: "write_not_allowed" }));
  const type = normalizeTransactionType(String(form.get("type") || "expense"));
  const transactionDate = String(form.get("transaction_date") || formatDate(nowKstDate())).trim();
  const amount = parseMyAmount(form);
  if (!amount || amount <= 0) return redirectResponse(myReturnLocation(month, selected.id, { err: "amount_required" }));
  if (!isValidTransactionDateString(transactionDate)) return redirectResponse(myReturnLocation(month, selected.id, { err: "invalid_date" }));
  const members = await fetchHouseholdMembers(env, selected.id);
  const requestedUserId = String(form.get("user_id") || "").trim();
  if (requestedUserId && !memberExists(members, requestedUserId)) return redirectResponse(myReturnLocation(month, selected.id, { err: "spender_not_member" }));
  const spenderUserId = canManageAllRecords(selected.role) && requestedUserId && memberExists(members, requestedUserId) ? requestedUserId : userId;
  const rawText = String(form.get("raw_text") || "").trim();
  const memoText = String(form.get("memo") || "").trim();
  const manualClass = await resolveManualInputClassification(env, selected.id, type, {
    raw_text: rawText,
    memo: memoText,
    category: String(form.get("category") || "").trim(),
    payment_method: String(form.get("payment_method") || "").trim(),
  });
  const body = {
    household_id: selected.id,
    user_id: spenderUserId,
    type,
    transaction_date: transactionDate,
    amount,
    memo: memoText,
    category: manualClass.category,
    payment_method: manualClass.payment_method,
    source: "my_web",
    raw_text: rawText,
  };
  try {
    const created = await createManualTransaction(env, body);
    if (created?.__duplicate_skipped) {
      return redirectResponse(duplicateSkippedReturnLocation(String(transactionDate).slice(0, 7) || month, selected.id));
    }
    return redirectResponse(myReturnLocation(String(transactionDate).slice(0, 7) || month, selected.id, { msg: "created" }));
  } catch (err) {
    rememberOpsEvent({ kind: "save_error", severity: isDatabaseBusyError(err) ? "warn" : "error", path: "/my/transactions", method: "POST", detail: safeError(err) });
    return redirectResponse(myReturnLocation(month, selected.id, { err: userSafeErrorCode(err) }));
  }
}

async function handleMyUpdateTransaction(request, env) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const form = await request.formData();
  const id = String(form.get("id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const householdId = String(form.get("household_id") || "").trim();
  const { selected } = await getMySelectedHousehold(env, userId, householdId);
  if (!selected) return redirectResponse("/my?err=no_household");
  if (!canWriteMyHousehold(selected.role)) return redirectResponse(myReturnLocation(month, selected.id, { err: "write_not_allowed" }));
  const row = await getTransactionForUserEdit(env, id, selected.id);
  if (!row) return redirectResponse(myReturnLocation(month, selected.id, { err: "record_not_found" }));
  if (!canManageMyRecord(selected.role, row, userId)) return redirectResponse(myReturnLocation(month, selected.id, { err: "not_my_record" }));
  const transactionDate = String(form.get("transaction_date") || row.transaction_date || formatDate(nowKstDate())).trim();
  const amount = parseMyAmount(form);
  if (!amount || amount <= 0) return redirectResponse(myReturnLocation(month, selected.id, { err: "amount_required" }));
  if (!isValidTransactionDateString(transactionDate)) return redirectResponse(myReturnLocation(month, selected.id, { err: "invalid_date" }));
  const members = await fetchHouseholdMembers(env, selected.id);
  const requestedUserId = String(form.get("user_id") || "").trim();
  if (requestedUserId && !memberExists(members, requestedUserId)) return redirectResponse(myReturnLocation(month, selected.id, { err: "spender_not_member" }));
  const patch = {
    type: normalizeTransactionType(String(form.get("type") || row.type || "expense")),
    transaction_date: transactionDate,
    amount,
    memo: String(form.get("memo") || "").trim(),
    category: String(form.get("category") || "").trim(),
    payment_method: String(form.get("payment_method") || "").trim(),
    user_id: canManageAllRecords(selected.role) && requestedUserId && memberExists(members, requestedUserId) ? requestedUserId : row.user_id,
  };
  try {
    await updateTransaction(env, id, patch, { householdId: selected.id, actorUserId: userId, actorKind: "user" });
    await appendTransactionEditHistory(env, selected.id, id, row, { ...row, ...patch }, userId, members);
    return redirectResponse(myReturnLocation(String(transactionDate).slice(0, 7) || month, selected.id, { msg: "updated" }));
  } catch (err) {
    rememberOpsEvent({ kind: "my_record_update_failed", severity: "warn", path: "/my/update", method: "POST", detail: safeError(err) });
    return redirectResponse(myReturnLocation(month, selected.id, { err: "record_update_failed" }));
  }
}

async function handleMyDeleteTransaction(request, env) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const form = await request.formData();
  const id = String(form.get("id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const householdId = String(form.get("household_id") || "").trim();
  const { selected } = await getMySelectedHousehold(env, userId, householdId);
  if (!selected) return redirectResponse("/my?err=no_household");
  if (!canWriteMyHousehold(selected.role)) return redirectResponse(myReturnLocation(month, selected.id, { err: "write_not_allowed" }));
  const row = await getTransactionForUserEdit(env, id, selected.id);
  if (!row) return redirectResponse(myReturnLocation(month, selected.id, { err: "record_not_found" }));
  if (!canManageMyRecord(selected.role, row, userId)) return redirectResponse(myReturnLocation(month, selected.id, { err: "not_my_record" }));
  try {
    await deleteTransactionWithAudit(env, id, selected.id, { actorUserId: userId, actorKind: "user" });
    return redirectResponse(myReturnLocation(month, selected.id, { msg: "deleted" }));
  } catch (err) {
    rememberOpsEvent({ kind: "my_record_delete_failed", severity: "warn", path: "/my/delete", method: "POST", detail: safeError(err) });
    return redirectResponse(myReturnLocation(month, selected.id, { err: "record_delete_failed" }));
  }
}


function householdTemplatePreset(key = "") {
  const presets = {
    travel: { name: "우리 여행 경비", label: "여행" },
    meeting: { name: "우리 모임 회비", label: "모임" },
    settlement: { name: "단발성 정산", label: "정산" },
    family_event: { name: "가족 행사비", label: "가족 행사" },
  };
  return presets[String(key || "").trim()] || null;
}

