async function fetchMonthAmountRows(env, month, householdId) {
  if (!householdId) return [];
  const params = new URLSearchParams();
  params.set("select", "type,amount");
  params.set("transaction_date", `gte.${month}-01`);
  params.append("transaction_date", `lt.${nextMonthStart(month)}`);
  params.set("household_id", `eq.${householdId}`);
  params.set("order", "transaction_date.desc");
  return fetchPostgrestRows(env, `/rest/v1/transactions?${params.toString()}`, { maxRows: 10000 });
}

function filterMobileTransactionRows(rows = [], filters = {}) {
  const type = filters.type === "income" ? "income" : filters.type === "expense" ? "expense" : "all";
  const needle = String(filters.q || "").trim().toLowerCase();
  const quality = String(filters.quality || "all");
  const date = String(filters.date || "");
  const category = String(filters.category || "");
  const payment = String(filters.payment_method || "");
  return safeArray(rows).filter((row) => {
    if (type !== "all" && row.type !== type) return false;
    if (date && String(row.transaction_date || "") !== date) return false;
    if (needle && !String(`${row.memo || ""} ${row.category || ""} ${row.payment_method || ""} ${row.raw_text || ""}`).toLowerCase().includes(needle)) return false;
    if (category && !(category === "__missing" ? isMissingCategory(row.category) : String(row.category || "") === category)) return false;
    if (payment && !(payment === "__missing" ? isMissingPayment(row.payment_method) : String(row.payment_method || "") === payment)) return false;
    if (quality === "missing_category" && !isMissingCategory(row.category)) return false;
    if (quality === "missing_payment" && !(row.type === "expense" && isMissingPayment(row.payment_method))) return false;
    if (quality === "missing_any" && !(isMissingCategory(row.category) || (row.type === "expense" && isMissingPayment(row.payment_method)))) return false;
    if (quality === "kakao_only" && !String(row.source || "").includes("kakao")) return false;
    if (quality === "web_only" && !String(row.source || "").includes("web")) return false;
    return true;
  });
}

async function handleMobileV8Page(request, env, url) {
  const [userId, adminOk] = await Promise.all([
    verifyUserSession(request, env),
    verifyAdminSession(request, env),
  ]);
  if (!userId && !adminOk) return redirectResponse("/my");
  const title = escapeHtml(appName(env));
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  let households = [];
  let selectedHousehold = null;
  if (userId) {
    const access = await getMySelectedHousehold(env, userId, url.searchParams.get("household_id") || "");
    if (access.restricted) {
      const user = await fetchUserById(env, userId);
      return myAccessStatusResponse({ env, user, household: access.restricted, role: access.restricted.role, month });
    }
    households = access.households;
    selectedHousehold = access.selected;
    if (!selectedHousehold) {
      const user = await fetchUserById(env, userId);
      return htmlResponse(renderMyStartChoiceHtml({ env, user, err: "no_household" }));
    }
  } else {
    households = await fetchAdminHouseholds(env);
    const requestedId = url.searchParams.get("household_id") || households[0]?.id || "";
    selectedHousehold = households.find((h) => h.id === requestedId) || households[0] || null;
  }
  const householdId = selectedHousehold?.id || "";
  const mobileType = url.searchParams.get("type") === "income" ? "income" : url.searchParams.get("type") === "expense" ? "expense" : "all";
  const mobileQ = String(url.searchParams.get("q") || "").trim();
  const mobileQuality = ["missing_any", "missing_category", "missing_payment", "kakao_only", "web_only"].includes(String(url.searchParams.get("quality") || "")) ? String(url.searchParams.get("quality")) : "all";
  const mobileDate = isValidTransactionDateString(url.searchParams.get("date") || "") ? String(url.searchParams.get("date")) : "";
  const mobileCategory = String(url.searchParams.get("category") || "").trim();
  const mobilePayment = String(url.searchParams.get("payment_method") || "").trim();
  const canLoadWriteOptions = !!selectedHousehold && (adminOk || canWriteMyHousehold(String(selectedHousehold.role || "")));
  const includeReserve = !!selectedHousehold && month === currentMonthKst();
  const homeSettingsPromise = selectedHousehold
    ? fetchMobileHomeSettings(env, householdId, month, { includeReserve, includePayment: canLoadWriteOptions })
    : Promise.resolve({ aliases: {}, budgetRows: [], reservePlans: [], paymentAssets: [] });
  const [members, rawMonthlyRows, prevAmountRows, budgets, homeSettings] = await Promise.all([
    selectedHousehold ? fetchHouseholdMembers(env, selectedHousehold.id, { aliasesPromise: homeSettingsPromise.then((settings) => settings.aliases) }) : [],
    selectedHousehold ? fetchAdminRows(env, { month, householdId, type: "all" }) : [],
    selectedHousehold ? fetchMonthAmountRows(env, addMonthsYm(month, -1), householdId) : [],
    selectedHousehold ? fetchBudgets(env, householdId, month, { settingsRowsPromise: homeSettingsPromise.then((settings) => settings.budgetRows) }) : [],
    homeSettingsPromise,
  ]);
  const reservePlans = homeSettings.reservePlans;
  const paymentAssetRows = homeSettings.paymentAssets;
  const rows = attachSpenderNames(rawMonthlyRows, members);
  const filteredRows = filterMobileTransactionRows(rows, {
    type: mobileType,
    q: mobileQ,
    quality: mobileQuality,
    date: mobileDate,
    category: mobileCategory,
    payment_method: mobilePayment,
  });
  const stats = calculateStats(rows);
  const prevStats = calculateStats(prevAmountRows);
  const budget = budgetSummary(rows, budgets);
  const categoryOptions = mergedOptions(DEFAULT_CATEGORIES, rows.map((r) => r.category).filter(Boolean));
  const paymentOptions = mergedOptions(DEFAULT_PAYMENTS, [...paymentAssetRows.map((p) => p.name).filter(Boolean), ...rows.map((r) => r.payment_method).filter(Boolean)]);
  const msg = url.searchParams.get("msg") || "";
  const err = url.searchParams.get("err") || "";
  const mobileFeed = url.searchParams.get("feed") === "all" ? "all" : url.searchParams.get("feed") === "30" ? "30" : "10";
  const focusTab = url.searchParams.get("tab") === "transactions" ? "transactions" : "home";
  const balert = String(url.searchParams.get("balert") || "").slice(0, 120);
  const homeView = url.searchParams.get("view") === "calendar" ? "calendar" : "";
  const calendarRows = rows;
  return htmlResponse(renderMobileV81Html({ title, month, households, selectedHousehold, members, rows, filteredRows, stats, prevStats, budgets, reservePlans, budget, recurring: [], meme: null, categoryOptions, paymentOptions, msg, err, mobileFeed, mobileFilters: { type: mobileType, q: mobileQ, quality: mobileQuality, date: mobileDate, category: mobileCategory, payment_method: mobilePayment }, focusTab, balert, homeView, calendarRows, sessionRole: adminOk ? "admin" : String(selectedHousehold?.role || ""), sessionUserId: userId || "", isAdminSession: !!adminOk }));
}



async function handleBudgetSave(request, env) {
  const form = await request.formData();
  const householdId = String(form.get("household_id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const returnTo = safeAdminReturnPath(form.get("return_to") || "", `/budgets?month=${month}&household_id=${encodeURIComponent(householdId)}`);
  const adminOk = await verifyAdminSession(request, env);
  const userId = adminOk ? "" : await verifyUserSession(request, env);
  if (!adminOk) {
    const role = await getHouseholdMemberRole(env, userId, householdId);
    if (!["owner", "admin"].includes(role)) return redirectResponse(addQueryToUrl(returnTo, { err: "예산 저장 권한이 없습니다." }));
  }
  const rawCategory = String(form.get("category") || "__total").trim() || "__total";
  const customCategory = String(form.get("category_custom") || "").trim().slice(0, 80);
  let category = rawCategory;
  if (rawCategory === "__income_custom") category = customCategory ? `__income:${customCategory}` : "__income";
  if (rawCategory === "__category_custom") category = customCategory || "기타";
  const amount = Math.max(0, Math.round(parseAmountValue(form.get("amount") || "0")));
  try {
    await supabase(env, "/rest/v1/accountbook_budgets?on_conflict=household_id,month,category", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify({ household_id: householdId, month, category, amount }),
    });
    return redirectResponse(addQueryToUrl(returnTo, { msg: "budget_saved" }));
  } catch (err) {
    try {
      await saveSettingsBudget(env, householdId, month, category, amount);
      return redirectResponse(addQueryToUrl(returnTo, { msg: "budget_saved" }));
    } catch (fallbackErr) {
      return redirectResponse(addQueryToUrl(returnTo, { err: "예산 저장을 완료하지 못했습니다." }));
    }
  }
}

async function handleBudgetDelete(request, env) {
  const form = await request.formData();
  const householdId = String(form.get("household_id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const category = String(form.get("category") || "").trim();
  const returnTo = safeAdminReturnPath(form.get("return_to") || "", `/budgets?month=${month}&household_id=${encodeURIComponent(householdId)}`);
  const adminOk = await verifyAdminSession(request, env);
  const userId = adminOk ? "" : await verifyUserSession(request, env);
  if (!adminOk) {
    const role = await getHouseholdMemberRole(env, userId, householdId);
    if (!["owner", "admin"].includes(role)) return redirectResponse(addQueryToUrl(returnTo, { err: "예산 삭제 권한이 없습니다." }));
  }
  if (!category) return redirectResponse(addQueryToUrl(returnTo, { err: "삭제할 예산을 찾지 못했습니다." }));
  try {
    await optionalSupabase(env, `/rest/v1/accountbook_budgets?household_id=eq.${encodeURIComponent(householdId)}&month=eq.${encodeURIComponent(month)}&category=eq.${encodeURIComponent(category)}`, { method: "DELETE", headers: { Prefer: "return=minimal" } }, null);
    await deleteSettingsBudget(env, householdId, month, category);
    return redirectResponse(addQueryToUrl(returnTo, { msg: "budget_deleted" }));
  } catch (err) {
    return redirectResponse(addQueryToUrl(returnTo, { err: "예산 삭제를 완료하지 못했습니다." }));
  }
}


async function pcScopedContext(request, env, url) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return null;
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const [user, access] = await Promise.all([
    fetchUserById(env, userId),
    getMySelectedHousehold(env, userId, url.searchParams.get("household_id") || ""),
  ]);
  if (access.restricted) return { userId, user, month, households: access.households, selectedHousehold: null, restricted: access.restricted };
  const households = access.households;
  const selectedHousehold = access.selected;
  if (!selectedHousehold) return { userId, month, households, selectedHousehold: null, members: [], rows: [], stats: calculateStats([]), budgets: [], budget: budgetSummary([], []), calendar: [] };
  const [members, rawRows, budgets, calendar] = await Promise.all([
    fetchHouseholdMembers(env, selectedHousehold.id),
    fetchAdminRows(env, { month, householdId: selectedHousehold.id, type: "all" }),
    fetchBudgets(env, selectedHousehold.id, month),
    getCalendar(env, selectedHousehold.id, month),
  ]);
  const rows = attachSpenderNames(rawRows, members);
  const stats = calculateStats(rows);
  const budget = budgetSummary(rows, budgets);
  return { userId, month, households, selectedHousehold, members, rows, stats, budgets, budget, calendar };
}

function pcHouseholdMonthFilters(action, households = [], selected = null, month = currentMonthKst()) {
  const opts = safeArray(households).map((h) => `<option value="${escapeHtml(h.id)}" ${selected?.id === h.id ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  return `<form class="filters" method="get" action="${escapeHtml(action)}"><select name="household_id">${opts}</select><input type="month" name="month" value="${escapeHtml(month)}"/><button type="submit">조회</button></form>`;
}


const ANALYSIS_DONUT_COLORS = ["#3182F6", "#7c3aed", "#f59e0b", "#ef4444", "#10b981", "#ec4899", "#94a3b8"];

function renderDonutChart(categories = [], totalExpense = 0) {
  const top = safeArray(categories).filter((c) => Number(c.expense || 0) > 0).slice(0, 6);
  const total = Number(totalExpense || 0);
  if (!top.length || !total) return `<div class="empty">지출 데이터가 없습니다. 기록을 남기면 분류별 비중이 표시됩니다.</div>`;
  const topSum = top.reduce((s, c) => s + Number(c.expense || 0), 0);
  const etc = Math.max(0, total - topSum);
  const slices = [...top.map((c) => ({ name: c.category || "미분류", amount: Number(c.expense || 0) })), ...(etc > 0 ? [{ name: "기타", amount: etc }] : [])];
  const circumference = 2 * Math.PI * 42;
  let dashOffset = 0;
  const segments = slices.map((s, i) => {
    const len = Math.max(0, s.amount / total) * circumference;
    const seg = `<circle r="42" cx="60" cy="60" fill="none" stroke="${ANALYSIS_DONUT_COLORS[i % ANALYSIS_DONUT_COLORS.length]}" stroke-width="17" stroke-dasharray="${len.toFixed(2)} ${(circumference - len).toFixed(2)}" stroke-dashoffset="${(-dashOffset).toFixed(2)}" transform="rotate(-90 60 60)"/>`;
    dashOffset += len;
    return seg;
  }).join("");
  const legend = slices.map((s, i) => `<li><i style="background:${ANALYSIS_DONUT_COLORS[i % ANALYSIS_DONUT_COLORS.length]}"></i><b>${escapeHtml(s.name)}</b><span>${numberWithCommas(s.amount)}원 · ${Math.round(s.amount / total * 100)}%</span></li>`).join("");
  return `<div class="donutWrap"><svg class="donutSvg" viewBox="0 0 120 120" role="img" aria-label="분류별 지출 비중 도넛 차트">${segments}<text x="60" y="55" text-anchor="middle" class="donutLabel">총 지출</text><text x="60" y="73" text-anchor="middle" class="donutValue">${escapeHtml(shortWonLabel(total))}</text></svg><ul class="donutLegend">${legend}</ul></div>`;
}

function renderMonthlySeriesChart(items = []) {
  const list = safeArray(items).slice(-6);
  if (!list.some((x) => Number(x.income || 0) > 0 || Number(x.expense || 0) > 0)) return `<div class="empty">아직 월별 흐름을 그릴 데이터가 없습니다.</div>`;
  const max = Math.max(1, ...list.map((x) => Math.max(Number(x.income || 0), Number(x.expense || 0))));
  const cols = list.map((x) => {
    const ih = Math.max(3, Math.round(Number(x.income || 0) / max * 118));
    const eh = Math.max(3, Math.round(Number(x.expense || 0) / max * 118));
    return `<div class="seriesCol" title="${escapeHtml(x.month)} · 수입 ${numberWithCommas(x.income)}원 · 지출 ${numberWithCommas(x.expense)}원"><div class="seriesBars"><i class="in" style="height:${ih}px"></i><i class="ex" style="height:${eh}px"></i></div><b>${escapeHtml(shortWonLabel(x.expense))}</b><span>${escapeHtml(String(x.month).slice(5))}월</span></div>`;
  }).join("");
  return `<div class="seriesLegend"><span><i class="in"></i>수입</span><span><i class="ex"></i>지출</span></div><div class="seriesChart">${cols}</div>`;
}

function normalizeRecurringKey(row = {}) {
  const memo = String(row.memo || row.raw_text || "").trim().toLowerCase().replace(/\s+/g, "").slice(0, 30);
  const amount = Math.round(Number(row.amount || 0));
  if (!memo || !amount) return "";
  return `${memo}|${amount}`;
}

function detectRecurringCandidates(historyRows = [], month = currentMonthKst(), registered = []) {
  const windowMonths = [addMonthsYm(month, -2), addMonthsYm(month, -1), month];
  const registeredKeys = new Set(safeArray(registered).map((x) => normalizeRecurringKey(x)).filter(Boolean));
  const byKey = {};
  for (const r of safeArray(historyRows)) {
    if (r.type === "income" || ["recurring", "recurring_auto"].includes(String(r.source || ""))) continue;
    const ym = String(r.transaction_date || "").slice(0, 7);
    if (!windowMonths.includes(ym)) continue;
    const key = normalizeRecurringKey(r);
    if (!key || registeredKeys.has(key)) continue;
    if (!byKey[key]) byKey[key] = { memo: String(r.memo || r.raw_text || "").trim(), amount: Math.round(Number(r.amount || 0)), category: r.category || "", paymentMethod: r.payment_method || "", days: [], months: new Set() };
    const day = Number(String(r.transaction_date || "").slice(8, 10));
    if (Number.isFinite(day) && day >= 1 && day <= 31) byKey[key].days.push(day);
    byKey[key].months.add(ym);
  }
  return Object.values(byKey)
    .filter((v) => v.months.size >= 2 && v.amount >= 1000)
    .map((v) => ({ memo: v.memo, amount: v.amount, category: v.category, paymentMethod: v.paymentMethod || "", dayOfMonth: v.days.length ? Math.round(v.days.reduce((s, x) => s + x, 0) / v.days.length) : 1, hitMonths: v.months.size }))
    .sort((a, b) => b.hitMonths - a.hitMonths || b.amount - a.amount)
    .slice(0, 8);
}

function renderRecurringInsightList(candidates = []) {
  if (!candidates.length) return `<p class="muted">최근 3개월에서 같은 이름·같은 금액으로 반복된 지출을 찾지 못했습니다. 구독료나 회비는 메모를 같은 이름으로 적으면 자동으로 잡아드립니다.</p>`;
  return `<ul class="insightList">${candidates.map((c) => `<li><b>${escapeHtml(c.memo || "이름 없음")}</b><span>${escapeHtml(c.category || "미분류")} · 최근 3개월 중 ${c.hitMonths}개월 반복</span><strong>${numberWithCommas(c.amount)}원</strong></li>`).join("")}</ul>`;
}

function findAnomalousExpenses(rows = [], historyRows = [], month = currentMonthKst()) {
  const expenses = safeArray(rows).filter((r) => r.type !== "income" && Number(r.amount || 0) > 0);
  if (!expenses.length) return [];
  const past = safeArray(historyRows).filter((r) => r.type !== "income" && Number(r.amount || 0) > 0 && String(r.transaction_date || "").slice(0, 7) !== month);
  const catSum = {};
  const catCount = {};
  for (const r of past) {
    const k = r.category || "미분류";
    catSum[k] = (catSum[k] || 0) + Number(r.amount || 0);
    catCount[k] = (catCount[k] || 0) + 1;
  }
  const totalExpense = expenses.reduce((s, r) => s + Number(r.amount || 0), 0);
  return expenses.map((r) => {
    const k = r.category || "미분류";
    const avg = catCount[k] ? Math.round(catSum[k] / catCount[k]) : 0;
    const amount = Number(r.amount || 0);
    const vsAvg = avg > 0 ? Math.round(amount / avg * 10) / 10 : 0;
    const share = totalExpense ? Math.round(amount / totalExpense * 100) : 0;
    if ((avg > 0 && vsAvg >= 3 && amount >= 30000) || share >= 15) return { ...r, avg, vsAvg, share };
    return null;
  }).filter(Boolean).sort((a, b) => Number(b.amount) - Number(a.amount)).slice(0, 3);
}

function renderAnomalyList(items = []) {
  if (!items.length) return `<p class="muted">평소 흐름에서 크게 벗어난 지출이 없습니다. 안정적인 소비 흐름이에요.</p>`;
  return `<ul class="insightList">${items.map((r) => `<li><b>${escapeHtml(r.memo || r.raw_text || r.category || "지출")}</b><span>${escapeHtml(String(r.transaction_date || ""))} · ${escapeHtml(r.category || "미분류")}${r.avg && r.vsAvg >= 3 ? ` · 평소 ${numberWithCommas(r.avg)}원의 ${r.vsAvg}배` : ` · 이번 달 지출의 ${r.share}%`}</span><strong>${numberWithCommas(r.amount)}원</strong></li>`).join("")}</ul>`;
}

function buildWeeklyReport(historyRows = [], month = currentMonthKst()) {
  const todayStr = formatDate(nowKstDate());
  if (todayStr.slice(0, 7) !== month) return null;
  const today = nowKstDate();
  const mondayOffset = (today.getDay() + 6) % 7;
  const thisWeekStart = formatDate(addDays(today, -mondayOffset));
  const lastWeekStart = formatDate(addDays(today, -mondayOffset - 7));
  const lastWeekSamePoint = formatDate(addDays(today, -7));
  const lastWeekEnd = formatDate(addDays(today, -mondayOffset - 1));
  const inRange = (d, a, b) => d >= a && d <= b;
  let thisWeek = 0;
  let lastWeekToPoint = 0;
  let lastWeekTotal = 0;
  const catMap = {};
  for (const r of safeArray(historyRows)) {
    if (r.type === "income") continue;
    const d = String(r.transaction_date || "");
    if (!d) continue;
    const amount = Number(r.amount || 0);
    if (inRange(d, thisWeekStart, todayStr)) {
      thisWeek += amount;
      const k = r.category || "미분류";
      catMap[k] = (catMap[k] || 0) + amount;
    }
    if (inRange(d, lastWeekStart, lastWeekSamePoint)) lastWeekToPoint += amount;
    if (inRange(d, lastWeekStart, lastWeekEnd)) lastWeekTotal += amount;
  }
  const topEntry = Object.entries(catMap).sort((a, b) => b[1] - a[1])[0] || null;
  return {
    thisWeekStart,
    todayStr,
    thisWeek,
    lastWeekToPoint,
    lastWeekTotal,
    rate: percentChange(thisWeek, lastWeekToPoint),
    topCategory: topEntry ? { name: topEntry[0], amount: topEntry[1] } : null,
  };
}

function renderWeeklyReportCard(weekly) {
  if (!weekly) return "";
  const cls = weekly.rate > 10 ? "deltaUp" : weekly.rate < -10 ? "deltaDown" : "deltaFlat";
  const message = weekly.rate > 10 ? "지난주보다 소비 속도가 빨라요. 남은 요일을 조금 아껴보세요." : weekly.rate < -10 ? "지난주보다 잘 아끼고 있어요. 이 흐름을 유지해보세요." : "지난주와 비슷한 속도로 쓰고 있어요.";
  const max = Math.max(1, weekly.thisWeek, weekly.lastWeekTotal);
  return `<section class="card"><h2>주간 리포트</h2><p class="muted">이번 주(월요일~오늘) 지출을 지난주 같은 시점까지의 지출과 비교합니다.</p><div class="weeklyHead"><b>${numberWithCommas(weekly.thisWeek)}원</b><span class="${cls}">지난주 같은 시점 대비 ${formatSignedPercent(weekly.rate)}</span></div><div class="trendBars"><div class="trendLine"><div class="trendLabel">이번 주</div><div class="bar"><span style="width:${Math.round(weekly.thisWeek / max * 100)}%"></span></div><div class="trendValue">${numberWithCommas(weekly.thisWeek)}원</div></div><div class="trendLine"><div class="trendLabel">지난주 전체</div><div class="bar"><span style="width:${Math.round(weekly.lastWeekTotal / max * 100)}%"></span></div><div class="trendValue">${numberWithCommas(weekly.lastWeekTotal)}원</div></div></div><p class="muted">${escapeHtml(message)}${weekly.topCategory ? ` 이번 주는 <b>${escapeHtml(weekly.topCategory.name)}</b>에 ${numberWithCommas(weekly.topCategory.amount)}원을 가장 많이 썼어요.` : ""}</p></section>`;
}

function renderPcAnalysisHtml({ month, households, selectedHousehold, rows, stats, budgets, budget, calendar, extended = null, recurringCandidates = [], anomalies = [], weeklyReport = null }) {
  const selected = selectedHousehold || {};
  const analysis = calculateDashboardAnalysis(rows, rows, calendar, month);
  const center = budgetCenterSummary(rows, budgets);
  const ext = extended || calculateExtendedAnalytics({ month, allRows: rows, prevRows: [], historyRows: [], yearRows: [], rowsBase: rows });
  const incomeMoMRate = percentChange(stats.totals.income, ext.prev.totals.income);
  const daysInMonth = new Date(Number(month.slice(0, 4)), Number(month.slice(5, 7)), 0).getDate() || 30;
  const todayStr = formatDate(nowKstDate());
  const remainingDays = todayStr.slice(0, 7) === month ? Math.max(1, daysInMonth - Number(todayStr.slice(8, 10)) + 1) : 0;
  const remainingBudget = Math.max(0, center.totalBudget - center.budget.expense);
  const dailyAllowance = center.totalBudget && remainingDays ? Math.round(remainingBudget / remainingDays) : 0;
  const recurringTotal = safeArray(recurringCandidates).reduce((s, c) => s + Number(c.amount || 0), 0);
  const drillBase = `/app?month=${encodeURIComponent(month)}${selected.id ? `&household_id=${encodeURIComponent(selected.id)}` : ""}`;
  const topRows = stats.categories.filter((c) => c.expense > 0).slice(0, 10).map((c) => `<tr><td><a class="drillLink" href="${escapeHtml(`${drillBase}&type=expense&category=${encodeURIComponent(c.category)}&feed=all`)}#feed">${escapeHtml(c.category)}</a></td><td>${numberWithCommas(c.expense)}원</td><td>${numberWithCommas(c.count || 0)}건</td><td>${stats.totals.expense ? Math.round(c.expense / stats.totals.expense * 100) : 0}%</td></tr>`).join("") || `<tr><td colspan="4">지출 데이터가 없습니다.</td></tr>`;
  const patternRows = [
    ["월말 예상 지출", `${numberWithCommas(analysis.burnForecast || 0)}원`, "현재 지출 속도 기준"],
    ["고정비 비중", `${analysis.fixedRate || 0}%`, `${numberWithCommas(analysis.fixedExpense || 0)}원`],
    ["주말 지출 비중", `${analysis.weekendRate || 0}%`, `${numberWithCommas(analysis.weekendExpense || 0)}원`],
    ["카테고리 집중도", `${analysis.concentration || 0}%`, `${escapeHtml(analysis.topCategory?.category || "없음")} 중심`],
    ["소비 위험도", `${analysis.riskScore || 0}점`, (analysis.riskScore || 0) >= 70 ? "주의" : "정상"],
    ["무지출일", `${analysis.noSpendDays || 0}일`, "이번 달 소비 없는 날짜"],
  ].map(([a,b,c]) => `<div class="metric"><span>${a}</span><b>${b}</b><small>${c}</small></div>`).join("");
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${escapeHtml(selected.name || "가계부")} · 분석</title><style>*,*:before,*:after{box-sizing:border-box}body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1180px;margin:0 auto;padding:16px}.hero,.card{background:#fff;border:1px solid #e5e7eb;border-radius:28px;padding:22px;margin:14px 0;box-shadow:0 12px 32px rgba(15,23,42,.06)}.hero{background:linear-gradient(135deg,#111827,#7c3aed);color:#fff}.hero h1{margin:0;font-size:30px}.hero p{opacity:.9}.filters{display:grid;grid-template-columns:1fr 200px 140px;gap:8px;margin-top:14px}.filters select,.filters input,.filters button{height:44px;border:1px solid #d1d5db;border-radius:14px;padding:0 12px;background:#fff;font:inherit}.filters button{background:#111827;color:#fff;font-weight:1000}.metricGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:20px;padding:15px}.metric span,.metric small{display:block;color:#64748b}.metric b{display:block;font-size:24px;margin:5px 0}.trendChart{display:flex;align-items:end;gap:5px;min-height:176px;overflow:auto;padding:12px;border:1px solid #e8edf4;border-radius:18px;background:#f8fafc}.trendBar{display:grid;grid-template-rows:22px 1fr 16px;align-items:end;justify-items:center;min-width:26px;height:156px}.trendBar strong{font-size:10px;color:#334155;white-space:nowrap;writing-mode:vertical-rl;transform:rotate(180deg);align-self:start}.trendBar i{display:block;width:13px;background:#2563eb;border-radius:999px 999px 0 0}.trendBar span{font-size:10px;color:#64748b}.tableWrap{overflow:auto}table{width:100%;border-collapse:collapse;min-width:720px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left}.btn{display:inline-flex;background:#111827;color:#fff!important;border-radius:14px;text-decoration:none;padding:10px 14px;font-weight:1000}.soft{background:#eef2f7!important;color:#111827!important}@media(max-width:760px){body{overflow-x:hidden}.wrap{padding:12px 10px 96px}.filters{grid-template-columns:1fr}.filters select,.filters input,.filters button{width:100%;font-size:16px}.hero{border-radius:22px;padding:18px}.hero h1{font-size:24px;line-height:1.25}.metricGrid{grid-template-columns:1fr 1fr;gap:8px}.metric{padding:13px;border-radius:18px}.metric b{font-size:20px}.card{border-radius:20px;padding:16px}.trendChart{min-height:150px}.tableWrap{overflow-x:auto;-webkit-overflow-scrolling:touch}table{min-width:680px}}
.muted{color:#64748b;font-size:13px;line-height:1.5}
.grid2col{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin:14px 0}
.grid2col>.card{margin:0}
.insightGrid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}
.insight{border-radius:18px;border:1px solid #e5e7eb;padding:14px;background:#fff}
.insight.warn{background:#fff7ed;border-color:#fed7aa}
.insight.danger{background:#fef2f2;border-color:#fecaca}
.insight.good{background:#f0fdf4;border-color:#bbf7d0}
.insight b{display:block;margin-bottom:4px}
.donutWrap{display:grid;grid-template-columns:230px 1fr;gap:18px;align-items:center}
.donutSvg{width:100%;max-width:230px}
.donutLabel{font-size:9px;fill:#64748b;font-weight:700}
.donutValue{font-size:15px;fill:#111827;font-weight:1000}
.donutLegend{list-style:none;margin:0;padding:0;display:grid;gap:9px}
.donutLegend li{display:grid;grid-template-columns:14px minmax(0,1fr) auto;gap:8px;align-items:center;font-size:13px}
.donutLegend i{width:12px;height:12px;border-radius:4px}
.donutLegend b{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.donutLegend span{color:#64748b;white-space:nowrap}
.seriesChart{display:flex;align-items:flex-end;gap:14px;padding:14px;border:1px solid #e8edf4;border-radius:18px;background:#f8fafc;overflow-x:auto}
.seriesCol{display:grid;justify-items:center;gap:4px;min-width:52px}
.seriesBars{display:flex;align-items:flex-end;gap:4px;height:124px}
.seriesBars i{display:inline-block;width:15px;border-radius:6px 6px 0 0}
.seriesBars i.in,.seriesLegend i.in{background:#10b981}
.seriesBars i.ex,.seriesLegend i.ex{background:#3182F6}
.seriesCol b{font-size:11px;color:#334155}
.seriesCol span{font-size:11px;color:#64748b}
.seriesLegend{display:flex;gap:14px;margin:0 0 8px;color:#64748b;font-size:12px;align-items:center}
.seriesLegend span{display:inline-flex;align-items:center}
.seriesLegend i{display:inline-block;width:10px;height:10px;border-radius:3px;margin-right:5px}
.insightList{list-style:none;margin:10px 0;padding:0;display:grid;gap:8px}
.insightList li{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:2px 12px;border:1px solid #e5e7eb;border-radius:14px;padding:10px 12px;background:#f8fafc}
.insightList li b{grid-column:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.insightList li span{grid-column:1;color:#64748b;font-size:12px}
.insightList li strong{grid-row:1/3;grid-column:2;align-self:center;white-space:nowrap}
.bar{height:10px;background:#e5e7eb;border-radius:999px;overflow:hidden}
.bar span{display:block;height:100%;background:linear-gradient(90deg,#2563eb,#7c3aed)}
.deltaUp{color:#dc2626!important;font-weight:900}
.deltaDown{color:#16a34a!important;font-weight:900}
.deltaFlat{color:#64748b!important;font-weight:900}
.statTable th,.statTable td{font-size:13px}
details.foldTable{margin-top:12px}
details.foldTable summary{cursor:pointer;font-weight:1000;color:#2563eb}
details.foldTable>div{margin-top:10px}
details.foldSection summary{cursor:pointer;font-weight:1000;color:#2563eb;padding:2px 0}
details.foldSection>div{margin-top:10px}
details.foldSection summary h2{display:inline;font-size:inherit}
.drillLink{color:#2563eb;text-decoration:none;font-weight:1000}.drillLink:hover{text-decoration:underline}
.weeklyHead{display:flex;align-items:baseline;gap:10px;flex-wrap:wrap;margin:6px 0 10px}
.weeklyHead b{font-size:26px;letter-spacing:-.04em}
.trendBars{display:grid;gap:10px}
.trendLine{display:grid;grid-template-columns:84px 1fr 130px;gap:10px;align-items:center}
.trendLabel{font-size:12px;font-weight:900;color:#334155}
.trendValue{text-align:right;font-size:12px;color:#64748b}
@media(max-width:760px){.grid2col{grid-template-columns:1fr}.donutWrap{grid-template-columns:1fr}.insightGrid{grid-template-columns:1fr}.seriesCol{min-width:44px}.trendLine{grid-template-columns:70px 1fr}.trendValue{display:none}}</style></head><body>${renderUnifiedNav("analysis", { month, householdId: selected.id || "", householdName: selected.name || "가계부" })}<main class="wrap"><section class="hero"><h1>${escapeHtml(selected.name || "가계부")} 분석</h1><p>전월 대비 변화, 월별 흐름, 지출 구성, 반복 지출과 큰 지출까지 월간 리포트처럼 한 화면에서 확인합니다.</p>${pcHouseholdMonthFilters("/analysis", households, selected, month)}</section><section class="metricGrid"><div class="metric"><span>총 지출</span><b>${numberWithCommas(stats.totals.expense)}원</b><small class="${deltaClass(ext.expenseMoMRate)}">지난달 대비 ${formatSignedPercent(ext.expenseMoMRate)}</small></div><div class="metric"><span>총 수입</span><b>${numberWithCommas(stats.totals.income)}원</b><small class="${incomeMoMRate > 0 ? "deltaDown" : incomeMoMRate < 0 ? "deltaUp" : "deltaFlat"}">지난달 대비 ${formatSignedPercent(incomeMoMRate)}</small></div><div class="metric"><span>잔여 예산</span><b>${numberWithCommas(remainingBudget)}원</b>${center.totalBudget && remainingDays ? `<small>남은 ${remainingDays}일 · 하루 ${numberWithCommas(dailyAllowance)}원</small>` : ""}</div><div class="metric"><span>예산 사용률</span><b>${center.budget.rate || 0}%</b></div><div class="metric"><span>하루 평균 지출</span><b>${numberWithCommas(analysis.avgExpense || 0)}원</b></div><div class="metric"><span>월말 예상</span><b>${numberWithCommas(analysis.burnForecast || 0)}원</b></div></section><section class="card"><h2>핵심 인사이트</h2><p class="muted">전월 대비 변화, 3개월 평균, 급증 분류, 소비 경보를 한눈에 요약했습니다.</p><div class="insightGrid">${renderStrategyCards(ext, analysis)}</div></section>${renderWeeklyReportCard(weeklyReport)}<section class="card"><h2>일별 소비 그래프</h2><p class="muted">금액이 있는 날을 누르면 그날 기록 목록으로 이동합니다.</p>${renderReadableDailyTrend(rows, month, drillBase)}</section><section class="card"><h2>요일별 소비 추이</h2><p class="muted">요일별로 소비가 집중되는 패턴을 확인합니다.</p>${renderWeekdayTrend(rows)}</section><section class="card"><details class="foldSection"><summary>이번 달 지출 구성 (도넛 차트)</summary><div><h2>이번 달 지출 구성</h2><p class="muted">상위 분류가 전체 지출에서 차지하는 비중입니다.</p>${renderDonutChart(stats.categories, stats.totals.expense)}</div></details></section><section class="card"><details class="foldSection"><summary>전월 대비 분류 변화 TOP</summary><div><h2>전월 대비 분류 변화 TOP</h2><p class="muted">지난달보다 크게 늘거나 줄어든 분류입니다.</p>${renderCategoryCompareTable(ext.categoryCompare, true)}</div></details></section><section class="card"><details class="foldSection"><summary>최근 6개월 수입·지출 흐름 · 12개월 상세</summary><div><h2>최근 6개월 수입·지출 흐름</h2><p class="muted">막대에 마우스를 올리면 정확한 금액이 표시됩니다.</p>${renderMonthlySeriesChart(ext.monthlyTrend)}<details class="foldTable"><summary>최근 12개월 상세 표 보기</summary><div>${renderMonthlyTrendTable(ext.monthlyTrend)}</div></details></div></details></section><section class="card"><details class="foldSection"><summary>매달 나가는 돈 (반복 지출 후보)</summary><div><h2>매달 나가는 돈</h2><p class="muted">최근 3개월간 같은 이름·같은 금액으로 반복된 지출입니다.${recurringTotal ? ` 합치면 매달 약 <b>${numberWithCommas(recurringTotal)}원</b>이에요.` : ""}</p>${renderRecurringInsightList(recurringCandidates)}<a class="btn soft" href="/reserve-plans?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(selected.id || "")}">정기지출로 관리하기</a></div></details></section><section class="card"><details class="foldSection"><summary>큰 지출 체크</summary><div><h2>큰 지출 체크</h2><p class="muted">평소 그 분류에서 쓰던 평균보다 크게 벗어난 지출입니다.</p>${renderAnomalyList(anomalies)}</div></details></section><section class="card"><h2>정밀 분석 도구</h2><div class="metricGrid">${patternRows}</div></section><section class="card"><h2>분류별 지출 랭킹</h2><div class="tableWrap"><table><thead><tr><th>분류</th><th>금액</th><th>건수</th><th>비중</th></tr></thead><tbody>${topRows}</tbody></table></div></section><section class="card"><a class="btn" href="/app?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(selected.id || "")}&view=calendar#calendar">캘린더로 보기</a> <a class="btn soft" href="/budgets?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(selected.id || "")}">예산관리로 이동</a></section></main></body></html>`;
}

async function handlePcAnalysisPage(request, env, url) {
  const ctx = await pcScopedContext(request, env, url);
  if (!ctx) return redirectResponse("/my");
  if (ctx.restricted) return myAccessStatusResponse({ env, user: ctx.user, household: ctx.restricted, role: ctx.restricted.role, month: ctx.month });
  const householdId = ctx.selectedHousehold?.id || "";
  const month = ctx.month;
  const prevRows = householdId ? await fetchAdminRows(env, { month: addMonthsYm(month, -1), householdId, type: "all" }) : [];
  const historyRows = householdId ? await fetchAdminRowsRange(env, { householdId, start: `${addMonthsYm(month, -11)}-01`, end: nextMonthStart(month) }) : [];
  const yearRows = householdId ? await fetchAdminRowsRange(env, { householdId, start: `${month.slice(0, 4)}-01-01`, end: `${Number(month.slice(0, 4)) + 1}-01-01` }) : [];
  const registeredRecurring = householdId ? await fetchRecurring(env, householdId) : [];
  const extended = calculateExtendedAnalytics({ month, allRows: ctx.rows, prevRows, historyRows, yearRows, rowsBase: ctx.rows });
  extended.fairMoM = computeFairMoM(month, ctx.rows, prevRows);
  const recurringCandidates = detectRecurringCandidates(historyRows, month, registeredRecurring);
  const anomalies = findAnomalousExpenses(ctx.rows, historyRows, month);
  const weeklyReport = buildWeeklyReport(historyRows, month);
  return htmlResponse(renderPcAnalysisHtml({ ...ctx, extended, recurringCandidates, anomalies, weeklyReport }));
}

function renderPcCalendarHtml({ month, households, selectedHousehold, rows, stats, calendar }) {
  const selected = selectedHousehold || {};
  const prevMonth = shiftMonthString(month, -1);
  const nextMonth = shiftMonthString(month, 1);
  const daily = {};
  for (const r of safeArray(rows)) {
    const d = String(r.transaction_date || "");
    if (!daily[d]) daily[d] = { expense: 0, income: 0, count: 0, rows: [] };
    if (r.type === "income") daily[d].income += Number(r.amount || 0); else daily[d].expense += Number(r.amount || 0);
    daily[d].count += 1;
    daily[d].rows.push(r);
  }
  const dayNames = ["일","월","화","수","목","금","토"];
  const maxDayExpense = Math.max(1, ...safeArray(calendar).map((d) => Number(d.expense || 0)));
  const heatLevel = (exp) => exp <= 0 ? 0 : Math.min(5, Math.max(1, Math.ceil(exp / maxDayExpense * 5)));
  const dayCard = (d, compact = false) => {
    const date = String(d.date || "");
    const dayName = dayNames[new Date(`${date}T00:00:00+09:00`).getDay()] || "";
    const has = Number(d.count || 0) > 0;
    return `<a class="day ${compact ? "compactDay" : ""} ${has ? "hasSpend" : "emptyDay"} heat${heatLevel(Number(d.expense || 0))}" href="#day-${escapeHtml(date)}" title="${escapeHtml(date)} 지출 ${numberWithCommas(d.expense || 0)}원 · ${numberWithCommas(d.count || 0)}건"><b>${escapeHtml(String(date).slice(8,10))}</b><em>${escapeHtml(dayName)}</em><span>${has ? escapeHtml(shortWonLabel(d.expense || 0)) : ""}</span><small>${has ? `${numberWithCommas(d.count || 0)}건` : ""}</small></a>`;
  };
  const activeDays = calendar.filter((d) => Number(d.count || 0) > 0);
  const activeDayCards = activeDays.map((d) => dayCard(d, true)).join("") || `<p class="muted">이번 달 기록이 있는 날짜가 없습니다.</p>`;
  const days = calendar.map((d) => dayCard(d)).join("");
  const detail = Object.entries(daily).filter(([,v])=>v.count).sort(([a],[b])=>a.localeCompare(b)).map(([date, v]) => `<section class="card dayDetail" id="day-${escapeHtml(date)}"><h2>${escapeHtml(date)} · ${numberWithCommas(v.expense)}원 · ${numberWithCommas(v.count)}건</h2>${v.rows.map((r)=>`<div class="record"><div><b>${escapeHtml(r.memo || r.raw_text || r.category || "기록")}</b><span>${escapeHtml(r.spender_name || "미지정")} · ${escapeHtml(r.category || "미분류")} · ${escapeHtml(r.payment_method || "")}</span></div><strong class="${r.type === "income" ? "income" : "expense"}">${r.type === "income" ? "+" : "-"}${numberWithCommas(r.amount)}원</strong></div>`).join("")}</section>`).join("") || `<section class="card">기록이 있는 날짜가 없습니다.</section>`;
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${escapeHtml(selected.name || "가계부")} · 캘린더</title><style>*,*:before,*:after{box-sizing:border-box}body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1180px;margin:0 auto;padding:16px}.hero,.card{background:#fff;border:1px solid #e5e7eb;border-radius:28px;padding:22px;margin:14px 0;box-shadow:0 12px 32px rgba(15,23,42,.06)}.hero{background:linear-gradient(135deg,#111827,#0f766e);color:#fff}.hero h1{margin:0;font-size:30px}.filters{display:grid;grid-template-columns:1fr 200px 120px 120px 120px;gap:8px;margin-top:14px}.filters select,.filters input,.filters button,.filters a{height:44px;border:1px solid #d1d5db;border-radius:14px;padding:0 12px;background:#fff;font:inherit;display:flex;align-items:center;justify-content:center;text-decoration:none;color:#111827}.filters button,.filters a.dark{background:#111827;color:#fff;font-weight:1000}.activeDayGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:8px}.fullCalendar summary{cursor:pointer;font-weight:1000;background:#f8fafc;border:1px solid #e5e7eb;border-radius:16px;padding:12px;margin-bottom:10px}.calendarGrid{display:grid;grid-template-columns:repeat(7,1fr);gap:8px}.day{display:grid;grid-template-columns:auto auto;align-content:start;text-decoration:none;color:#111827;background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:12px;min-height:96px;box-shadow:0 8px 18px rgba(15,23,42,.035)}.day.hasSpend{border-color:#99f6e4;background:#f0fdfa}.day.heat1{background:#f0fdfa;border-color:#ccfbf1}.day.heat2{background:#ccfbf1;border-color:#99f6e4}.day.heat3{background:#99f6e4;border-color:#5eead4}.day.heat4{background:#5eead4;border-color:#2dd4bf}.day.heat5{background:#2dd4bf;border-color:#14b8a6}.day.heat4 span,.day.heat5 span{color:#134e4a}.heatLegend{display:flex;align-items:center;gap:5px;color:#64748b;font-size:12px;font-weight:900;margin:8px 0}.heatLegend i{display:inline-block;width:20px;height:12px;border-radius:4px;border:1px solid #e5e7eb}.heatLegend i.h1{background:#f0fdfa}.heatLegend i.h2{background:#ccfbf1}.heatLegend i.h3{background:#99f6e4}.heatLegend i.h4{background:#5eead4}.heatLegend i.h5{background:#2dd4bf}.day.emptyDay{opacity:.58}.day b{font-size:22px;line-height:1}.day em{font-style:normal;justify-self:end;color:#64748b;font-size:12px;font-weight:900}.day span{grid-column:1/-1;display:block;color:#0f766e;font-weight:1000;margin-top:8px}.day small{grid-column:1/-1;display:block;color:#64748b;margin-top:2px}.record{display:flex;justify-content:space-between;gap:10px;border:1px solid #e5e7eb;border-radius:16px;padding:12px;margin:8px 0}.record span{display:block;color:#64748b;font-size:13px}.income{color:#059669}.expense{color:#dc2626}@media(max-width:760px){body{overflow-x:hidden}.wrap{padding:12px 10px 96px}.filters{grid-template-columns:1fr 1fr}.filters select{grid-column:1/-1}.filters select,.filters input,.filters button,.filters a{width:100%;font-size:15px}.calendarGrid{grid-template-columns:repeat(7,minmax(0,1fr));gap:4px}.day{min-height:58px;padding:7px 3px;grid-template-columns:1fr;align-content:start;justify-items:center;border-radius:11px;box-shadow:none}.day b{font-size:13px;line-height:1}.day em{display:none}.day span{grid-column:1/-1;margin-top:5px;font-size:10px;text-align:center;white-space:nowrap;max-width:100%;overflow:hidden;text-overflow:ellipsis}.day small{display:none}.record{display:block}.record strong{display:block;margin-top:6px}.hero{border-radius:22px;padding:18px}.hero h1{font-size:24px;line-height:1.25}.card{border-radius:20px;padding:16px}}</style></head><body>${renderUnifiedNav("calendar", { month, householdId: selected.id || "", householdName: selected.name || "가계부" })}<main class="wrap"><section class="hero"><h1>${escapeHtml(selected.name || "가계부")} 캘린더</h1><p>월 이동과 일별 지출금액/건수를 한 화면에서 확인합니다.</p><form class="filters" method="get" action="/calendar"><select name="household_id">${households.map((h)=>`<option value="${escapeHtml(h.id)}" ${h.id === selected.id ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("")}</select><input type="month" name="month" value="${escapeHtml(month)}"/><button type="submit">조회</button><a class="dark" href="/calendar?month=${encodeURIComponent(prevMonth)}&household_id=${encodeURIComponent(selected.id || "")}">이전달</a><a class="dark" href="/calendar?month=${encodeURIComponent(nextMonth)}&household_id=${encodeURIComponent(selected.id || "")}">다음달</a></form></section><section class="card"><h2>기록 있는 날짜</h2><div class="activeDayGrid">${activeDayCards}</div></section><section class="card"><details class="fullCalendar"><summary>전체 날짜 달력 펼쳐 보기</summary><div class="heatLegend">지출 적음 <i class="h1"></i><i class="h2"></i><i class="h3"></i><i class="h4"></i><i class="h5"></i> 많음 · 색이 진할수록 그날 지출이 큽니다</div><div class="calendarGrid">${days}</div></details></section>${detail}</main></body></html>`;
}

async function handlePcCalendarPage(request, env, url) {
  const ctx = await pcScopedContext(request, env, url);
  if (!ctx) return redirectResponse("/my");
  if (ctx.restricted) return myAccessStatusResponse({ env, user: ctx.user, household: ctx.restricted, role: ctx.restricted.role, month: ctx.month });
  return htmlResponse(renderPcCalendarHtml(ctx));
}

async function handleBudgetCenterPage(request, env, url) {
  const userId = await verifyUserSession(request, env);
  const adminOk = await verifyAdminSession(request, env);
  if (!userId && !adminOk) return redirectResponse("/my");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  let households = [];
  let householdId = "";
  let selected = null;
  if (userId) {
    const user = await fetchUserById(env, userId);
    const access = await getMySelectedHousehold(env, userId, url.searchParams.get("household_id") || "");
    if (access.restricted) return myAccessStatusResponse({ env, user, household: access.restricted, role: access.restricted.role, month });
    households = access.households;
    selected = access.selected;
    householdId = selected?.id || "";
  } else {
    households = await fetchAdminHouseholds(env);
    selected = selectScopedHousehold(households, url.searchParams.get("household_id") || "") || households[0] || null;
    householdId = selected?.id || "";
  }
  if (!selected) return redirectResponse(userId ? "/my/households?err=no_household" : "/?legacy=1");
  const canManage = adminOk || ["owner", "admin"].includes(String(selected.role || "").toLowerCase());
  const members = await fetchHouseholdMembers(env, householdId);
  const rows = attachSpenderNames(await fetchAdminRows(env, { month, householdId, type: "all" }), members);
  const budgets = await fetchBudgets(env, householdId, month);
  const customCategories = await fetchCustomCategories(env, householdId);
  const center = budgetCenterSummary(rows, budgets);
  const incomePlans = incomeBudgetRows(budgets).filter((row) => Number(row.amount || 0) > 0);
  while (incomePlans.length < 2) incomePlans.push({ name: defaultIncomeBudgetNames()[incomePlans.length] || "기타수입", amount: 0 });
  const expensePlans = expenseBudgetRows(budgets, customCategories).filter((row) => Number(row.amount || 0) > 0);
  const editExpenses = expensePlans.length ? expensePlans : ["식비", "교통", "생활용품", "보험", "카페/간식"].map((name) => ({ name, amount: 0 }));
  const incomeOptions = [`<option value="">직접입력</option>`, ...defaultIncomeBudgetNames().map((name) => `<option value="${escapeHtml(name)}">${escapeHtml(name)}</option>`)].join("");
  const categoryNames = defaultExpenseBudgetNames(customCategories);
  const categoryOptions = [`<option value="">직접입력</option>`, ...categoryNames.map((name) => `<option value="${escapeHtml(name)}">${escapeHtml(name)}</option>`)].join("");
  const incomeInputs = incomePlans.slice(0, 8).map((row) => `<div class="planLine"><label>수입 종류<input name="income_name" value="${escapeHtml(row.name)}" placeholder="예: 급여, 상여, 부수입"/></label><label>빠른 선택<select class="pickValue">${incomeOptions}</select></label><label>예상 금액<input name="income_amount" inputmode="numeric" value="${Number(row.amount || 0) || ""}" placeholder="예: 2500000"/></label></div>`).join("");
  const expenseInputs = editExpenses.slice(0, 12).map((row) => `<div class="planLine"><label>지출 분류<input name="budget_category" value="${escapeHtml(row.name)}" placeholder="예: 식비, 교통"/></label><label>빠른 선택<select class="pickValue">${categoryOptions}</select></label><label>한도 금액<input name="budget_amount" inputmode="numeric" value="${Number(row.amount || 0) || ""}" placeholder="예: 500000"/></label></div>`).join("");
  const actualIncomeRows = center.actualIncomeCategories.length
    ? center.actualIncomeCategories.map((item) => `<li><span><b>${escapeHtml(item.category)}</b><small>${numberWithCommas(item.count)}건</small></span><strong>${numberWithCommas(item.amount)}원</strong></li>`).join("")
    : `<li class="empty">아직 이번 달 수입 기록이 없습니다.</li>`;
  const planIncomeRows = incomePlans.filter((row) => Number(row.amount || 0) > 0).length
    ? incomePlans.filter((row) => Number(row.amount || 0) > 0).map((row) => `<li><span><b>${escapeHtml(row.name)}</b><small>예상</small></span><strong>${numberWithCommas(row.amount)}원</strong></li>`).join("")
    : `<li class="empty">예상 수입을 종류별로 입력하면 여기에 합산됩니다.</li>`;
  const usageCards = expensePlans.length ? expensePlans.map((row) => {
    const usage = center.budget.categoryAlerts.find((item) => normalizeText(item.category) === normalizeText(row.name)) || { spent: 0, rate: 0 };
    const remain = Math.max(0, Number(row.amount || 0) - Number(usage.spent || 0));
    return `<article class="usageCard"><div><b>${escapeHtml(row.name)}</b><span>${budgetStatusLabel(usage.rate || 0)}</span></div><dl><div><dt>예산</dt><dd>${numberWithCommas(row.amount)}원</dd></div><div><dt>사용</dt><dd>${numberWithCommas(usage.spent)}원</dd></div><div><dt>남음</dt><dd>${numberWithCommas(remain)}원</dd></div></dl><div class="miniBar"><i style="width:${Math.min(100, Math.max(0, usage.rate || 0))}%"></i></div><small>사용률 ${numberWithCommas(usage.rate || 0)}%</small></article>`;
  }).join("") : `<div class="empty">지출 분류별 한도를 저장하면 사용 현황이 표시됩니다.</div>`;
  const legacyTotal = budgets.find((b) => String(b.category || "") === "__total") || null;
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${String(h.id) === String(householdId) ? "selected" : ""}>${escapeHtml(h.name || "가계부")}</option>`).join("");
  const msg = url.searchParams.get("msg") || "";
  const err = url.searchParams.get("err") || "";
  const hh = `month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}`;
  const planForm = canManage && userId ? `<section class="card" id="plan"><div class="sectionHead"><div><span class="eyebrow">종류·분류별 입력</span><h2>예상 수입과 지출 예산</h2></div><b>월 총액 직접입력 없음</b></div><p class="muted">급여·부수입 같은 수입 종류와 식비·교통 같은 지출 분류를 입력하면 각각 자동 합산됩니다. 0원이나 빈 행은 저장하지 않습니다.</p><form method="post" action="/my/budget-bulk/save" id="budgetPlanForm"><input type="hidden" name="household_id" value="${escapeHtml(householdId)}"/><input type="hidden" name="month" value="${escapeHtml(month)}"/><div class="planGrid"><div><h3>예상 수입 종류</h3><div id="incomeRows">${incomeInputs}</div><button type="button" class="addLine" data-add="income">+ 수입 종류 추가</button><p class="guide">실제 수입은 기록에서 자동 집계됩니다. 여기는 앞으로 들어올 예상 금액만 입력합니다.</p></div><div><h3>지출 분류별 한도</h3><div id="expenseRows">${expenseInputs}</div><button type="button" class="addLine" data-add="expense">+ 지출 분류 추가</button><p class="guide">분류별 금액의 합계가 이번 달 전체 지출 예산이 됩니다.</p></div></div><button class="savePlan" type="submit">종류별 수입·분류별 예산 저장</button></form></section>` : `<section class="card"><h2>예산 설정</h2><p class="muted">${canManage ? "관리자 세션에서는 사용자 계정으로 가계부를 연 뒤 종류·분류별 계획을 편집하세요." : "가계부 소유자 또는 관리자만 계획을 변경할 수 있습니다."}</p></section>`;
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${escapeHtml(appName(env))} · 수입·예산</title><style>*,*:before,*:after{box-sizing:border-box}html,body{max-width:100%;overflow-x:hidden}body{margin:0;background:#f6f7fb;color:#101828;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1100px;margin:0 auto;padding:16px 16px 126px}.hero,.card{background:#fff;border:1px solid #e5e7eb;border-radius:24px;padding:20px;margin:12px 0;box-shadow:0 12px 30px rgba(15,23,42,.055)}.hero h1{margin:0 0 7px;font-size:25px}.hero p,.muted{color:#667085;line-height:1.6}.filters{display:grid;grid-template-columns:minmax(0,1fr) 160px 100px;gap:8px;margin-top:14px}.filters select,.filters input,.filters button,.planLine input,.planLine select{width:100%;min-width:0;height:46px;border:1px solid #d0d5dd;border-radius:13px;padding:0 11px;background:#fff;font:inherit}.filters button,.savePlan,.addLine{border:0;border-radius:13px;background:#111827;color:#fff;font-weight:1000;padding:0 14px;min-height:44px}.metrics{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:14px;min-width:0}.metric span,.metric small{display:block;color:#667085;font-size:12px;font-weight:900}.metric b{display:block;font-size:23px;margin-top:5px;overflow-wrap:anywhere}.metric.actual{background:#ecfdf5;border-color:#bbf7d0}.metric.plan{background:#eff6ff;border-color:#bfdbfe}.twoCol{display:grid;grid-template-columns:1fr 1fr;gap:12px}.moneyList{list-style:none;padding:0;margin:0;display:grid;gap:7px}.moneyList li{display:flex;align-items:center;justify-content:space-between;gap:10px;border:1px solid #e5e7eb;border-radius:14px;padding:11px 12px}.moneyList li span b,.moneyList li span small{display:block}.moneyList li span small{color:#667085;margin-top:3px}.moneyList li strong{white-space:nowrap}.empty{display:block!important;background:#f8fafc;border:1px dashed #cbd5e1!important;color:#667085;padding:14px!important;border-radius:14px}.sectionHead{display:flex;align-items:flex-start;justify-content:space-between;gap:10px}.sectionHead h2{margin:7px 0 0}.sectionHead>b{background:#dcfce7;color:#166534;border-radius:999px;padding:7px 10px;font-size:12px;white-space:nowrap}.eyebrow{display:inline-flex;background:#fff7cc;color:#5c4700;border-radius:999px;padding:6px 9px;font-size:11px;font-weight:1000}.planGrid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.planLine{display:grid;grid-template-columns:1.1fr .9fr 1fr;gap:7px;margin:8px 0}.planLine label{display:grid;gap:5px;color:#475467;font-size:11px;font-weight:1000}.addLine{background:#eef2ff;color:#3730a3;min-height:40px}.guide{background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;border-radius:14px;padding:11px;font-size:12px;line-height:1.5}.savePlan{width:100%;margin-top:12px;min-height:50px}.usageGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:9px}.usageCard{border:1px solid #e5e7eb;border-radius:17px;padding:13px;min-width:0}.usageCard>div:first-child{display:flex;justify-content:space-between;gap:8px}.usageCard>div:first-child span{font-size:11px;font-weight:1000;color:#475569}.usageCard dl{display:grid;grid-template-columns:repeat(3,1fr);gap:5px;margin:12px 0}.usageCard dl div{min-width:0}.usageCard dt{font-size:10px;color:#667085}.usageCard dd{margin:3px 0 0;font-size:12px;font-weight:1000;overflow-wrap:anywhere}.miniBar{height:9px;background:#eef2f7;border-radius:999px;overflow:hidden}.miniBar i{display:block;height:100%;background:#3182f6;border-radius:999px}.usageCard>small{display:block;color:#667085;margin-top:6px}.notice{border-radius:14px;padding:11px}.notice.ok{background:#ecfdf5;color:#166534}.notice.error,.legacy{background:#fff7ed;color:#9a3412;border:1px solid #fed7aa}.legacy{border-radius:14px;padding:11px;font-size:12px;line-height:1.5}@media(max-width:760px){.wrap{padding:10px 10px 132px}.hero,.card{padding:16px;border-radius:19px}.filters,.planGrid,.twoCol{grid-template-columns:1fr}.metrics{grid-template-columns:1fr 1fr}.planLine{grid-template-columns:1fr}.planLine input,.planLine select,.filters select,.filters input{font-size:16px}.sectionHead{display:block}.sectionHead>b{display:inline-flex;margin-top:9px}.usageGrid{grid-template-columns:1fr}.metric b{font-size:20px}}@media(max-width:360px){.metrics{grid-template-columns:1fr}}</style></head><body>${renderUnifiedNav("budgets", { month, householdId, householdName: selected.name })}<main class="wrap"><section class="hero"><h1>수입·예산</h1><p>실제 수입은 기록에서 자동 합산하고, 예상 수입과 지출 예산은 종류·분류별 금액을 더해 계산합니다.</p><form class="filters" method="get" action="/budgets"><select name="household_id">${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month)}"/><button type="submit">조회</button></form></section>${msg ? `<div class="notice ok">${escapeHtml(householdPageMessage(msg))}</div>` : ""}${err ? `<div class="notice error">${escapeHtml(householdPageMessage(err))}</div>` : ""}<section class="metrics"><div class="metric actual"><span>실제 수입 · 기록 자동합계</span><b>${numberWithCommas(center.actualIncome)}원</b><small>${numberWithCommas(center.actualIncomeCategories.reduce((sum, item) => sum + item.count, 0))}건</small></div><div class="metric plan"><span>예상 수입 · 종류별 합계</span><b>${numberWithCommas(center.incomeBudget)}원</b><small>${numberWithCommas(incomePlans.filter((row) => Number(row.amount || 0) > 0).length)}종류</small></div><div class="metric"><span>지출 예산 · 분류별 합계</span><b>${numberWithCommas(center.totalBudget)}원</b><small>${numberWithCommas(expensePlans.length)}개 분류</small></div><div class="metric"><span>이번 달 지출</span><b>${numberWithCommas(center.budget.expense)}원</b><small>예산 사용 ${numberWithCommas(center.budget.rate || 0)}%</small></div><div class="metric"><span>남은 지출 예산</span><b>${numberWithCommas(Math.max(0, center.totalBudget - center.budget.expense))}원</b><small>${center.totalBudget ? "분류별 한도 기준" : "먼저 분류별 예산을 입력하세요"}</small></div><div class="metric"><span>실제 수입 - 실제 지출</span><b>${numberWithCommas(center.actualSavings)}원</b><small>기록 기준 단순 차액</small></div></section><section class="twoCol"><div class="card"><h2>실제 수입 분류</h2><p class="muted">수입으로 기록한 거래가 자동 합산됩니다.</p><ul class="moneyList">${actualIncomeRows}</ul></div><div class="card"><h2>예상 수입 종류</h2><p class="muted">앞으로 들어올 것으로 계획한 금액입니다.</p><ul class="moneyList">${planIncomeRows}</ul></div></section>${planForm}<section class="card"><h2>지출 분류별 사용 현황</h2><p class="muted">월 총액을 따로 정하지 않고 각 분류의 한도를 더해 전체 예산을 계산합니다.</p><div class="usageGrid">${usageCards}</div>${legacyTotal ? `<div class="legacy"><b>이전 버전의 월 총액 ${numberWithCommas(legacyTotal.amount)}원이 남아 있습니다.</b><br/>분류별 예산이 있으면 이 값은 계산에 사용하지 않습니다. 새 계획을 저장하면 자동으로 정리됩니다.</div>` : ""}</section><section class="card"><h2>계산 기준</h2><p class="muted">실제 수입 = 수입 거래 합계 · 예상 수입 = 수입 종류별 계획 합계 · 전체 지출 예산 = 지출 분류별 한도 합계 · 남은 예산 = 전체 지출 예산 - 실제 지출입니다.</p><p><a href="/app?${hh}">홈으로 돌아가기</a> · <a href="/my/settings?${hh}">정기지출·분류 키워드 설정</a></p></section></main><script>(function(){var incomeOptions=${JSON.stringify(incomeOptions)};var categoryOptions=${JSON.stringify(categoryOptions)};function bind(root){root.querySelectorAll('.pickValue').forEach(function(select){select.addEventListener('change',function(){var line=select.closest('.planLine');var input=line&&line.querySelector('input');if(input&&select.value)input.value=select.value;});});}function make(type){var div=document.createElement('div');div.className='planLine';if(type==='income'){div.innerHTML='<label>수입 종류<input name="income_name" placeholder="직접입력: 수입 종류"/></label><label>빠른 선택<select class="pickValue">'+incomeOptions+'</select></label><label>예상 금액<input name="income_amount" inputmode="numeric" placeholder="예상 수입"/></label>';}else{div.innerHTML='<label>지출 분류<input name="budget_category" placeholder="직접입력: 지출 분류"/></label><label>빠른 선택<select class="pickValue">'+categoryOptions+'</select></label><label>한도 금액<input name="budget_amount" inputmode="numeric" placeholder="예산 금액"/></label>';}bind(div);return div;}document.querySelectorAll('[data-add]').forEach(function(button){button.addEventListener('click',function(){var type=button.getAttribute('data-add');document.getElementById(type==='income'?'incomeRows':'expenseRows').appendChild(make(type));});});bind(document);})();</script></body></html>`);
}

async function handleBudgetCenterPageLegacyV2264(request, env, url) {
  const userId = await verifyUserSession(request, env);
  const adminOk = await verifyAdminSession(request, env);
  if (!userId && !adminOk) return redirectResponse("/my");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  let households = [];
  let householdId = "";
  if (userId) {
    const user = await fetchUserById(env, userId);
    const access = await getMySelectedHousehold(env, userId, url.searchParams.get("household_id") || "");
    if (access.restricted) return myAccessStatusResponse({ env, user, household: access.restricted, role: access.restricted.role, month });
    households = access.households;
    householdId = access.selected?.id || "";
  } else {
    households = await fetchAdminHouseholds(env);
    householdId = selectScopedHousehold(households, url.searchParams.get("household_id") || "")?.id || "";
  }
  const canManage = adminOk || ["owner", "admin"].includes(String((households.find((h) => String(h.id) === String(householdId)) || {}).role || "").toLowerCase());
  const msg = url.searchParams.get("msg") || "";
  const err = url.searchParams.get("err") || "";
  const customCategoryRows = await fetchCustomCategories(env, householdId);
  const members = householdId ? await fetchHouseholdMembers(env, householdId) : [];
  const rows = attachSpenderNames(await fetchAdminRows(env, { month, householdId, type: "all" }), members);
  const budgets = await fetchBudgets(env, householdId, month);
  const center = budgetCenterSummary(rows, budgets);
  const totalBudgetRow = budgets.find((b) => String(b.category || "") === "__total") || {};
  const incomeBudgetRow = budgets.find((b) => String(b.category || "") === "__income") || {};
  const hh = householdId ? `&household_id=${encodeURIComponent(householdId)}` : "";
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const categoryOptions = mergedOptions(DEFAULT_CATEGORIES, customCategoryRows.map((c) => c.name)).map((c) => `<option value="${escapeHtml(c)}">${escapeHtml(c)}</option>`).join("");
  const incomeOptions = CATEGORY_KEYWORD_GUIDE.filter((g) => g.type === "income").map((g) => `<option value="__income:${escapeHtml(g.category)}">${escapeHtml(g.category)} 수입 기준</option>`).join("");
  const budgetBasisList = renderBudgetBasisRows(budgets);
  const budgetConsistency = renderBudgetConsistencyAlert(budgets, center);
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>예산 관리</title><style>*,*::before,*::after{box-sizing:border-box}body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1160px;margin:0 auto;padding:16px}.hero{background:linear-gradient(135deg,#111827,#7c3aed);color:#fff;border-radius:28px;padding:22px;margin:12px 0;box-shadow:0 18px 42px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:29px}.hero p{line-height:1.55;opacity:.92}.filters,.formGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px;margin-top:12px}.filters select,.filters input,.filters button,.formGrid input,.formGrid select,.formGrid button{height:44px;border:1px solid #d1d5db;border-radius:14px;padding:0 12px;background:#fff;font:inherit}.filters button,.formGrid button{background:#111827;color:#fff;font-weight:1000}.card{background:#fff;border:1px solid #e5e7eb;border-radius:24px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.metricGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:20px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:24px;margin-top:5px}.modeTag{display:inline-block;font-style:normal;font-size:11px;font-weight:1000;border-radius:999px;padding:2px 7px;margin-left:4px;vertical-align:1px}.modeTag.auto{background:#dcfce7;color:#166534}.modeTag.manual{background:#eff6ff;color:#1e3a8a}.bar{height:14px;background:#e5e7eb;border-radius:999px;overflow:hidden}.bar i{display:block;height:100%;width:var(--w);background:#3182F6;border-radius:999px}.basisGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:12px;margin-top:12px}.basisGrid>div{background:#f8fafc;border:1px solid #e5e7eb;border-radius:20px;padding:14px;min-width:0}.basisGrid h3{margin:0 0 10px;font-size:17px}.basisGrid ul{list-style:none;padding:0;margin:0;display:grid;gap:8px}.basisGrid li{display:grid;grid-template-columns:minmax(0,1fr) auto;align-items:center;gap:10px;background:#fff;border:1px solid #e5e7eb;border-radius:14px;padding:10px 12px}.basisGrid li b{word-break:keep-all;line-height:1.25}.basisGrid li span{white-space:nowrap;font-weight:1000}.budgetWarn,.budgetOk{border-radius:18px;padding:14px;margin:12px 0;display:grid;gap:5px;line-height:1.45}.budgetWarn{background:#fff7ed;border:1px solid #fdba74;color:#9a3412}.budgetOk{background:#ecfdf5;border:1px solid #86efac;color:#166534}.budgetWarn b,.budgetOk b{font-size:17px}.budgetWarn span,.budgetOk span{font-weight:900}.budgetWarn small{color:#9a3412}.tableWrap{overflow-x:auto}.catUse summary{cursor:pointer;font-weight:1000}.catUse small{display:block;color:#64748b;margin-top:3px}.budgetTree{margin-top:10px;display:grid;gap:7px}.memberUse{background:#f8fafc;border:1px solid #e5e7eb;border-radius:14px;padding:8px}.memberUse summary{cursor:pointer;color:#111827}.memberUse ul{list-style:none;margin:8px 0 0;padding:0;display:grid;gap:5px}.memberUse li{display:grid;grid-template-columns:92px 90px 1fr;gap:8px;font-size:12px;color:#475569}.memberUse li b{color:#111827}.memberUse li em{font-style:normal}.emptyTree{color:#64748b;background:#f8fafc;border:1px dashed #cbd5e1;border-radius:12px;padding:10px}table{width:100%;border-collapse:collapse;min-width:820px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px}.status{display:inline-flex;border-radius:999px;padding:5px 9px;font-weight:1000;font-size:12px}.status.ok{background:#dcfce7;color:#166534}.status.warn{background:#fff7ed;color:#9a3412}.status.bad{background:#fee2e2;color:#991b1b}.mini{height:32px;border:0;border-radius:10px;padding:0 10px;font-weight:900}.danger{background:#fee2e2;color:#991b1b}.okmsg{background:#e8f1e9;color:#365b41;border:1px solid #c9decf;border-radius:12px;padding:10px}.errmsg{background:#f7e8e4;color:#8f463d;border:1px solid #e7c4bd;border-radius:12px;padding:10px}.tip{background:#ecfdf5;border:1px solid #a7f3d0;color:#065f46;border-radius:16px;padding:12px;line-height:1.55}@media(max-width:760px){body{overflow-x:hidden}.wrap{padding:12px 10px 96px}.hero{border-radius:22px;padding:18px}.hero h1{font-size:24px;line-height:1.25}.formGrid,.filters{grid-template-columns:1fr}.formGrid input,.formGrid select,.formGrid button,.filters input,.filters select,.filters button{width:100%;font-size:16px;min-height:46px}.card{border-radius:20px;padding:16px}.metricGrid,.basisGrid{grid-template-columns:1fr}.tableWrap{overflow-x:auto;-webkit-overflow-scrolling:touch}table{min-width:760px}.memberUse li{grid-template-columns:1fr;gap:3px}}</style></head><body>${renderUnifiedNav("budgets", { month, householdId, householdName: (households.find((h)=>h.id===householdId)||{}).name })}<main class="wrap"><section class="hero"><h1>예산 관리</h1><p>월 수입 기준으로 전체 예산을 얼마까지 잡았는지 보고, 분류별 예산의 사용금액·잔여금액·사용률을 한눈에 관리합니다.</p><form class="filters" method="get" action="/budgets"><select name="household_id">${householdOptions}</select><input type="month" name="month" value="${escapeHtml(month)}"/><button type="submit">조회</button></form></section>${msg ? `<div class="okmsg">${formatMessage(msg)}</div>` : ""}${err ? `<div class="errmsg">${escapeHtml(err)}</div>` : ""}<section class="metricGrid"><div class="metric"><span>월 수입 기준</span><b>${numberWithCommas(center.incomeBase)}원</b></div><div class="metric"><span>이번 달 예산 ${center.budget.explicitTotalBudget ? `<i class="modeTag manual">직접 설정</i>` : `<i class="modeTag auto">분류 합계 자동</i>`}</span><b>${numberWithCommas(center.totalBudget)}원</b></div><div class="metric"><span>수입 대비 예산</span><b>${center.budgetIncomeRate}%</b></div><div class="metric"><span>남은 배정 가능 예산</span><b>${numberWithCommas(center.freeAfterBudget)}원</b></div><div class="metric"><span>이번 달 지출</span><b>${numberWithCommas(center.budget.expense)}원</b></div><div class="metric"><span>예산 사용률</span><b>${center.budget.rate || 0}%</b></div></section><section class="card"><h2>수입 대비 예산 비율</h2><div class="bar"><i style="--w:${Math.min(100, Math.max(0, center.budgetIncomeRate))}%"></i></div><p class="tip">월 수입 기준을 입력하면 예산이 수입의 몇 %인지 볼 수 있습니다. 수입 기준을 비워두면 이번 달 기록된 수입을 기준으로 계산합니다.</p></section><section class="card"><h2>월 기준 설정</h2><p class="note">월 예산은 <b>분류별 예산 합계로 자동 산정</b>되므로 따로 설정하지 않아도 됩니다. 수입 기준(이번 달 들어올 돈)만 입력해도 충분하고, 월 전체 예산 직접 설정은 분류 합계와 다르게 잡고 싶을 때만 쓰는 선택 항목입니다. 직접입력을 선택했을 때만 이름 입력칸이 열립니다.</p>${canManage ? `<form class="formGrid smartBudgetForm" method="post" action="/admin/budget/save"><input type="hidden" name="household_id" value="${escapeHtml(householdId)}"/><input type="hidden" name="month" value="${escapeHtml(month)}"/><input type="hidden" name="return_to" value="/budgets?month=${escapeHtml(month)}${escapeHtml(hh)}"/><label>설정 항목<select name="category" class="jsBudgetKind"><option value="__income">월 수입 기준 합계</option>${incomeOptions}<option value="__income_custom">수입 기준 직접입력</option><option value="__total">월 전체 예산 직접 설정 (선택)</option></select></label><label class="jsCustomWrap" hidden>직접입력 이름<input name="category_custom" disabled placeholder="예: 상여, 부수입"/></label><label>금액<input name="amount" inputmode="numeric" placeholder="예: 3500000" value=""/></label><button type="submit">기준 저장</button></form>` : `<p class="note">예산 기준 저장은 가계부 owner/admin만 할 수 있습니다.</p>`}<p class="tip">현재 월 수입 기준 합계: ${numberWithCommas(center.incomeBudget || 0)}원 · 분류별 예산 합계(자동): ${numberWithCommas(center.budget.categoryBudgetTotal || 0)}원${Number(totalBudgetRow.amount || 0) ? ` · 직접 설정한 월 전체 예산: ${numberWithCommas(totalBudgetRow.amount)}원` : ""}</p>${Number(totalBudgetRow.amount || 0) && canManage ? `<form method="post" action="/admin/budget/delete" onsubmit="return confirm('직접 설정한 월 전체 예산을 지우고 분류별 합계 자동 산정으로 전환할까요?')"><input type="hidden" name="household_id" value="${escapeHtml(householdId)}"/><input type="hidden" name="month" value="${escapeHtml(month)}"/><input type="hidden" name="category" value="__total"/><input type="hidden" name="return_to" value="/budgets?month=${escapeHtml(month)}${escapeHtml(hh)}"/><button type="submit" class="mini" style="background:#eff6ff;color:#1e3a8a">자동 산정(분류 합계)으로 전환</button></form>` : ""}${budgetConsistency}${budgetBasisList}</section><section class="card"><h2>분류별 예산 추가</h2><p class="note">먼저 기존 분류를 선택하거나, 맨 아래 “분류 직접입력”을 선택하면 이름 입력칸이 열립니다.</p>${canManage ? `<form class="formGrid smartBudgetForm" method="post" action="/admin/budget/save"><input type="hidden" name="household_id" value="${escapeHtml(householdId)}"/><input type="hidden" name="month" value="${escapeHtml(month)}"/><input type="hidden" name="return_to" value="/budgets?month=${escapeHtml(month)}${escapeHtml(hh)}"/><label>분류<select name="category" class="jsBudgetKind">${categoryOptions}<option value="__category_custom">분류 직접입력</option></select></label><label class="jsCustomWrap" hidden>직접입력 분류명<input name="category_custom" disabled placeholder="예: 아이간식, 반려동물, 병원비"/></label><label>예산 금액<input name="amount" inputmode="numeric" placeholder="예: 500000"/></label><button type="submit">분류 예산 저장</button></form>` : `<p class="note">분류별 예산 추가는 가계부 owner/admin만 할 수 있습니다.</p>`}<p class="tip">분류별 사용 현황은 아래에서 분류명을 눌러 상세를 확인하세요.</p></section><section class="card"><h2>분류별 사용 현황</h2><p class="note">분류명을 눌러 멤버별 사용 합계를 보고, 멤버명을 한 번 더 누르면 날짜·금액·항목이 표시됩니다.</p><div class="tableWrap"><table><thead><tr><th>분류/상세</th><th>예산</th><th>사용</th><th>남음</th><th>사용률</th><th>상태</th><th>관리</th></tr></thead><tbody>${renderBudgetRows(budgets, center.budget, rows, canManage)}</tbody></table></div></section><script>const BUDGET_CTX={catTotal:${Number(center.budget.categoryBudgetTotal || 0)},incomeBase:${Number(center.incomeBase || 0)},explicitTotal:${Number(center.budget.explicitTotalBudget || 0)}};document.querySelectorAll(".smartBudgetForm").forEach((form)=>{const sel=form.querySelector(".jsBudgetKind");const wrap=form.querySelector(".jsCustomWrap");const input=wrap&&wrap.querySelector("input");function sync(){const v=sel?.value||"";const on=v==="__income_custom"||v==="__category_custom";if(wrap){wrap.hidden=!on;}if(input){input.disabled=!on;if(!on)input.value="";}}sel&&sel.addEventListener("change",sync);sync();form.addEventListener("submit",(e)=>{const kind=sel?.value||"";const amtEl=form.querySelector("input[name=amount]");const amt=Number(String(amtEl?.value||"").replace(/[^0-9]/g,""))||0;if(!amt)return;const won=(n)=>n.toLocaleString("ko-KR")+"원";if(kind&&!kind.startsWith("__")||kind==="__category_custom"){const nextTotal=BUDGET_CTX.catTotal+amt;const limit=BUDGET_CTX.explicitTotal||BUDGET_CTX.incomeBase;if(limit&&nextTotal>limit){const over=nextTotal-limit;const base=BUDGET_CTX.explicitTotal?"직접 설정한 월 전체 예산":"월 수입 기준";if(!confirm("⚠️ 예산 초과 경고\\n\\n이 예산을 저장하면 분류별 예산 합계("+won(nextTotal)+")가 "+base+"("+won(limit)+")를 "+won(over)+" 초과합니다.\\n\\n그래도 저장할까요?")){e.preventDefault();}}}else if(kind==="__total"&&BUDGET_CTX.incomeBase&&amt>BUDGET_CTX.incomeBase){if(!confirm("⚠️ 월 전체 예산("+won(amt)+")이 월 수입 기준("+won(BUDGET_CTX.incomeBase)+")보다 큽니다.\\n\\n그래도 저장할까요?")){e.preventDefault();}}});});</script></main></body></html>`);
}

async function handleRecurringSave(request, env) {
  const form = await request.formData();
  const _hh = String(form.get("household_id") || "").trim();
  const _month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const _access = await resolveTransactionAccess(request, env, _hh, { manageOnly: true });
  if (!_access.ok) {
    if (!_access.admin && _access.userId) return redirectResponse(`/app?month=${encodeURIComponent(_month)}&household_id=${encodeURIComponent(_hh)}&err=${encodeURIComponent("고정지출 저장 권한이 없습니다.")}#fixed`);
    return redirectResponse("/?legacy=1");
  }
  const householdId = String(form.get("household_id") || "").trim();
  const returnTo = safeAdminReturnPath(form.get("return_to") || "", "/app#fixed");
  const members = await fetchHouseholdMembers(env, householdId);
  const spenderId = String(form.get("user_id") || "").trim();
  const row = {
    household_id: householdId,
    type: String(form.get("type") || "expense") === "income" ? "income" : "expense",
    amount: Math.max(0, Math.round(Number(form.get("amount") || 0))),
    category: String(form.get("category") || "기타").slice(0, 80),
    memo: String(form.get("memo") || "").slice(0, 160),
    payment_method: String(form.get("payment_method") || "").slice(0, 40),
    day_of_month: Math.min(28, Math.max(1, Math.round(Number(form.get("day_of_month") || 1)))),
    user_id: spenderId,
    is_active: true,
  };
  if (!row.amount) return redirectResponse(addQueryToUrl(returnTo, { err: "고정항목 금액을 입력하세요." }));
  if (!spenderId || !memberExists(members, spenderId)) return redirectResponse(addQueryToUrl(returnTo, { err: "고정항목의 지출자를 가계부 참여자 중에서 선택하세요." }));
  try {
    await supabase(env, "/rest/v1/accountbook_recurring", { method: "POST", headers: { Prefer: "return=minimal" }, body: JSON.stringify(row) });
    return redirectResponse(addQueryToUrl(returnTo, { msg: "recurring_saved" }));
  } catch (err) {
    rememberOpsEvent({ kind: "recurring_save_failed", severity: "warn", path: "/admin/recurring/save", method: "POST", detail: safeError(err) });
    return redirectResponse(addQueryToUrl(returnTo, { err: "고정항목을 저장하지 못했습니다. 기존 항목은 유지되므로 잠시 후 다시 시도해 주세요." }));
  }
}

async function handleRecurringDelete(request, env) {
  const form = await request.formData();
  const _hh = String(form.get("household_id") || "").trim();
  const _month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const _access = await resolveTransactionAccess(request, env, _hh, { manageOnly: true });
  if (!_access.ok) {
    if (!_access.admin && _access.userId) return redirectResponse(`/app?month=${encodeURIComponent(_month)}&household_id=${encodeURIComponent(_hh)}&err=${encodeURIComponent("고정지출 삭제 권한이 없습니다.")}#fixed`);
    return redirectResponse("/?legacy=1");
  }
  const id = String(form.get("id") || "");
  const returnTo = safeAdminReturnPath(form.get("return_to") || "", "/app#fixed");
  if (!id) return redirectResponse(addQueryToUrl(returnTo, { err: "삭제할 고정항목이 없습니다." }));
  try {
    const deleted = await supabase(env, `/rest/v1/accountbook_recurring?id=eq.${encodeURIComponent(id)}&household_id=eq.${encodeURIComponent(_hh)}`, { method: "DELETE", headers: { Prefer: "return=representation" } });
    if (!Array.isArray(deleted) || !deleted.length) throw new Error("recurring_not_found");
    return redirectResponse(addQueryToUrl(returnTo, { msg: "recurring_deleted" }));
  } catch (err) {
    rememberOpsEvent({ kind: "recurring_delete_failed", severity: "warn", path: "/recurring/delete", method: "POST", detail: safeError(err) });
    return redirectResponse(addQueryToUrl(returnTo, { err: "고정항목을 삭제하지 못했습니다. 기존 항목은 유지됩니다." }));
  }
}

async function handleRecurringApply(request, env) {
  const form = await request.formData();
  const _hh = String(form.get("household_id") || "").trim();
  const _month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const _access = await resolveTransactionAccess(request, env, _hh, { manageOnly: true });
  if (!_access.ok) {
    if (!_access.admin && _access.userId) return redirectResponse(`/app?month=${encodeURIComponent(_month)}&household_id=${encodeURIComponent(_hh)}&err=${encodeURIComponent("고정지출 반영 권한이 없습니다.")}#fixed`);
    return redirectResponse("/?legacy=1");
  }
  const householdId = String(form.get("household_id") || "");
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const returnTo = safeAdminReturnPath(form.get("return_to") || "", `/app?month=${month}&household_id=${encodeURIComponent(householdId)}#fixed`);
  try {
    const result = await supabase(env, "/rest/v1/rpc/accountbook_apply_recurring_v227", {
      method: "POST",
      headers: { Prefer: "return=representation" },
      body: JSON.stringify({ p_household_id: householdId, p_month: month }),
    });
    const summary = Array.isArray(result) ? result[0] : result;
    const count = Math.max(0, Number(summary?.inserted || 0));
    return redirectResponse(addQueryToUrl(returnTo, { msg: `고정항목 ${count}건 기록` }));
  } catch (err) {
    rememberOpsEvent({ kind: "recurring_atomic_apply_failed", severity: "warn", path: "/recurring/apply", method: "POST", detail: safeError(err) });
    const message = /recurring_spender_required/.test(safeError(err)) ? "고정항목의 지출자를 먼저 지정하세요." : "고정항목 반영을 완료하지 못했습니다. 기존 기록은 변경하지 않았습니다.";
    return redirectResponse(addQueryToUrl(returnTo, { err: message }));
  }
}

function addQueryToUrl(path, params = {}) {
  const u = new URL(path, "https://local");
  for (const [k, v] of Object.entries(params)) if (v !== undefined && v !== "") u.searchParams.set(k, String(v));
  return `${u.pathname}${u.search}${u.hash}`;
}












function renderMyStartChoiceHtml({ env, user, msg = "", err = "" }) {
  const title = escapeHtml(appName(env));
  const userName = escapeHtml(user?.nickname || "카카오사용자");
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 가계부 시작</title><style>
  *,*:before,*:after{box-sizing:border-box}body{margin:0;background:linear-gradient(180deg,#fff9d9 0%,#f8fafc 48%,#eef2f7 100%);color:#101828;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif;letter-spacing:-.025em}.wrap{max-width:1000px;margin:0 auto;padding:18px}.hero{background:#fff;border:1px solid #e8edf4;border-radius:32px;box-shadow:0 22px 54px rgba(15,23,42,.09);padding:26px;margin:16px 0}.badge{display:inline-flex;background:#FEE500;color:#191919;border-radius:999px;padding:7px 11px;font-size:13px;font-weight:1000}.hero h1{margin:14px 0 10px;font-size:32px;letter-spacing:-.06em}.muted{color:#667085;line-height:1.6}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.card{background:#fff;border:1px solid #e8edf4;border-radius:28px;padding:22px;box-shadow:0 14px 34px rgba(15,23,42,.055)}.card h2{margin:0 0 8px;font-size:22px}.field{display:grid;gap:7px;margin:14px 0}.field label{font-size:12px;font-weight:1000;color:#475467}.field input{height:48px;border:1px solid #d0d5dd;background:#fff;border-radius:16px;padding:0 13px;font:inherit}.btn,button{display:inline-flex;align-items:center;justify-content:center;min-height:48px;border:0;border-radius:16px;background:#111827;color:#fff;font-weight:1000;padding:0 16px;text-decoration:none;cursor:pointer;width:100%}.secondary{background:#eef2f7!important;color:#111827!important;border:1px solid #d8dee8}.criteria{background:#f8fafc;border:1px solid #edf1f7;border-radius:18px;padding:13px;margin:12px 0}.criteria b{display:block}.criteria span{display:block;color:#667085;font-size:13px;line-height:1.5;margin-top:4px}.ok{background:#ecfdf5;color:#166534;border:1px solid #bbf7d0;border-radius:14px;padding:11px;margin:10px 0}.error{background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;border-radius:14px;padding:11px;margin:10px 0}.foot{background:#fffdf3;border:1px solid #fde68a;color:#854d0e;border-radius:20px;padding:14px;margin:14px 0;line-height:1.6}@media(max-width:760px){.wrap{padding:12px}.grid{grid-template-columns:1fr}.hero h1{font-size:26px}}</style></head><body><main class="wrap"><section class="hero"><span class="badge">가계부 시작</span><h1>${userName}님,<br/>새로 만들까요? 참여할까요?</h1><p class="muted">아래 두 가지 중 현재 상황에 맞는 것을 선택하세요. 잘못 선택해도 나중에 다른 가계부를 추가하거나 초대코드로 다시 참여할 수 있습니다.</p>${msg ? `<div class="ok">${formatMessage(msg)}</div>` : ""}${err ? `<div class="error">${formatMessage(err)}</div>` : ""}</section><section class="grid"><div class="card"><h2>새 가계부 만들기</h2><p class="muted">아직 가계부가 없거나, 내가 우리집/모임 가계부의 시작자가 되는 경우입니다.</p><div class="criteria"><b>이럴 때 선택</b><span>내가 가계부를 만들고 구성원을 초대한 뒤 첫 기록부터 시작할 때</span></div><form method="post" action="/my/create"><div class="field"><label>가계부 이름</label><input name="household_name" placeholder="예: 우리집 가계부" value="우리집 가계부"/></div><button type="submit">새 가계부 만들기</button></form></div><div class="card"><h2>초대코드로 참여하기</h2><p class="muted">가족, 배우자, 모임장이 이미 만든 가계부가 있는 경우입니다.</p><div class="criteria"><b>이럴 때 선택</b><span>이미 받은 초대코드가 있고 같은 가계부에 내 기록을 함께 남길 때</span></div><form method="post" action="/my/join"><div class="field"><label>초대코드</label><input name="invite_code" placeholder="예: 38NDLPNR" required/></div><button class="secondary" type="submit">초대코드로 참여하기</button></form></div></section><div class="foot"><b>다음 단계</b><br/>가계부 생성 또는 참여 → 구성원 초대·승인 → 단톡방 연결(선택) → 기록 방법 확인 → 첫 기록 순서로 진행하세요. 예산과 분류는 첫 기록 후 필요할 때 설정해도 됩니다.</div></main></body></html>`;
}


function localWebUserKey(nickname = "", accessCode = "") {
  const seed = `${normalizeText(nickname)}|${String(accessCode || "").trim()}`;
  return `local_web:${stableShortHash(seed)}`;
}

async function ensureLocalLoginUser(env, nickname = "", accessCode = "") {
  return await findUserByLocalLoginIdentity(env, nickname, accessCode);
}

async function createLocalLoginUser(env, loginName = "", displayName = "", accessCode = "") {
  const cleanLoginName = String(loginName || "").normalize("NFKC").trim().replace(/\s+/g, " ").slice(0, 80);
  const cleanDisplayName = String(displayName || cleanLoginName).normalize("NFKC").trim().replace(/\s+/g, " ").slice(0, 80);
  const cleanCode = String(accessCode || "").trim();
  if (normalizeLocalLoginName(cleanLoginName).length < 2) throw new Error("invalid_login_name");
  if (cleanCode.length < 8) throw new Error("password_too_short");
  const salt = newPasswordSalt();
  const hash = await pbkdf2PasswordHash(cleanCode, salt, PASSWORD_KDF_ITERATIONS);
  const result = await supabase(env, "/rest/v1/rpc/accountbook_create_local_user_v227", {
    method: "POST",
    headers: { Prefer: "return=representation" },
    body: JSON.stringify({
      p_login_name: cleanLoginName,
      p_nickname: cleanDisplayName,
      p_credential_hash: hash,
      p_credential_salt: salt,
      p_credential_iterations: PASSWORD_KDF_ITERATIONS,
    }),
  });
  return Array.isArray(result) ? result[0] : result;
}

async function handleMyLocalLogin(request, env) {
  const form = await request.formData();
  const nickname = String(form.get("login_name") || form.get("nickname") || "").trim().slice(0, 80);
  const accessCode = String(form.get("access_code") || "").trim();
  const inviteCode = String(form.get("invite_code") || "").trim().toUpperCase();
  if (!nickname) return htmlResponse(renderUserLoginHtml(env, "로그인 이름을 입력하세요."), 400);
  if (accessCode.length < 4) return htmlResponse(renderUserLoginHtml(env, "비밀번호를 4자리 이상 입력하세요."), 400);
  const attempt = await recordAuthAttempt(env, request, "/my/local-login", false);
  if (!attempt.allowed) return htmlResponse(renderUserLoginHtml(env, "로그인 시도가 너무 많습니다. 잠시 후 다시 시도하세요."), 429, { "retry-after": "900" });
  try {
    const user = await ensureLocalLoginUser(env, nickname, accessCode);
    if (!user?.id) return htmlResponse(renderUserLoginHtml(env, "로그인 이름 또는 비밀번호가 맞지 않습니다. 처음이라면 새 계정 만들기를 이용하세요."), 401);
    await recordAuthAttempt(env, request, "/my/local-login", true);
    let location = "/my";
    if (inviteCode) {
      const joined = await joinHouseholdByCode(env, user.id, inviteCode);
      location = joined
        ? `/my?household_id=${encodeURIComponent(joined.id)}&msg=${joined.join_role === "pending" ? "approval_pending" : "joined"}`
        : `/my/households?err=${encodeURIComponent("초대코드를 찾지 못했습니다. 로그인은 완료되었습니다.")}`;
    }
    const session = await makeUserSession(env, user.id);
    return redirectResponse(location, {
      "set-cookie": `ab_user=${encodeURIComponent(session)}; Path=/; Max-Age=1209600; HttpOnly; Secure; SameSite=Lax`,
    });
  } catch (err) {
    const missingSecret = /USER_SESSION_SECRET/.test(safeError(err));
    return htmlResponse(renderUserLoginHtml(env, missingSecret ? "운영 보안키가 설정되지 않아 로그인할 수 없습니다." : "로그인을 처리하지 못했습니다. 잠시 후 다시 시도하세요."), missingSecret ? 503 : 500);
  }
}

async function handleMyLocalSignup(request, env) {
  const form = await request.formData();
  const loginName = String(form.get("login_name") || "").trim().slice(0, 80);
  const displayName = String(form.get("display_name") || loginName).trim().slice(0, 80);
  const accessCode = String(form.get("access_code") || "").trim();
  const confirm = String(form.get("access_code_confirm") || "").trim();
  const inviteCode = String(form.get("invite_code") || "").trim().toUpperCase();
  if (normalizeLocalLoginName(loginName).length < 2) return htmlResponse(renderUserLoginHtml(env, "로그인 이름은 2자 이상 입력하세요."), 400);
  if (!displayName) return htmlResponse(renderUserLoginHtml(env, "가계부에 표시할 이름을 입력하세요."), 400);
  if (accessCode.length < 8) return htmlResponse(renderUserLoginHtml(env, "새 비밀번호는 8자리 이상 입력하세요."), 400);
  if (accessCode !== confirm) return htmlResponse(renderUserLoginHtml(env, "비밀번호 확인이 일치하지 않습니다."), 400);
  const attempt = await recordAuthAttempt(env, request, "/my/local-signup", false);
  if (!attempt.allowed) return htmlResponse(renderUserLoginHtml(env, "계정 생성 시도가 너무 많습니다. 잠시 후 다시 시도하세요."), 429, { "retry-after": "900" });
  try {
    const user = await createLocalLoginUser(env, loginName, displayName, accessCode);
    if (!user?.id) throw new Error("local_signup_failed");
    await recordAuthAttempt(env, request, "/my/local-signup", true);
    let location = "/my/households?first=1";
    if (inviteCode) {
      const joined = await joinHouseholdByCode(env, user.id, inviteCode);
      location = joined
        ? `/my?household_id=${encodeURIComponent(joined.id)}&msg=${joined.join_role === "pending" ? "approval_pending" : "joined"}`
        : `/my/households?first=1&err=${encodeURIComponent("초대코드를 찾지 못했습니다. 계정은 생성되었습니다.")}`;
    }
    const session = await makeUserSession(env, user.id);
    return redirectResponse(location, {
      "set-cookie": `ab_user=${encodeURIComponent(session)}; Path=/; Max-Age=1209600; HttpOnly; Secure; SameSite=Lax`,
    });
  } catch (err) {
    const detail = safeError(err);
    const message = /login_name_in_use|duplicate key|409/i.test(detail)
      ? "이미 사용 중인 로그인 이름입니다. 다른 이름을 선택하세요."
      : /schema|accountbook_create_local_user_v227|PGRST202|404/i.test(detail)
        ? "V22.7 인증 마이그레이션을 먼저 적용해야 새 계정을 만들 수 있습니다."
        : /USER_SESSION_SECRET/.test(detail)
          ? "운영 보안키가 설정되지 않아 계정을 만들 수 없습니다."
          : "계정을 만들지 못했습니다. 입력값을 확인하고 다시 시도하세요.";
    return htmlResponse(renderUserLoginHtml(env, message), /schema|PGRST202|USER_SESSION_SECRET/.test(detail) ? 503 : 409);
  }
}


function kakaoLoginStatusBlock(env) {
  const config = inspectKakaoLoginConfig(env);
  if (config.ready) {
    return `<a class="kakaoBtn" href="/auth/kakao/start">💬 카카오로 로그인하기</a><div class="notice"><b>가장 간편한 방법</b><br/>카카오 계정으로 로그인하면 참여 중인 가계부를 바로 이어서 사용할 수 있습니다.</div><div class="sep">다른 방법으로 접속</div>`;
  }
  if (!config.enabled) {
    return `<div class="warn"><b>카카오 로그인을 잠시 사용할 수 없어요</b><br/>기존 로그인 이름과 내 계정 로그인 비밀번호로 접속할 수 있습니다.</div><div class="mobileAccessHelp"><b>PC에서는 이미 사용 중인가요?</b><br/>PC의 전체 메뉴 → 내 계정·보안에서 한 번 설정한 뒤, 모바일에서 같은 로그인 이름과 비밀번호를 입력하세요.</div>`;
  }
  return `<div class="warn"><b>카카오 로그인 설정을 확인하고 있어요</b><br/>주소나 앱 설정이 맞기 전에는 오류 페이지로 이동하지 않도록 버튼을 숨깁니다.</div><div class="mobileAccessHelp"><b>지금 모바일에서 접속하려면</b><br/>PC의 전체 메뉴 → 내 계정·보안에서 계정 로그인 비밀번호를 설정한 뒤 아래 기존 계정 로그인을 사용하세요.</div>`;
}



async function handleMyBackupLoginPage(request, env, url) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const user = await fetchUserById(env, userId);
  if (!user) return handleMyLogout();
  const first = url.searchParams.get("first") === "1";
  const hasBackup = await hasBackupLoginIdentity(env, user);
  const identity = await fetchStrongIdentityForUser(env, "local", user.id);
  const returnTo = safeUserReturnPath(url.searchParams.get("return_to") || "", first ? "/my/households" : "/my/households");
  return htmlResponse(renderMyBackupLoginHtml({ env, user, loginName: identity?.login_name || identity?.provider_subject || user.nickname || "", first, hasBackup, returnTo, msg: url.searchParams.get("msg") || "", err: url.searchParams.get("err") || "" }));
}

async function handleMyBackupLoginSave(request, env) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const user = await fetchUserById(env, userId);
  if (!user) return handleMyLogout();
  let hasBackup = false;
  try {
    hasBackup = await hasBackupLoginIdentity(env, user);
  } catch (err) {
    rememberOpsEvent({ kind: "backup_login_status_deferred", severity: "warn", path: "/my/backup-login", method: "POST", detail: safeError(err) });
  }
  const form = await request.formData();
  const loginName = String(form.get("login_name") || "").normalize("NFKC").trim().replace(/\s+/g, " ").slice(0, 80);
  const accessCode = String(form.get("access_code") || "").trim();
  const accessCode2 = String(form.get("access_code_confirm") || "").trim();
  const returnTo = safeUserReturnPath(form.get("return_to") || "", "/my/households");
  if (normalizeLocalLoginName(loginName).length < 2) return htmlResponse(renderMyBackupLoginHtml({ env, user, loginName, first: true, hasBackup: false, returnTo, err: "로그인 이름은 2자 이상 입력하세요." }), 400);
  if (accessCode.length < 8) return htmlResponse(renderMyBackupLoginHtml({ env, user, loginName, first: true, hasBackup: false, returnTo, err: "내 계정 로그인 비밀번호는 8자리 이상으로 입력하세요." }), 400);
  if (accessCode !== accessCode2) return htmlResponse(renderMyBackupLoginHtml({ env, user, loginName, first: true, hasBackup: false, returnTo, err: "확인 입력이 일치하지 않습니다." }), 400);
  try {
    await replaceLocalLoginForUser(env, loginName, accessCode, userId, { revokeSessions: true });
    const session = await makeUserSession(env, userId);
    return redirectResponse(addQueryToUrl(returnTo, { msg: "backup_login_saved" }), {
      "set-cookie": `ab_user=${encodeURIComponent(session)}; Path=/; Max-Age=1209600; HttpOnly; Secure; SameSite=Lax`,
    });
  } catch (err) {
    const detail = safeError(err);
    const message = /login_name_in_use|duplicate key|409/i.test(detail) ? "이미 사용 중인 로그인 이름입니다." : "내 계정 로그인 비밀번호를 저장하지 못했습니다. V22.7 인증 마이그레이션 적용 상태를 확인하세요.";
    return htmlResponse(renderMyBackupLoginHtml({ env, user, loginName, first: true, hasBackup, returnTo, err: message }), 409);
  }
}

function renderMyBackupLoginHtml({ env, user, loginName = "", first = false, hasBackup = false, returnTo = "/my/households", msg = "", err = "" }) {
  const title = escapeHtml(appName(env));
  const userName = escapeHtml(user?.nickname || "사용자");
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 내 계정·보안</title><style>
*,*:before,*:after{box-sizing:border-box}body{margin:0;background:linear-gradient(180deg,#fff9d9,#f8fafc 52%,#eef2f7);color:#101828;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:760px;margin:0 auto;padding:18px 18px 110px}.hero,.card{background:#fff;border:1px solid #e8edf4;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 44px rgba(15,23,42,.075)}.badge{display:inline-flex;background:#FEE500;color:#191919;border-radius:999px;padding:7px 11px;font-size:13px;font-weight:1000}.hero h1{font-size:28px;letter-spacing:-.05em}.muted{color:#667085;line-height:1.65}.field{display:grid;gap:7px;margin:14px 0}.field label{font-size:13px;font-weight:1000;color:#475467}.field input{width:100%;height:50px;border:1px solid #d0d5dd;border-radius:14px;padding:0 13px;font:inherit}.btn,button{display:inline-flex;align-items:center;justify-content:center;min-height:50px;border:0;border-radius:14px;background:#111827;color:#fff!important;font-weight:1000;padding:0 16px;text-decoration:none;width:100%}.btn:disabled,button:disabled{cursor:not-allowed;opacity:.55}.secondary{background:#eef2f7!important;color:#111827!important;border:1px solid #d8dee8}.ok{background:#ecfdf5;color:#166534;border:1px solid #bbf7d0;border-radius:16px;padding:13px;line-height:1.6}.error{background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;border-radius:16px;padding:13px;line-height:1.6}.guide{background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;border-radius:18px;padding:14px;line-height:1.65}.identity{background:#f8fafc;border:1px solid #e2e8f0;border-radius:16px;padding:13px;color:#475467;line-height:1.6}.credentialFeedback{min-height:20px;margin:-4px 0 12px;color:#667085;font-size:13px;line-height:1.45}.credentialFeedback[data-state="error"]{color:#b42318}.credentialFeedback[data-state="success"]{color:#067647;font-weight:800}@media(max-width:620px){.wrap{padding:12px 12px 110px}.hero,.card{padding:18px;border-radius:20px}.hero h1{font-size:24px}}
</style></head><body><main class="wrap"><section class="hero"><span class="badge">${title}</span><h1>내 계정·보안</h1><p class="muted">이 비밀번호는 가계부마다 만드는 비밀번호가 아닙니다. 모든 가계부에 공통인 내 계정 로그인·복구 수단이며 다른 참여자와 공유하지 않습니다.</p>${hasBackup ? `<div class="ok">내 계정 로그인 비밀번호가 설정되어 있습니다. 새로 저장하면 이전 비밀번호는 사용할 수 없게 바뀝니다.</div>` : ""}${msg ? `<div class="ok">${formatMessage(msg)}</div>` : ""}${err ? `<div class="error">${escapeHtml(err)}</div>` : ""}</section><section class="card"><div class="identity"><b>현재 표시 이름</b><br/>${userName}<br/><span class="muted">표시 이름은 내 프로필에서 별도로 변경합니다. 여기서 정하는 로그인 이름과는 다릅니다.</span></div><form method="post" action="/my/backup-login"><input type="hidden" name="return_to" value="${escapeHtml(safeUserReturnPath(returnTo, "/my/households"))}"/><div class="field"><label for="backupLoginName">로그인 이름</label><input id="backupLoginName" name="login_name" value="${escapeHtml(loginName || user?.nickname || "")}" placeholder="로그인할 때 사용할 이름" autocomplete="username" minlength="2" required/></div><div class="field"><label for="backupPassword">내 계정 로그인 비밀번호</label><input id="backupPassword" name="access_code" type="password" minlength="8" autocomplete="new-password" placeholder="8자리 이상" aria-describedby="backupPasswordStatus" required/></div><div class="field"><label for="backupPasswordConfirm">내 계정 로그인 비밀번호 확인</label><input id="backupPasswordConfirm" name="access_code_confirm" type="password" minlength="8" autocomplete="new-password" placeholder="같은 비밀번호를 한 번 더 입력" aria-describedby="backupPasswordStatus" required/></div><div id="backupPasswordStatus" class="credentialFeedback" data-state="hint" role="status" aria-live="polite">비밀번호는 8자리 이상 입력해 주세요.</div><button id="backupPasswordSubmit" type="submit">저장하고 이전 화면으로</button></form><p><a class="btn secondary" href="${escapeHtml(safeUserReturnPath(returnTo, "/my/households"))}">취소하고 이전 화면으로</a></p></section><section class="guide"><b>이탈 방지 안내</b><br/>저장하면 현재 세션을 새 보안 버전으로 갱신한 뒤 지금 보던 화면으로 자동 복귀합니다.</section></main><script id="credentialMatchRuntime">(${passwordMatchFeedbackClientMain.toString()})({passwordId:"backupPassword",confirmationId:"backupPasswordConfirm",statusId:"backupPasswordStatus",buttonId:"backupPasswordSubmit"});</script></body></html>`;
}

function renderKakaoLoginCheckHtml(env, url) {
  const title = escapeHtml(appName(env));
  const config = inspectKakaoLoginConfig(env);
  const originMatch = !config.issues.includes("redirect_origin_mismatch") && !!config.publicBase && !!config.redirectUri;
  const redirectFormatOk = !config.issues.includes("redirect_uri_invalid") && !!config.redirectUri;
  const issueLabels = {
    rest_api_key_missing: "REST API 키 없음",
    public_base_url_missing: "공개 기준 주소 없음",
    public_base_url_invalid: "공개 기준 주소 형식 오류",
    redirect_uri_missing: "Redirect URI 없음",
    redirect_uri_invalid: "Redirect URI 형식 오류",
    redirect_origin_mismatch: "공개 주소와 Redirect URI 호스트 불일치",
    client_secret_missing: "활성화된 Client Secret 없음",
  };
  const issues = config.issues.map((item) => issueLabels[item] || item).join(", ");
  const row = (name, ok, detail) => `<tr><td><b>${escapeHtml(name)}</b></td><td><span class="${ok ? "ok" : "bad"}">${ok ? "정상" : "확인"}</span></td><td>${detail}</td></tr>`;
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 카카오 로그인 점검</title><style>body{margin:0;background:#f8fafc;color:#101828;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:900px;margin:0 auto;padding:18px}.card{background:#fff;border:1px solid #e8edf4;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 14px 34px rgba(15,23,42,.055)}table{width:100%;border-collapse:collapse}td,th{border-bottom:1px solid #e8edf4;padding:12px;text-align:left;vertical-align:top}.ok{color:#166534;background:#dcfce7;border-radius:999px;padding:5px 9px;font-weight:1000}.bad{color:#991b1b;background:#fee2e2;border-radius:999px;padding:5px 9px;font-weight:1000}code{background:#f1f5f9;border-radius:8px;padding:2px 6px;overflow-wrap:anywhere}.btn{display:inline-flex;background:#111827;color:#fff!important;text-decoration:none;border-radius:14px;padding:11px 14px;font-weight:1000}.warn{background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;border-radius:16px;padding:13px;line-height:1.6}</style></head><body><main class="wrap"><section class="card"><h1>카카오 로그인 점검</h1><p>카카오 로그인은 명시적으로 켜고, 공개 주소와 Redirect URI가 정확히 일치할 때만 사용자에게 표시됩니다.</p><table><tbody>${row("KAKAO_LOGIN_ENABLED", config.enabled, "명시적으로 <code>1</code> 설정")}${row("KAKAO_REST_API_KEY", config.apiKeyConfigured, "카카오 앱의 REST API 키 설정")}${row("PUBLIC_BASE_URL", !!config.publicBase && !config.issues.includes("public_base_url_invalid"), `<code>${escapeHtml(config.publicBase || "미설정")}</code>`)}${row("Redirect URI 형식", redirectFormatOk, `<code>${escapeHtml(config.redirectUri || "미설정")}</code>`)}${row("공개 주소와 호스트 일치", originMatch, originMatch ? "같은 HTTPS 호스트" : "PUBLIC_BASE_URL과 Redirect URI의 호스트를 같게 설정")}${row("Client Secret", !config.clientSecretRequired || config.clientSecretConfigured, config.clientSecretRequired ? "필수 모드: Secret 설정 필요" : "카카오 앱에서 Client Secret을 켰을 때만 설정")}${row("사용 가능 상태", config.ready, config.ready ? "로컬 설정 일치 · 로그인 버튼 표시" : escapeHtml(issues || "기능이 꺼져 있음"))}</tbody></table><p class="warn"><b>마지막 외부 확인</b><br/>위 Redirect URI와 완전히 같은 주소를 동일한 카카오 앱의 Redirect URI 목록에 등록해야 합니다. 이 화면에서는 카카오 관리자센터 등록 여부까지 자동 확인할 수 없습니다.</p><p><a class="btn" href="/my">로그인 화면으로 돌아가기</a></p></section></main></body></html>`;
}

function renderUserLoginHtml(env, error = "") {
  const title = escapeHtml(appName(env));
  const kakaoPart = kakaoLoginStatusBlock(env);
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 시작</title><style>
  *,*:before,*:after{box-sizing:border-box}body{margin:0;background:#f4f6f8;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif;color:#101828;letter-spacing:-.025em}.loginPage{max-width:960px;margin:0 auto;padding:24px 20px 96px}.hero,.card{background:#fff;border:1px solid #e3e8ef;border-radius:20px;box-shadow:0 4px 18px rgba(15,23,42,.045);padding:22px}.badge{display:inline-flex;background:#FEE500;color:#191919;border-radius:999px;padding:7px 11px;font-size:13px;font-weight:800}.muted{color:#667085;line-height:1.6}.loginGrid{display:grid;grid-template-columns:1.08fr .92fr;gap:14px}.field{display:grid;gap:7px;margin:10px 0}.field label{font-size:13px;font-weight:700;color:#344054}.field input{width:100%;height:50px;border:1px solid #cfd6e1;background:#fff;border-radius:12px;padding:0 13px;font:inherit}.btn,button,.kakaoBtn{display:inline-flex;align-items:center;justify-content:center;min-height:50px;border:0;border-radius:12px;background:#172033;color:#fff!important;font-weight:750;padding:0 16px;text-decoration:none;cursor:pointer;width:100%}.btn:disabled,button:disabled{cursor:not-allowed;opacity:.55}.secondary{background:#eef2f7!important;color:#172033!important;border:1px solid #d8dee8}.kakaoBtn{background:#FEE500!important;color:#191919!important;border:1px solid rgba(245,158,11,.18)}.notice{background:#ecfdf5;border:1px solid #a7f3d0;color:#065f46;border-radius:13px;padding:12px;line-height:1.55;margin:10px 0}.warn{background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;border-radius:13px;padding:12px;line-height:1.55;margin:10px 0}.error{background:#fef2f2;color:#b91c1c;border:1px solid #fecaca;border-radius:13px;padding:12px;margin:10px 0}.sep{text-align:center;color:#7b8494;font-weight:700;margin:10px 0}.hint{font-size:12px;color:#667085;line-height:1.5;margin-top:-4px}.credentialFeedback{min-height:20px;margin:-3px 0 10px;color:#667085;font-size:13px;line-height:1.45}.credentialFeedback[data-state="error"]{color:#b42318}.credentialFeedback[data-state="success"]{color:#067647;font-weight:800}@media(max-width:760px){.loginPage{padding:10px 12px 96px}.loginGrid{grid-template-columns:1fr}}</style></head><body><main class="loginPage"><section class="hero loginHero"><span class="badge">${title}</span><h1>내 가계부에 접속하세요.</h1><p class="muted">기존 계정은 로그인 이름과 비밀번호만 입력하면 바로 이어서 사용할 수 있습니다.</p>${error ? `<div class="error" role="alert">${escapeHtml(error)}</div>` : ""}${kakaoPart}</section><section class="loginGrid"><div class="card loginCard"><h2>기존 계정 로그인</h2><p class="muted">PC에서 쓰던 계정의 로그인 이름과 계정 로그인 비밀번호를 입력하세요.</p><form method="post" action="/my/local-login"><div class="field"><label for="loginName">로그인 이름</label><input id="loginName" name="login_name" autocomplete="username" autocapitalize="none" spellcheck="false" enterkeyhint="next" placeholder="가입할 때 정한 로그인 이름" required/></div><div class="field"><label for="loginPassword">비밀번호</label><input id="loginPassword" name="access_code" type="password" autocomplete="current-password" minlength="4" enterkeyhint="go" placeholder="계정 로그인 비밀번호" required/></div><details class="loginOptional"><summary>초대코드도 함께 입력</summary><div class="field"><label for="loginInvite">초대코드 (선택)</label><input id="loginInvite" name="invite_code" autocomplete="off" autocapitalize="characters" spellcheck="false" placeholder="로그인과 동시에 참여할 때만 입력"/></div></details><button type="submit">로그인</button></form></div><details class="card signupCard"><summary><b>처음이라면 새 계정 만들기</b><span>가입 후 가계부 생성·참여로 이어집니다.</span></summary><div class="signupBody"><form method="post" action="/my/local-signup"><div class="field"><label for="signupName">로그인 이름</label><input id="signupName" name="login_name" autocomplete="username" autocapitalize="none" spellcheck="false" minlength="2" placeholder="계속 사용할 로그인 이름" required/></div><div class="hint">표시 이름을 나중에 바꿔도 로그인 이름은 유지됩니다.</div><div class="field"><label for="signupDisplay">가계부에 표시할 이름</label><input id="signupDisplay" name="display_name" autocomplete="nickname" placeholder="예: Bin, 엄마, 아빠" required/></div><div class="field"><label for="signupPassword">새 비밀번호</label><input id="signupPassword" name="access_code" type="password" autocomplete="new-password" minlength="8" placeholder="8자리 이상" aria-describedby="signupPasswordStatus" required/></div><div class="field"><label for="signupPasswordConfirm">새 비밀번호 확인</label><input id="signupPasswordConfirm" name="access_code_confirm" type="password" autocomplete="new-password" minlength="8" placeholder="같은 비밀번호를 다시 입력" aria-describedby="signupPasswordStatus" required/></div><div id="signupPasswordStatus" class="credentialFeedback" data-state="hint" role="status" aria-live="polite">비밀번호는 8자리 이상 입력해 주세요.</div><div class="field"><label for="signupInvite">초대코드 (선택)</label><input id="signupInvite" name="invite_code" autocomplete="off" autocapitalize="characters" spellcheck="false" placeholder="받은 코드가 있으면 입력"/></div><button id="signupPasswordSubmit" class="secondary" type="submit">새 계정 만들기</button></form></div></details></section><section class="warn legacyHelp"><b>기존 4자리 접속코드도 사용할 수 있습니다.</b><br/>정상 로그인하면 새 보안 방식으로 자동 전환됩니다.</section></main><script id="credentialMatchRuntime">(${passwordMatchFeedbackClientMain.toString()})({passwordId:"signupPassword",confirmationId:"signupPasswordConfirm",statusId:"signupPasswordStatus",buttonId:"signupPasswordSubmit"});</script></body></html>`;
}


function myNavCss() {
  return `.appLayout{display:grid;grid-template-columns:250px minmax(0,1fr);gap:14px;align-items:start}.appMenu{position:sticky;top:12px;background:#fff;border:1px solid #E8EBEF;border-radius:20px;padding:12px;box-shadow:0 2px 14px rgba(15,23,42,.05);z-index:5}.appMenu summary{cursor:pointer;font-weight:800;list-style:none;display:flex;align-items:center;justify-content:space-between;gap:8px;padding:12px 14px;border-radius:14px;background:#fff;color:#191F28;border:1px solid #E8EBEF}.appMenu summary::-webkit-details-marker{display:none}.appMenu summary:after{content:"열기";font-size:11px;font-weight:800;color:#8B95A1;background:#F2F4F6;border-radius:999px;padding:4px 9px}.appMenu[open] summary:after{content:"접기"}.appMenuBody{padding-top:8px}.navGroup{margin:10px 0}.navGroupTitle{font-size:12px;color:#8B95A1;font-weight:800;padding:5px 8px}.appMenu a{display:flex;justify-content:space-between;align-items:center;gap:8px;text-decoration:none;color:#333D4B;background:#fff;border:1px solid transparent;border-radius:13px;padding:10px 12px;margin:2px 0;font-weight:700}.appMenu a:hover{background:#F5F7F9}.appMenu a.active{background:#191F28;color:#fff}.appMenu small{font-size:11px;color:inherit;opacity:.6}.pageMain{min-width:0}.safeGrid>*{min-width:0}@media(min-width:961px){.appMenu summary{display:none}.appMenuBody{padding-top:0}}@media(max-width:960px){.appLayout{grid-template-columns:1fr}.appMenu{position:static;padding:8px}.appMenuBody{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:6px}.navGroup{margin:0}.navGroupTitle{grid-column:1/-1}.appMenu a{margin:0;background:#F8F9FB;border:1px solid #EEF0F3}}@media(max-width:620px){.appMenuBody{grid-template-columns:1fr}}
/* v19.0 통합 디자인 시스템 — /my 화면도 다른 화면들과 같은 톤으로 통일 */
:root{--ab-bg:#F7F8FA;--ab-surface:#FFFFFF;--ab-ink:#191919;--ab-sub:#6B7280;--ab-line:#ECEFF3;--ab-accent:#FEE500;--ab-dark:#111827;--ab-shadow:0 2px 14px rgba(15,23,42,.06);--ab-radius:20px}
body{background:var(--ab-bg)!important}
.hero{background:var(--ab-surface)!important;color:var(--ab-ink)!important;border:1px solid var(--ab-line)!important;box-shadow:var(--ab-shadow)!important;border-radius:var(--ab-radius)!important;padding:22px 20px!important}
.hero h1{color:var(--ab-ink)!important;font-size:21px!important;font-weight:800!important;letter-spacing:-.02em!important;margin:0 0 6px!important;opacity:1!important}
.hero p{color:var(--ab-sub)!important;font-size:14px!important;line-height:1.6!important;opacity:1!important;margin:0}
.card,.panel,.record,.startPanel{box-shadow:var(--ab-shadow)!important;border-radius:18px!important;padding:18px!important}
.card h2,.panel h2{font-size:16px!important;font-weight:800!important;margin:0 0 10px!important;color:var(--ab-ink)!important}
main.wrap>section,.wrap>section{margin:14px 0!important}
.btn,form>button[type="submit"]{border-radius:14px!important;font-weight:800!important;min-height:44px!important}
input,select,textarea{border-radius:13px!important}
@media(max-width:760px){
  .wrap{padding:12px 12px 28px!important}
  .hero{padding:18px 16px!important;border-radius:16px!important}
  .hero h1{font-size:19px!important}
  .card,.panel{padding:16px!important;border-radius:16px!important}
}`;
}

function renderMySideNav(selectedHousehold, role = "", month = currentMonthKst(), current = "home") {
  const hid = selectedHousehold?.id || "";
  const qs = `household_id=${encodeURIComponent(hid)}&month=${encodeURIComponent(month)}`;
  const isManager = ["owner", "admin"].includes(String(role || ""));
  const returnByMenu = {
    home: `/app?${qs}`,
    settings: `/my/settings?${qs}`,
    members: `/my/members?${qs}`,
    groups: `/my/groups?${qs}`,
    backup: `/my/backup?${qs}`,
    "smart-tools": `/smart-tools?${qs}`,
    analysis: `/my/analysis?${qs}`,
  };
  const securityHref = `/my/backup-login?return_to=${encodeURIComponent(returnByMenu[current] || `/my/households?${qs}`)}`;
  const item = (key, href, label, hint = "") => `<a class="${current === key ? "active" : ""}" href="${href}"><span>${label}</span>${hint ? `<small>${hint}</small>` : ""}</a>`;
  return `<details class="appMenu" open><summary>☰ 메뉴</summary><div class="appMenuBody"><div class="navGroup"><div class="navGroupTitle">가계부</div>${item("home", `/app?${qs}`, "홈", "요약·입력")}${item("analysis", `/my/analysis?${qs}`, "분석", "필터·차트")}${item("smart-tools", `/smart-tools?${qs}`, "무료 스마트 도구", "예측·자동화")}${item("receipts", `/receipts?${qs}`, "영수증 기록", "사진·문자")}${item("reports", `/reports?${qs}`, "자동 리포트", "주간·월간")}${item("calendar", `/app?${qs}&view=calendar#calendar`, "캘린더", "일별/수정")}${item("settings", `/my/settings?${qs}`, "수입·예산", "분류 합계")}</div><div class="navGroup"><div class="navGroupTitle">가계부 관리</div>${item("households", `/my/households?${qs}`, "가계부 전환·옵션", "이름·삭제")}${item("groups", `/my/groups?${qs}`, "단톡방 연결", "챗봇")}${item("backup", `/my/backup?${qs}`, "백업·가져오기", "CSV")}${isManager ? item("members", `/my/members?${qs}`, "참여자·초대", "권한") : item("profile", "/my/profile", "내 프로필", "표시명")}</div><div class="navGroup"><div class="navGroupTitle">계정·도움말</div>${item("backup-login", securityHref, "내 계정·보안", "로그인·복구")}${item("guide", `/start-guide?${qs}`, "시작가이드", "순서")}${item("keyword", `/keyword-guide?${qs}`, "키워드 안내", "분류")}${item("privacy", "/privacy", "개인정보 안내", "정책")}</div></div></details><script>(function(){try{if(Math.min(window.innerWidth||9999,(document.documentElement||{}).clientWidth||9999)<961){var m=document.querySelector(".appMenu");if(m)m.removeAttribute("open");}}catch(e){}})();</script>`;
}

function renderMemberOptions(members = [], selected = "") {
  return safeArray(members).filter((m) => m.user_id && !["blocked","pending"].includes(String(m.role || ""))).map((m) => `<option value="${escapeHtml(m.user_id)}" ${String(selected || "") === String(m.user_id) ? "selected" : ""}>${escapeHtml(m.nickname || "구성원")} · ${escapeHtml(m.role || "member")}</option>`).join("");
}



function addMonthsYm(month, delta) {
  const d = new Date(Number(month.slice(0, 4)), Number(month.slice(5, 7)) - 1 + delta, 1);
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
}

function calculateExtendedAnalytics({ month, allRows, prevRows, historyRows, yearRows, rowsBase }) {
  const current = calculateStats(allRows);
  const prev = calculateStats(prevRows);
  const expenseMoMRate = percentChange(current.totals.expense, prev.totals.expense);
  const monthlyTrend = [];
  for (let i = -11; i <= 0; i++) {
    const ym = addMonthsYm(month, i);
    const rs = historyRows.filter((r) => String(r.transaction_date || "").slice(0, 7) === ym);
    const st = calculateStats(rs);
    monthlyTrend.push({ month: ym, income: st.totals.income, expense: st.totals.expense, balance: st.totals.balance, count: rs.length });
  }
  const threeMonthTrend = monthlyTrend.slice(-3);
  const currentCat = categoryExpenseMap(allRows);
  const prevCat = categoryExpenseMap(prevRows);
  const names = new Set([...Object.keys(currentCat), ...Object.keys(prevCat)]);
  const categoryCompare = [...names].map((name) => {
    const currentExpense = currentCat[name] || 0;
    const prevExpense = prevCat[name] || 0;
    return { name, current: currentExpense, previous: prevExpense, diff: currentExpense - prevExpense, rate: percentChange(currentExpense, prevExpense) };
  }).sort((a, b) => Math.abs(b.diff) - Math.abs(a.diff) || b.current - a.current);
  const topNames = [...new Set(categoryCompare.filter((x) => x.current > 0 || x.previous > 0).slice(0, 8).map((x) => x.name))];
  const categoryTrend3 = topNames.map((name) => ({ name, months: threeMonthTrend.map((m) => ({ month: m.month, amount: categoryExpenseMap(historyRows.filter((r) => String(r.transaction_date || "").slice(0, 7) === m.month))[name] || 0 })) }));
  const yearMonths = [];
  for (let i = 1; i <= 12; i++) {
    const ym = `${month.slice(0, 4)}-${String(i).padStart(2, "0")}`;
    const rs = yearRows.filter((r) => String(r.transaction_date || "").slice(0, 7) === ym);
    const st = calculateStats(rs);
    yearMonths.push({ month: ym, income: st.totals.income, expense: st.totals.expense, balance: st.totals.balance, count: rs.length });
  }
  const weekdayStats = buildWeekdayStats(yearRows.length ? yearRows : historyRows);
  const topIncrease = categoryCompare.find((x) => x.diff > 0 && x.current > 0) || { name: "없음", diff: 0, rate: 0 };
  const topDecrease = categoryCompare.find((x) => x.diff < 0) || { name: "없음", diff: 0, rate: 0 };
  const avg3 = Math.round(threeMonthTrend.reduce((s, x) => s + x.expense, 0) / Math.max(1, threeMonthTrend.filter((x) => x.expense > 0).length || 3));
  const cleanupCount = rowsBase.filter((r) => isMissingCategory(r.category) || (r.type === "expense" && isMissingPayment(r.payment_method))).length;
  return { current, prev, expenseMoMRate, monthlyTrend, threeMonthTrend, categoryCompare, categoryTrend3, yearMonthSummary: yearMonths, weekdayStats, topIncrease, topDecrease, avg3Expense: avg3, cleanupCount };
}

function categoryExpenseMap(rows) {
  const map = {};
  for (const r of rows || []) {
    if (r.type === "income") continue;
    const k = r.category || "미분류";
    map[k] = (map[k] || 0) + Number(r.amount || 0);
  }
  return map;
}

function percentChange(current, previous) {
  if (!previous && !current) return 0;
  if (!previous) return current > 0 ? 100 : 0;
  return Math.round(((current - previous) / previous) * 100);
}

function formatSignedPercent(v) {
  if (v > 0) return `+${v}%`;
  if (v < 0) return `${v}%`;
  return "0%";
}

function deltaClass(v) {
  return v > 0 ? "deltaUp" : v < 0 ? "deltaDown" : "deltaFlat";
}

function buildWeekdayStats(rows) {
  const names = ["일", "월", "화", "수", "목", "금", "토"];
  const map = names.map((name) => ({ name, income: 0, expense: 0, count: 0 }));
  for (const r of rows || []) {
    const d = new Date(String(r.transaction_date || "").replace(/-/g, "/"));
    const idx = Number.isFinite(d.getTime()) ? d.getDay() : 0;
    const amount = Number(r.amount || 0);
    if (r.type === "income") map[idx].income += amount; else map[idx].expense += amount;
    map[idx].count += 1;
  }
  return map;
}

function renderStrategyCards(ext, a) {
  const cards = [
    { cls: ext.expenseMoMRate > 20 ? "danger" : ext.expenseMoMRate > 5 ? "warn" : "good", title: "전월 대비 지출", value: formatSignedPercent(ext.expenseMoMRate), desc: `전월 ${numberWithCommas(ext.prev.totals.expense)}원 → 이번 달 ${numberWithCommas(ext.current.totals.expense)}원` },
    { cls: ext.avg3Expense > 0 && ext.current.totals.expense > ext.avg3Expense * 1.2 ? "warn" : "good", title: "3개월 평균 대비", value: `${numberWithCommas(ext.avg3Expense)}원`, desc: `최근 3개월 평균과 이번 달 속도를 비교하세요.` },
    { cls: ext.cleanupCount > 0 ? "danger" : "good", title: "분석 신뢰도", value: `${ext.cleanupCount}건`, desc: "미정리 데이터가 적을수록 고급 분석이 정확해집니다." },
    { cls: ext.topIncrease.diff > 0 ? "warn" : "good", title: "최대 증가 항목", value: ext.topIncrease.name, desc: `${numberWithCommas(ext.topIncrease.diff)}원 증가 · ${formatSignedPercent(ext.topIncrease.rate)}` },
    { cls: a.weekendRate >= 45 ? "warn" : "good", title: "주말 소비", value: `${a.weekendRate}%`, desc: "주말 외식·여가성 소비 비중을 점검하세요." },
    { cls: a.riskScore >= 70 ? "danger" : a.riskScore >= 45 ? "warn" : "good", title: "가계부 경보", value: `${a.riskScore}점`, desc: "고정비, 쏠림, 미정리, 월말 예상치를 종합한 점수입니다." },
  ];
  return cards.map((c) => `<div class="insight ${c.cls}"><b>${escapeHtml(c.title)}</b><div style="font-size:24px;font-weight:950;letter-spacing:-.04em">${escapeHtml(c.value)}</div><div class="muted">${escapeHtml(c.desc)}</div></div>`).join("");
}

function renderMonthlyTrendMini(items) {
  if (!items.length) return `<div class="empty">데이터가 없습니다.</div>`;
  const max = Math.max(1, ...items.map((x) => x.expense));
  return `<div class="trendBars">${items.map((x) => `<div class="trendLine"><div class="trendLabel">${escapeHtml(x.month)}</div><div class="bar"><span style="width:${Math.round(x.expense / max * 100)}%"></span></div><div class="trendValue expense">${numberWithCommas(x.expense)}원</div></div>`).join("")}</div>`;
}

function renderMonthlyTrendTable(items) {
  if (!items.length) return `<div class="empty">데이터가 없습니다.</div>`;
  const max = Math.max(1, ...items.map((x) => x.expense));
  return `<div class="tableWrap"><table class="statTable"><thead><tr><th>월</th><th>지출 추이</th><th>수입</th><th>지출</th><th>잔액</th><th>건수</th></tr></thead><tbody>${items.map((x) => `<tr><td><b>${escapeHtml(x.month)}</b></td><td><div class="bar"><span style="width:${Math.round(x.expense / max * 100)}%"></span></div></td><td class="income">${numberWithCommas(x.income)}원</td><td class="expense">${numberWithCommas(x.expense)}원</td><td>${numberWithCommas(x.balance)}원</td><td>${x.count}건</td></tr>`).join("")}</tbody></table></div>`;
}

function renderCategoryCompareTable(items, compact) {
  if (!items.length) return `<div class="empty">비교할 데이터가 없습니다.</div>`;
  const rows = compact ? items.slice(0, 8) : items;
  return `<div class="tableWrap"><table class="statTable"><thead><tr><th>카테고리</th><th>이번 달</th><th>전월</th><th>차이</th><th>증감률</th></tr></thead><tbody>${rows.map((x) => `<tr><td><b>${escapeHtml(x.name)}</b></td><td class="expense">${numberWithCommas(x.current)}원</td><td>${numberWithCommas(x.previous)}원</td><td class="${deltaClass(x.diff)}">${x.diff >= 0 ? "+" : ""}${numberWithCommas(x.diff)}원</td><td class="${deltaClass(x.rate)}">${formatSignedPercent(x.rate)}</td></tr>`).join("")}</tbody></table></div>`;
}

function renderCategoryTrendTable(items) {
  if (!items.length) return `<div class="empty">3개월 비교 데이터가 없습니다.</div>`;
  const months = items[0].months.map((m) => m.month);
  return `<div class="tableWrap"><table class="statTable"><thead><tr><th>카테고리</th>${months.map((m) => `<th>${escapeHtml(m)}</th>`).join("")}<th>흐름</th></tr></thead><tbody>${items.map((x) => { const max = Math.max(1, ...x.months.map((m) => m.amount)); return `<tr><td><b>${escapeHtml(x.name)}</b></td>${x.months.map((m) => `<td>${numberWithCommas(m.amount)}원</td>`).join("")}<td><div class="bar"><span style="width:${Math.round((x.months[x.months.length - 1].amount || 0) / max * 100)}%"></span></div></td></tr>`; }).join("")}</tbody></table></div>`;
}

function renderYearlyMonthSummary(items) {
  const available = items.filter((x) => x.count > 0 || x.income > 0 || x.expense > 0);
  if (!available.length) return `<div class="empty">올해 데이터가 없습니다.</div>`;
  return renderMonthlyTrendTable(available);
}

function renderWeekdayStats(items) {
  if (!items.length) return `<div class="empty">요일별 데이터가 없습니다.</div>`;
  const max = Math.max(1, ...items.map((x) => x.expense));
  return `<div class="trendBars">${items.map((x) => `<div class="trendLine"><div class="trendLabel">${escapeHtml(x.name)}요일</div><div class="bar"><span style="width:${Math.round(x.expense / max * 100)}%"></span></div><div class="trendValue">${numberWithCommas(x.expense)}원 · ${x.count}건</div></div>`).join("")}</div>`;
}

function calculateDashboardAnalysis(allRows, filteredRows, calendar, month) {
  const stats = calculateStats(allRows);
  const expense = stats.totals.expense;
  const income = stats.totals.income;
  const days = Math.max(1, calendar.length || 30);
  const avgExpense = Math.round(expense / days);
  const noSpendDays = calendar.filter((d) => Number(d.expense || 0) === 0).length;
  const expenseDays = calendar.filter((d) => Number(d.expense || 0) > 0).length;
  const topCategory = stats.categories.find((c) => c.expense > 0) || { category: "없음", expense: 0 };
  const maxDay = calendar.reduce((a, d) => Number(d.expense || 0) > Number(a.expense || 0) ? d : a, { date: "", expense: 0 });
  const missingCategory = allRows.filter((r) => isMissingCategory(r.category)).length;
  const missingPayment = allRows.filter((r) => r.type === "expense" && isMissingPayment(r.payment_method)).length;
  const missingAny = allRows.filter((r) => isMissingCategory(r.category) || (r.type === "expense" && isMissingPayment(r.payment_method))).length;
  const fixedNames = ["주거/관리", "공과금/통신", "보험", "구독", "월세", "관리비"];
  const fixedExpense = allRows.filter((r) => r.type === "expense" && fixedNames.some((x) => String(r.category || r.memo || "").includes(x))).reduce((s, r) => s + Number(r.amount || 0), 0);
  const fixedRate = expense ? Math.round(fixedExpense / expense * 100) : 0;
  const concentration = expense ? Math.round(Number(topCategory.expense || 0) / expense * 100) : 0;
  const maxDayRate = expense ? Math.round(Number(maxDay.expense || 0) / expense * 100) : 0;
  const weekendExpense = allRows.filter((r) => { const d = new Date(String(r.transaction_date || "").replace(/-/g, "/")); return r.type === "expense" && (d.getDay() === 0 || d.getDay() === 6); }).reduce((s, r) => s + Number(r.amount || 0), 0);
  const weekendRate = expense ? Math.round(weekendExpense / expense * 100) : 0;
  const spendText = (r) => `${r.category || ""} ${r.memo || ""} ${r.raw_text || ""}`;
  const cafeRows = allRows.filter((r) => r.type === "expense" && /카페|간식|커피|스타벅스|스벅|투썸|이디야|빽다방|메가커피|컴포즈|디저트/.test(spendText(r)));
  const deliveryRows = allRows.filter((r) => r.type === "expense" && /배달|배민|요기요|쿠팡이츠|치킨|피자|야식|족발|닭발/.test(spendText(r)));
  const shoppingRows = allRows.filter((r) => r.type === "expense" && /쇼핑|쿠팡|네이버쇼핑|무신사|올리브영|택배|구매|주문|옷|의류|신발|가방|화장품/.test(spendText(r)));
  const subscriptionRows = allRows.filter((r) => r.type === "expense" && /구독|넷플릭스|유튜브|쿠팡와우|멜론|티빙|웨이브|디즈니|스포티파이|멤버십/.test(spendText(r)));
  const vehicleRows = allRows.filter((r) => r.type === "expense" && /교통|택시|버스|지하철|주유|기름|주차|하이패스|정비|세차|카센터/.test(spendText(r)));
  const groceryRows = allRows.filter((r) => r.type === "expense" && /마트|장보기|시장|코스트코|트레이더스|이마트|홈플러스|식자재|슈퍼/.test(spendText(r)));
  const medicalRows = allRows.filter((r) => r.type === "expense" && /병원|약국|치과|한의원|진료|검진|의료|약|처방/.test(spendText(r)));
  const childRows = allRows.filter((r) => r.type === "expense" && /육아|어린이집|유치원|기저귀|분유|장난감|아이|키즈|학원|학습지/.test(spendText(r)));
  const petRows = allRows.filter((r) => r.type === "expense" && /강아지|고양이|반려|사료|동물병원|배변패드|애견|애묘/.test(spendText(r)));
  const beautyRows = allRows.filter((r) => r.type === "expense" && /미용|미용실|헤어|커트|염색|네일|피부관리|화장품/.test(spendText(r)));
  const cultureRows = allRows.filter((r) => r.type === "expense" && /영화|공연|전시|여행|숙박|호텔|게임|취미|헬스|운동|캠핑|노래방/.test(spendText(r)));
  const foodRows = allRows.filter((r) => r.type === "expense" && /식비|점심|저녁|아침|밥|외식|식당|분식|국밥|고기|회식|술|맥주|소주/.test(spendText(r)));
  const taxRows = allRows.filter((r) => r.type === "expense" && /세금|수수료|과태료|벌금|자동차세|재산세|종부세/.test(spendText(r)));
  const sumAmount = (arr) => arr.reduce((s, r) => s + Number(r.amount || 0), 0);
  const cafeCount = cafeRows.length;
  const cafeAmount = sumAmount(cafeRows);
  const deliveryCount = deliveryRows.length;
  const deliveryAmount = sumAmount(deliveryRows);
  const shoppingCount = shoppingRows.length;
  const shoppingAmount = sumAmount(shoppingRows);
  const subscriptionCount = subscriptionRows.length;
  const subscriptionAmount = sumAmount(subscriptionRows);
  const vehicleAmount = sumAmount(vehicleRows);
  const groceryAmount = sumAmount(groceryRows);
  const medicalAmount = sumAmount(medicalRows);
  const childAmount = sumAmount(childRows);
  const petAmount = sumAmount(petRows);
  const beautyAmount = sumAmount(beautyRows);
  const cultureAmount = sumAmount(cultureRows);
  const foodAmount = sumAmount(foodRows);
  const taxAmount = sumAmount(taxRows);
  const burnForecast = forecastMonthlyExpense(expense, month);
  const riskScore = Math.min(100, Math.round((fixedRate * 0.24) + (concentration * 0.22) + (maxDayRate * 0.18) + (weekendRate * 0.14) + (missingAny * 2.2) + (income > 0 && burnForecast > income ? 20 : 0)));
  const analysisBase = { stats, income, expense, avgExpense, noSpendDays, expenseDays, topCategory, maxDay, missingCategory, missingPayment, missingAny, fixedExpense, fixedRate, concentration, maxDayRate, weekendExpense, weekendRate, cafeCount, cafeAmount, deliveryCount, deliveryAmount, shoppingCount, shoppingAmount, subscriptionCount, subscriptionAmount, vehicleAmount, groceryAmount, medicalAmount, childAmount, petAmount, beautyAmount, cultureAmount, foodAmount, taxAmount, burnForecast, riskScore };
  return { ...analysisBase, meme: chooseMemeCard(analysisBase) };
}

function forecastMonthlyExpense(currentExpense, month) {
  const today = nowKstDate();
  const currentMonth = currentMonthKst();
  const daysInMonth = new Date(Number(month.slice(0, 4)), Number(month.slice(5, 7)), 0).getDate();
  const elapsed = month === currentMonth ? Math.max(1, today.getDate()) : daysInMonth;
  return Math.round(currentExpense / elapsed * daysInMonth);
}


function chooseMemeCard(a) {
  const key = detectMonthlyCardKey(a);
  return buildMemeCardFromKey(key, { ...a, scale: "monthly" });
}

function detectMonthlyCardKey(a) {
  if (a.expense === 0 && a.income === 0) return "NO_RECORDS";
  if (a.expense === 0) return "NO_SPEND_ZEN";
  if (a.income > 0 && a.burnForecast > a.income * 1.15) return "PAYCHECK_EVAPORATOR";
  if (a.riskScore >= 85) return "WALLET_SIREN";
  if (a.expenseDays <= 3 && a.expense > 0) return "FLASH_SPENDER";
  if (a.income > 0 && a.expense < a.income * 0.4 && a.noSpendDays >= 8) return "SAVING_SHIELD";
  if (a.fixedRate >= 62) return "FIXED_BOSS";
  if (a.maxDayRate >= 52) return "ONE_PUNCH";
  if (a.cafeCount >= 18 || a.cafeAmount >= 90000) return "CAFE_OVERLORD";
  if (a.cafeCount >= 8) return "LATTE_RABBIT";
  if (a.deliveryCount >= 8 || a.deliveryAmount >= 180000) return "DELIVERY_WIZARD";
  if (a.deliveryCount >= 4) return "LATE_NIGHT_KNIGHT";
  if (a.shoppingCount >= 9 || a.shoppingAmount >= 250000) return "ROCKET_CARTEL";
  if (a.shoppingAmount >= 120000) return "CART_OVERLOAD";
  if (a.subscriptionCount >= 5 || a.subscriptionAmount >= 80000) return "SUBSCRIPTION_GHOST";
  if (a.groceryAmount >= 350000) return "MART_RAIDER";
  if (a.vehicleAmount >= 250000) return "FUEL_DRAGON";
  if (a.medicalAmount >= 180000) return "HOSPITAL_SIDEQUEST";
  if (a.childAmount >= 250000) return "KID_BOSS_RAID";
  if (a.petAmount >= 120000) return "PET_BUTLER";
  if (a.beautyAmount >= 120000) return "BEAUTY_BUFF";
  if (a.cultureAmount >= 180000) return "DOPAMINE_TOUR";
  if (a.taxAmount >= 100000) return "TAX_NPC";
  if (a.missingAny >= 8) return "MYSTERY_SPENDER";
  if (a.missingAny >= 3) return "MISC_SWAMP";
  if (a.noSpendDays >= 12) return "SELF_CONTROL";
  if (a.weekendRate >= 48) return "WEEKEND_BURN";
  if (a.concentration >= 48) return "HYPER_FOCUS";
  if (a.foodAmount >= 300000) return "RICE_POWERED_HERO";
  return "STEADY_SQUIRREL";
}

function buildMemeCardFromKey(key, stats) {
  const variants = getMemeVariantPool();
  const core = getCoreCardPool()[key] || getCoreCardPool().STEADY_SQUIRREL;
  const variantIndex = hashString(`${key}|${stats.expense || 0}|${stats.noSpendDays || 0}|${stats.fixedRate || 0}|${stats.maxDayRate || 0}|${stats.deliveryCount || 0}|${stats.shoppingCount || 0}`) % variants.length;
  const variant = variants[variantIndex];
  const rarity = core.rarity || "R";
  const power = buildCardPower(stats, rarity, variantIndex);
  const title = `${core.title} ${variant.titleSuffix}`.trim();
  const line = formatTemplate(core.line, stats);
  const sub = formatTemplate(variant.sub || core.sub || "", stats);
  const share = formatTemplate(core.share || variant.share || "", stats);
  return {
    key,
    rarity,
    emoji: core.emoji + (variant.emojiAddon || ""),
    title,
    tagline: line,
    subline: sub,
    share,
    styleClass: `rarity-${rarity} ${variant.styleClass || "spark"}`,
    animation: variant.styleClass || "spark",
    power,
    label: core.label || "월간 대표 소비몬",
  };
}

