function mergedOptions(base, extra) {
  const seen = new Set();
  const out = [];
  for (const v of [...base, ...extra]) {
    const s = String(v || "").trim();
    if (!s || seen.has(s)) continue;
    seen.add(s); out.push(s);
  }
  return out;
}

